import React, { useEffect, useRef } from "react";
import { Button, ModalCloseButton, Modal, TextInput } from "@kui/foundations-react";
import { CameraGlyph } from "./icons";
import T from "../kui/tokens";

/**
 * Drag-drop + file-picker image upload modal triggered by the camera icon in
 * the search bar. Reuses the parent's `handleDrop` / `handleFileChange`
 * handlers (already set state up the tree) and triggers `onSubmit` to run the
 * image search. URL-paste is intentionally disabled for v1 — see TODO.
 */
const ImageUploadModal = ({
  isOpen,
  onClose,
  onDrop,
  onDragOver,
  onFileChange,
  imageBase64,
  onClearImage,
  onSubmit,
}) => {
  const fileInputRef = useRef(null);
  // Track the imageBase64 the modal saw when it OPENED — so a re-open with
  // an already-staged image doesn't auto-fire a second search. We only
  // update this on the open transition (not on every imageBase64 change).
  const baselineImageRef = useRef("");
  const wasOpenRef = useRef(false);
  useEffect(() => {
    if (isOpen && !wasOpenRef.current) {
      // Modal just opened: snapshot the staged image (if any).
      baselineImageRef.current = imageBase64 || "";
    }
    wasOpenRef.current = isOpen;
  }, [isOpen, imageBase64]);

  // Auto-fire the combined search as soon as a NEW image is staged inside
  // this open session. handleSearch reads `searchQuery` from parent state,
  // so any text already in the bar is included as a hybrid text + image
  // request. Fires once per open session.
  const autoFiredRef = useRef(false);
  useEffect(() => {
    if (!isOpen) {
      autoFiredRef.current = false;
      return;
    }
    if (autoFiredRef.current) return;
    if (!imageBase64) return;
    if (imageBase64 === baselineImageRef.current) return; // unchanged from open-time
    autoFiredRef.current = true;
    onSubmit?.();
    onClose?.();
  }, [isOpen, imageBase64, onSubmit, onClose]);

  const handleAttachClick = () => {
    // Manual fallback: clicking "Search" with an already-staged image fires
    // the search explicitly. The auto-fire above usually pre-empts this.
    if (imageBase64) {
      onSubmit?.();
    }
    onClose?.();
  };

  return (
    <Modal
      open={isOpen}
      onOpenChange={(o) => {
        if (!o) onClose?.();
      }}
      // Route backdrop-click and Escape through our own `onClose` (the same path
      // the footer Cancel/X buttons use) instead of Kaizen's internal animate-out
      // close. Kaizen's internal dismiss keeps `open`/`isOpen` true for the full
      // exit animation and re-invokes showModal() each render during it, which
      // flashes the dialog (reopen-then-close) on background dismiss. Preempting
      // it and flipping the controlled prop immediately matches the clean X path.
      onInteractOutside={(e) => {
        e.preventDefault();
        onClose?.();
      }}
      onEscapeKeyDown={(e) => {
        e.preventDefault();
        onClose?.();
      }}
      slotHeading="Search by image"
      // Catch dragover/drop on the entire dialog so a drop anywhere inside the
      // modal is handled — not just the dashed inner zone. Without this, a drop
      // outside the small inner box lets the browser navigate away to the
      // dropped file.
      attributes={{ ModalDialog: { onDragOver, onDrop } }}
      slotFooter={
        <>
          {imageBase64 && (
            <ModalCloseButton kind="tertiary" onClick={onClearImage}>
              Clear
            </ModalCloseButton>
          )}
          <ModalCloseButton kind="tertiary" onClick={onClose}>
            Cancel
          </ModalCloseButton>
          <Button
            kind="primary"
            color="brand"
            onClick={handleAttachClick}
            disabled={!imageBase64}
          >
            Search
          </Button>
        </>
      }
    >
      <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
        {imageBase64 ? (
          <div
            style={{
              position: "relative",
              borderRadius: T.radiusMd,
              overflow: "hidden",
              background: T.surfaceRaised,
              padding: 12,
            }}
          >
            <img
              src={imageBase64}
              alt="Selected image"
              style={{ maxHeight: 220, margin: "0 auto", objectFit: "contain", display: "block" }}
            />
          </div>
        ) : (
          <div
            onDrop={onDrop}
            onDragOver={onDragOver}
            onClick={() => fileInputRef.current?.click()}
            style={{
              border: `2px dashed ${T.border}`,
              borderRadius: T.radiusLg,
              padding: "40px 24px",
              textAlign: "center",
              cursor: "pointer",
              transition: "all 0.2s",
            }}
          >
            <div
              style={{
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                gap: 12,
                color: T.textSecondary,
              }}
            >
              <div style={{ color: T.textMuted }}>
                <CameraGlyph width={36} height={36} />
              </div>
              <span style={{ fontSize: 14, fontWeight: 500 }}>
                Drag &amp; drop an image here
              </span>
              <span style={{ fontSize: 12, color: T.textMuted }}>
                or click to browse
              </span>
            </div>
            <input
              ref={fileInputRef}
              type="file"
              accept="image/*"
              onChange={onFileChange}
              style={{ display: "none" }}
            />
          </div>
        )}

        {/* TODO: enable URL-paste path once we fetch + encode the image
            client-side without CORS surprises. For v1, the field is shown
            disabled so users know it's coming. */}
        <div style={{ display: "flex" }}>
          <TextInput
            size="small"
            kind="flat"
            placeholder="or paste an image URL (coming soon)"
            disabled
            style={{ width: "100%" }}
          />
        </div>
      </div>
    </Modal>
  );
};

export default ImageUploadModal;
