import React from "react";
import { Button, TextInput, Tooltip } from "@kui/foundations-react";
import { SearchGlyph, CameraGlyph, ArrowRightGlyph, CloseGlyph, SpinnerGlyph } from "./icons";
import T from "../kui/tokens";

/**
 * Unified Google-style pill search bar used on both the landing and results
 * states. The only visual difference between the two is the `size` prop which
 * controls width, height, and font size; behavior is identical.
 *
 * Built on the Kaizen `TextInput` (magnifier in `slotStart`, the camera /
 * submit actions in `slotEnd`) with the pill rounding applied via style.
 *
 * Props:
 *   size: "hero" | "compact"
 *   value, onChange, onSubmit, onImageClick
 *   placeholder (optional)
 *   isLoading (optional) — disables the input while a search is in flight
 */
const CompactSearchBar = ({
  size = "hero",
  value,
  onChange,
  onSubmit,
  onImageClick,
  onClearImage,
  onCancel,
  imageBase64,
  placeholder,
  isLoading = false,
  autoFocus = false,
  canSubmitEmpty = false,
}) => {
  const isHero = size === "hero";
  const hasImage = !!imageBase64;
  // A search can fire with text, a staged image, OR — when filters are set —
  // no query at all (filter-only search). `canSubmitEmpty` carries the latter.
  const canSubmit = hasImage || canSubmitEmpty || !!(value && value.trim());

  // Per-size default placeholder (mock copy); an explicit prop still wins.
  const resolvedPlaceholder =
    placeholder ??
    (isHero
      ? "Search for assets using natural language…"
      : "Search assets with natural language…");

  const handleKeyDown = (e) => {
    if (e.key === "Enter") {
      if (!canSubmit) return; // nothing to search on
      e.preventDefault();
      onSubmit?.();
    }
  };

  const handleSubmitClick = () => {
    // Mirror the Enter guard: text, a staged image, or active filters
    // (filter-only search) all count.
    if (!canSubmit) return;
    onSubmit?.();
  };

  const glyph = isHero ? 19 : 22;
  const actionBtn = isHero ? 40 : 42;

  return (
    <div style={{ width: "100%", maxWidth: 640, margin: isHero ? "0 auto" : 0 }}>
      <TextInput
        kind="flat"
        size={isHero ? "large" : "small"}
        value={value || ""}
        onValueChange={(v) => onChange?.(v)}
        placeholder={resolvedPlaceholder}
        aria-label="Search for assets"
        attributes={{ Input: { onKeyDown: handleKeyDown, autoFocus, disabled: isLoading, style: isHero ? undefined : { fontSize: "14.5px", paddingLeft: "12px" } } }}
        style={{ borderRadius: 999, width: "100%", ...(isHero ? {} : { height: 42 }) }}
        slotStart={
          // Hero keeps the leading magnifier as its search cue; the compact
          // results bar already has a magnifier submit button on the right, so
          // the leading icon is redundant there and is dropped.
          isHero ? (
            <span style={{ display: "flex", color: T.textMuted }}>
              <SearchGlyph width={`${glyph}px`} height={`${glyph}px`} />
            </span>
          ) : undefined
        }
        slotEnd={
          <span style={{ display: "flex", alignItems: "center", gap: isHero ? 2 : 1 }}>
            {hasImage && (
              <Tooltip slotContent="Remove image">
                <span
                  style={{
                    position: "relative",
                    width: actionBtn - 4,
                    height: actionBtn - 4,
                    borderRadius: T.radiusMd,
                    overflow: "hidden",
                    border: `1px solid ${T.borderStrong}`,
                    flexShrink: 0,
                    cursor: "pointer",
                  }}
                  onClick={onClearImage}
                  role="button"
                  aria-label="Clear staged image"
                >
                  <img
                    src={imageBase64}
                    alt="staged"
                    style={{ width: "100%", height: "100%", objectFit: "cover" }}
                  />
                  <span
                    style={{
                      position: "absolute",
                      top: -1,
                      right: -1,
                      width: 14,
                      height: 14,
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      background: "rgba(0,0,0,.7)",
                      color: "#fff",
                      borderRadius: 999,
                    }}
                  >
                    <CloseGlyph width="8px" height="8px" />
                  </span>
                </span>
              </Tooltip>
            )}

            {isLoading ? (
              <>
                {/* Spinning indicator so a slow query/parse shows live activity.
                    A symmetric ring glyph (not the triangle Spinner, whose arrows
                    are top-heavy in their viewBox) so it sits dead-center on the
                    bar's axis next to the cancel button. */}
                <span
                  style={{
                    display: "inline-flex",
                    alignItems: "center",
                    justifyContent: "center",
                    width: actionBtn,
                    height: actionBtn,
                    color: T.textMuted,
                  }}
                  role="status"
                  aria-label="Searching"
                >
                  <SpinnerGlyph
                    width={18}
                    height={18}
                    style={{ animation: "esSpin .8s linear infinite" }}
                  />
                </span>
                <Tooltip slotContent="Cancel search">
                  <Button
                    kind="tertiary"
                    color="danger"
                    size="small"
                    aria-label="Cancel search"
                    onClick={onCancel}
                    style={{ borderRadius: 999 }}
                  >
                    <CloseGlyph width="18px" height="18px" />
                  </Button>
                </Tooltip>
              </>
            ) : (
              <>
                {/* Search-by-image (camera) button — both sizes. */}
                <Tooltip slotContent={hasImage ? "Replace image" : "Search by image"}>
                  <Button
                    kind="tertiary"
                    color="neutral"
                    size="small"
                    aria-label="Search by image"
                    onClick={onImageClick}
                    style={{ borderRadius: 999 }}
                  >
                    <CameraGlyph width={isHero ? "20px" : "19px"} height={isHero ? "20px" : "19px"} />
                  </Button>
                </Tooltip>

                {/* Submit button. Hero: solid green circle with black arrow.
                    Compact: tertiary magnifier (Enter also submits). */}
                {isHero ? (
                  <Tooltip slotContent="Search">
                    <Button
                      kind="primary"
                      color="brand"
                      size="small"
                      aria-label="Search"
                      onClick={handleSubmitClick}
                      style={{ borderRadius: 999, width: 32, height: 32, padding: 0, marginLeft: 2 }}
                    >
                      <ArrowRightGlyph width="14px" height="14px" />
                    </Button>
                  </Tooltip>
                ) : (
                  <Tooltip slotContent="Search">
                    <Button
                      kind="tertiary"
                      color="neutral"
                      size="small"
                      aria-label="Search"
                      onClick={handleSubmitClick}
                      style={{ borderRadius: 999 }}
                    >
                      <SearchGlyph width="19px" height="19px" />
                    </Button>
                  </Tooltip>
                )}
              </>
            )}
          </span>
        }
      />
    </div>
  );
};

export default CompactSearchBar;
