"use client";

import { createContext, useContext } from 'react';

const TooltipContext = createContext(null);
function useTooltipContext() {
  const context = useContext(TooltipContext);
  if (!context) {
    throw new Error("Tooltip compound components must be used within a <TooltipRoot>.");
  }
  return context;
}
const DEFAULT_PROVIDER_CONTEXT = {
  openDelayDuration: 100,
  skipDelayDuration: 300,
  lastCloseTimestamp: {
    current: 0
  }
};
const TooltipProviderContext = createContext(DEFAULT_PROVIDER_CONTEXT);
function useTooltipProviderContext() {
  return useContext(TooltipProviderContext);
}

export { TooltipContext, TooltipProviderContext, useTooltipContext, useTooltipProviderContext };
