// A search hit carries usd_properties as an array of {name, value, ...} (when
// return_usd_properties=true). The asset-details USD Properties table wants a
// {name: value} object, so flatten it. This source needs no Asset Graph Service
// round-trip and is present even when AGS has no graph for the asset (e.g. when
// the deployment points at a remote OpenSearch index). On duplicate names the
// last occurrence wins.
export function usdPropertiesArrayToObject(arr) {
  const obj = {};
  if (!Array.isArray(arr)) return obj;
  for (const prop of arr) {
    if (!prop || prop.name == null) continue;
    obj[prop.name] = prop.value;
  }
  return obj;
}
