// Pure helpers for the global Downloads center.
//
// The download manager itself lives in HybridDeepSearchUI.jsx (it owns the
// AbortController, the streaming fetch, and the React state). These functions
// are the side-effect-free pieces it leans on — dedupe, queue ordering, the
// header summary string, the badge count, and reload persistence — so they can
// be unit-tested without spinning up the component or a network.
//
// An item is:
//   { id, url, name, ext, status, error,
//     fileCount, totalSize, size, summary, progress, startedAt, finishedAt }
// status ∈ "queued" | "downloading" | "completed" | "failed".

export const DOWNLOADS_STORAGE_KEY = "usdsearch.downloads.v1";

/** Lowercase extension (no dot) for an asset name/url, or "" when none. */
export function extOf(nameOrUrl) {
  const base = String(nameOrUrl || "").split(/[?#]/)[0].split("/").pop() || "";
  const m = /\.([a-z0-9]+)$/i.exec(base);
  return m ? m[1].toLowerCase() : "";
}

/** Is this url already active or waiting (so enqueue should be a no-op)? */
export function isActiveOrQueued(list, url) {
  return list.some(
    (it) => it.url === url && (it.status === "queued" || it.status === "downloading")
  );
}

/** The next item the single-flight processor should run, or null. */
export function nextQueued(list) {
  return list.find((it) => it.status === "queued") || null;
}

/** Top-bar badge = items still in flight (downloading + queued). */
export function badgeCount(list) {
  return list.filter((it) => it.status === "downloading" || it.status === "queued").length;
}

/**
 * Tray header summary, e.g. "1 active · 3 done · 1 failed". Always shows all
 * three counters so the line doesn't reflow as items move between states.
 */
export function summaryString(list) {
  const active = list.filter((it) => it.status === "downloading" || it.status === "queued").length;
  const done = list.filter((it) => it.status === "completed").length;
  const failed = list.filter((it) => it.status === "failed").length;
  return `${active} active · ${done} done · ${failed} failed`;
}

/**
 * Build a fresh queued item. `nextId` is the post-increment counter value so
 * ids stay unique and stable. `meta` is an optional pre-computed bundle summary
 * { fileCount, totalSize } (e.g. from the modal's manifest_only pre-flight).
 */
export function makeItem(nextId, url, name, meta = null, startedAt = null) {
  return {
    id: `dl-${nextId}`,
    url,
    name,
    ext: extOf(name) || extOf(url),
    status: "queued",
    error: null,
    fileCount: meta?.fileCount ?? null,
    totalSize: meta?.totalSize ?? null,
    size: null,
    summary: null,
    progress: 0,
    startedAt,
    finishedAt: null,
  };
}

/**
 * Restore a persisted list for a new session. Anything that was mid-flight when
 * the tab closed can't be resumed (the streamed fetch is gone), so mark it
 * failed-interrupted; queued items stay queued so the processor can pick them
 * back up; completed/failed history is kept as-is.
 */
export function hydrateDownloads(raw) {
  if (!Array.isArray(raw)) return [];
  return raw.map((it) => {
    if (it && it.status === "downloading") {
      return {
        ...it,
        status: "failed",
        error: "Interrupted by reload",
        progress: 0,
        finishedAt: it.finishedAt ?? null,
      };
    }
    return it;
  });
}

/** Serialize for persistence (drop nothing — the list is already small). */
export function serializeDownloads(list) {
  try {
    return JSON.stringify(list || []);
  } catch {
    return "[]";
  }
}
