import React from "react";
import { Button, Tooltip } from "@kui/foundations-react";
import { FilterGlyph, MosaicGlyph, IndexGlyph } from "./icons";
import InterpretedQueryChips from "./InterpretedQueryChips";
import T from "../kui/tokens";

// The bar above the results: filters toggle · N results (green) · removable
// selection chips + Delete all · icon-only Mosaic/Index segmented toggle.
const SegBtn = ({ active, icon, label, onClick }) => (
  <Tooltip slotContent={label} side="bottom">
    <Button
      kind={active ? "primary" : "tertiary"}
      color={active ? "brand" : "neutral"}
      size="tiny"
      aria-label={label}
      onClick={onClick}
      style={{ borderRadius: 5 }}
    >
      {icon}
    </Button>
  </Tooltip>
);

const MetaBar = ({
  filtersOpen,
  onToggleFilters,
  resultCount = 0,
  chips = [],
  onClearAll,
  viewMode = "grid",
  onViewModeChange,
}) => {
  const hasChips = chips.length > 0;
  return (
    <div
      style={{
        flex: "none",
        display: "flex",
        alignItems: "center",
        gap: "13px",
        padding: "13px 22px",
        borderBottom: `1px solid ${T.border}`,
        flexWrap: "wrap",
      }}
    >
      {/* Filters toggle */}
      <Button kind="tertiary" color="neutral" size="small" onClick={onToggleFilters} style={{ flex: "none" }}>
        <FilterGlyph width={18} height={18} color="var(--text-color-brand)" />
        <span style={{ whiteSpace: "nowrap" }}>{filtersOpen ? "Close filters" : "Show filters"}</span>
      </Button>

      <span style={{ flex: "none", width: "1px", height: "22px", background: T.borderStrong }} />

      {/* Result count */}
      <div style={{ flex: "none", fontSize: "12.8px", color: T.textSecondary, whiteSpace: "nowrap" }}>
        <span style={{ color: T.brandText, fontWeight: 700, fontVariantNumeric: "tabular-nums" }}>
          {resultCount.toLocaleString()}
        </span>{" "}
        results
      </div>

      {/* Selection chips */}
      {hasChips && (
        <div style={{ display: "flex", alignItems: "center", gap: "9px", marginLeft: "8px", minWidth: 0 }}>
          <InterpretedQueryChips chips={chips} onRemove={(c) => c.onRemove && c.onRemove()} />
          <Button kind="tertiary" color="brand" size="small" onClick={onClearAll} style={{ flex: "none", whiteSpace: "nowrap" }}>
            Delete all
          </Button>
        </div>
      )}

      <div style={{ flex: 1 }} />

      {/* Layout toggle — icon-only (tooltips on hover) */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          padding: "3px",
          background: T.surfaceRaised,
          border: `1px solid ${T.borderStrong}`,
          borderRadius: "7px",
          gap: "2px",
          flex: "none",
        }}
      >
        <SegBtn
          active={viewMode === "grid"}
          icon={<MosaicGlyph width={14} height={14} />}
          label="Mosaic view"
          onClick={() => onViewModeChange && onViewModeChange("grid")}
        />
        <SegBtn
          active={viewMode === "list"}
          icon={<IndexGlyph width={14} height={14} />}
          label="Index view"
          onClick={() => onViewModeChange && onViewModeChange("list")}
        />
      </div>
    </div>
  );
};

export default MetaBar;
