import React, { useState } from "react";
import { Badge } from "@kui/foundations-react";
import NavigableAssetImage from "./NavigableAssetImage";
import DownloadControl from "./DownloadControl";
import { CheckGlyph, WarningGlyph, SpinnerGlyph, ExpandGlyph, InfoGlyph } from "./icons";
import { getPolygonCount } from "../utils/assetFacets";
import { formatFileSize, middleTruncate } from "../utils/formatUtils";
import T from "../kui/tokens";

/**
 * Mosaic tile for the Results-state redesign (dark NVIDIA mock, spec §3).
 * Square thumbnail tile; whole tile is the hit target (calls onItemClick).
 * File-type badge top-right, inline VLM status badge top-left, and a
 * hover-revealed bottom caption (name + tris · size) with an expand button
 * and the download control.
 */

// Inline VLM status badge (top-left). Mirrors the mock per-tile badges
// (app.html L3463-3471). A state-colored Kaizen Badge carrying just the glyph.
const VlmBadge = ({ validationState, halted = false }) => {
  const inProgress =
    validationState === "pending" || validationState === "validating";
  const rejected = validationState === "rejected";
  // No thumbnail → couldn't be validated. Neutral badge, never a green check.
  const skipped = validationState === "skipped";

  let color;
  let glyph;
  if (rejected) {
    color = "yellow";
    glyph = <WarningGlyph width={11} height={11} strokeWidth={3} />;
  } else if (skipped) {
    color = "gray";
    glyph = <InfoGlyph width={11} height={11} />;
  } else if (inProgress) {
    color = "blue";
    glyph = (
      <SpinnerGlyph
        width={11}
        height={11}
        strokeWidth={2.6}
        // Freeze the spinner once validation has halted (VLM unavailable) —
        // a perpetual spin implies active work that isn't happening.
        style={halted ? undefined : { animation: "esSpin .8s linear infinite" }}
      />
    );
  } else {
    color = "green";
    glyph = <CheckGlyph width={11} height={11} strokeWidth={3.2} />;
  }

  const title = rejected
    ? "VLM rejected — likely false positive"
    : skipped
    ? "Validation skipped — no preview image to check"
    : inProgress
    ? halted
      ? "Validation paused — VLM unavailable"
      : "VLM validating…"
    : "VLM validated";

  return (
    <span
      title={title}
      style={{
        position: "absolute",
        top: "7px",
        left: "7px",
        display: "inline-flex",
        pointerEvents: "none",
        zIndex: 3,
      }}
    >
      <Badge color={color} kind="solid">
        {glyph}
      </Badge>
    </span>
  );
};

const CompactResultCard = ({
  result,
  onItemClick,
  getHeaders,
  apiUrl,
  downloadAsset,
  cancelDownload,
  downloadingUrl,
  queuedUrls,
  copyToClipboard,
  onFindSimilar,
  vlmUnavailable = false,
}) => {
  const [hovered, setHovered] = useState(false);

  const baseKey = result.source?.base_key || result.source?.url || result.id;
  const filename = result.source?.name || baseKey?.split("/").pop() || "Unknown";

  const size = result.source?.size_bytes ?? result.source?.size;

  const polygonCount = getPolygonCount(result);

  // Match score = the VLM query-relevance similarity (already 0–100). Shown as a
  // top-left badge once validation resolves; absent (VLM off / still validating)
  // means no badge.
  const simScore = result.query_relevance?.similarity_score;
  const matchScore =
    typeof simScore === "number" && Number.isFinite(simScore) ? Math.round(simScore) : null;

  // Meta line: "<polygon_count> tris · <size>" — drop missing parts gracefully.
  const metaParts = [];
  if (polygonCount != null) metaParts.push(`${polygonCount.toLocaleString()} tris`);
  if (size != null) metaParts.push(formatFileSize(size));
  const metaLine = metaParts.join(" · ");

  const validationState = result._validationState;
  const hasValidation = validationState != null && validationState !== "";

  const handleOpen = () => onItemClick?.(result);

  return (
    <div
      role="group"
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      onClick={handleOpen}
      aria-label={filename}
      style={{
        position: "relative",
        aspectRatio: "1 / 1",
        background: T.surfaceRaised,
        border: `1px solid ${hovered ? "rgba(118,185,0,.45)" : "rgba(255,255,255,.07)"}`,
        borderRadius: "7px",
        overflow: "hidden",
        cursor: "pointer",
        zIndex: hovered ? 2 : undefined,
        transition: "border-color .14s ease, z-index 0s",
      }}
    >
      {/* Placeholder cube — centered, behind the thumbnail */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          color: "rgba(255,255,255,.12)",
          pointerEvents: "none",
        }}
      >
        <svg
          width="38"
          height="38"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          strokeWidth="1.3"
          strokeLinejoin="round"
          aria-hidden="true"
        >
          <path d="M12 2 3 7v10l9 5 9-5V7z" />
          <path d="M3 7l9 5 9-5M12 12v10" />
        </svg>
      </div>

      {/* Thumbnail fills the tile */}
      <div style={{ position: "absolute", inset: 0 }}>
        <NavigableAssetImage
          result={result}
          getHeaders={getHeaders}
          apiUrl={apiUrl}
          width="100%"
          height="100%"
          borderRadius="0"
          objectFit="cover"
        />
      </div>

      {/* Top-left badge: the relevance match score once validation resolves,
          otherwise the VLM state icon (spinner while validating). The old
          top-right USD/USDA format chip is intentionally gone — the tile stays
          clean (thumbnail + score). */}
      {matchScore != null ? (
        <span
          title={`Query relevance ${matchScore}%`}
          style={{
            position: "absolute",
            top: "8px",
            left: "8px",
            zIndex: 3,
            pointerEvents: "none",
            fontSize: "10px",
            fontWeight: 700,
            color: validationState === "rejected" ? "#f4d47a" : "#a5de15",
            background: "rgba(20,20,20,.72)",
            borderRadius: "5px",
            padding: "2px 6px",
          }}
        >
          {matchScore}%
        </span>
      ) : (
        hasValidation && <VlmBadge validationState={validationState} halted={vlmUnavailable} />
      )}

      {/* Hover-revealed expand button (top-left, over the VLM badge slot) */}
      <button
        type="button"
        title="View details"
        aria-label="View details"
        onClick={(e) => {
          e.stopPropagation();
          handleOpen();
        }}
        style={{
          position: "absolute",
          top: "6px",
          left: "6px",
          width: "26px",
          height: "26px",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          background: "rgba(0,0,0,.62)",
          backdropFilter: "blur(4px)",
          border: "1px solid rgba(255,255,255,.14)",
          borderRadius: "6px",
          color: "#f4f4f5",
          cursor: "pointer",
          opacity: hovered ? 1 : 0,
          transition: "opacity .14s",
          zIndex: 4,
        }}
      >
        <ExpandGlyph width={13} height={13} />
      </button>

      {/* Download control (top-right, hover-revealed) */}
      {baseKey && (downloadAsset || cancelDownload) && (
        <div
          onClick={(e) => e.stopPropagation()}
          style={{
            position: "absolute",
            bottom: "6px",
            right: "6px",
            zIndex: 4,
            background: "rgba(0,0,0,.62)",
            backdropFilter: "blur(4px)",
            borderRadius: "6px",
            opacity: hovered ? 1 : 0,
            transition: "opacity .14s",
          }}
        >
          <DownloadControl
            url={baseKey}
            name={filename}
            downloadingUrl={downloadingUrl}
            queuedUrls={queuedUrls}
            onDownload={downloadAsset}
            onCancel={cancelDownload}
            size="xs"
          />
        </div>
      )}

      {/* Hover-revealed caption (name + meta line) */}
      <div
        style={{
          position: "absolute",
          left: 0,
          right: 0,
          bottom: 0,
          paddingTop: "18px",
          paddingLeft: "9px",
          paddingRight: "9px",
          paddingBottom: "8px",
          background: "linear-gradient(to top, rgba(0,0,0,.88), transparent)",
          opacity: hovered ? 1 : 0,
          transition: "opacity .14s",
          pointerEvents: "none",
          zIndex: 2,
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: "6px" }}>
          <span
            style={{
              fontSize: "11.5px",
              fontWeight: 500,
              color: "#fff",
              whiteSpace: "nowrap",
              overflow: "hidden",
              textOverflow: "ellipsis",
            }}
          >
            {middleTruncate(filename, 22)}
          </span>
        </div>
        {metaLine && (
          <span
            style={{
              display: "block",
              fontSize: "10.5px",
              color: "rgba(255,255,255,.6)",
              marginTop: "2px",
            }}
          >
            {metaLine}
          </span>
        )}
      </div>
    </div>
  );
};

// Memoized: with stable callback props (useStableCallback in the hub) and
// identity-preserved `result` objects (utils/mergeValidation.js), a validation
// flush only re-renders the cards whose verdict actually changed — the rest keep
// their DOM + thumbnail untouched.
export default React.memo(CompactResultCard);
