import { useState, useCallback, useRef, useEffect } from "react";
import { VALIDATION_CONFIG } from "../config";
import { peekValidationCached, setValidationCached, hashRequest } from "../utils/searchCache";

/**
 * Hook for asynchronous per-result VLM validation.
 *
 * Instead of blocking on all validations before showing results,
 * this fires independent validation requests (throttled to VALIDATION_CONFIG.MAX_CONCURRENT)
 * and updates each result as its response arrives.
 *
 * @param {string} apiUrl - The base API URL (v2 format, will be converted to v3)
 * @param {function} getHeaders - Returns auth/content-type headers for fetch
 *
 * When the server has no VLM configured, the first /vlm_validate/search_result
 * call returns 503; the batch is torn down and the `vlmUnavailable` banner is
 * surfaced reactively. No proactive capability probe is needed.
 */
export function useAsyncValidation(apiUrl, getHeaders) {
  const [validationMap, setValidationMap] = useState({});
  const [validatedCount, setValidatedCount] = useState(0);
  const [totalToValidate, setTotalToValidate] = useState(0);
  const [isValidating, setIsValidating] = useState(false);
  const [vlmUnavailable, setVlmUnavailable] = useState(false);

  const generationRef = useRef(0);
  const abortControllerRef = useRef(null);
  const vlmUnavailableRef = useRef(false);

  // Per-result verdicts are coalesced here and flushed to `validationMap` at most
  // once per FLUSH_INTERVAL_MS, so the results grid re-partitions a handful of
  // times instead of once per validation (avoids per-hit reflow / thumbnail churn).
  const pendingUpdatesRef = useRef({});
  const flushTimerRef = useRef(null);

  // Apply all accumulated verdicts in ONE setState. Reads only refs + the
  // functional updater, so it never closes over stale state (safe from a timer).
  const flushPending = useCallback(() => {
    if (flushTimerRef.current) {
      clearTimeout(flushTimerRef.current);
      flushTimerRef.current = null;
    }
    const batch = pendingUpdatesRef.current;
    pendingUpdatesRef.current = {};
    if (Object.keys(batch).length === 0) return;
    setValidationMap((prev) => ({ ...prev, ...batch }));
  }, []);

  // Fixed-window schedule: arm the timer once and do NOT reset it per enqueue, so
  // a steady stream still flushes at most FLUSH_INTERVAL_MS after the first update.
  const scheduleFlush = useCallback(() => {
    if (flushTimerRef.current) return;
    flushTimerRef.current = setTimeout(() => {
      flushTimerRef.current = null;
      flushPending();
    }, VALIDATION_CONFIG.FLUSH_INTERVAL_MS);
  }, [flushPending]);

  // Clear a pending flush timer on unmount so it can't setState after teardown.
  useEffect(
    () => () => {
      if (flushTimerRef.current) clearTimeout(flushTimerRef.current);
    },
    []
  );

  const cancelAllValidations = useCallback(() => {
    generationRef.current += 1;
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    // Drop any un-flushed verdicts + timer — a new run is starting, so stale
    // verdicts must never paint onto the next result set.
    if (flushTimerRef.current) {
      clearTimeout(flushTimerRef.current);
      flushTimerRef.current = null;
    }
    pendingUpdatesRef.current = {};
    vlmUnavailableRef.current = false;
    setIsValidating(false);
    setValidatedCount(0);
    setTotalToValidate(0);
    setValidationMap({});
    setVlmUnavailable(false);
  }, []);

  // The VLM endpoint went unavailable (503) or unreachable (network failure)
  // mid-batch. Unlike cancelAllValidations, this PRESERVES every verdict already
  // collected — validated/rejected hits keep their state — and the hits not yet
  // finished keep their pending/validating state, so they read as "In progress"
  // rather than collapsing into one bucket. We only stop issuing new work, abort
  // the in-flight requests (they resolve as AbortError → no state change), and
  // surface the banner. A fresh search re-enables validation via startValidation.
  const markVlmUnavailable = useCallback(() => {
    if (vlmUnavailableRef.current) return;
    vlmUnavailableRef.current = true;
    // Flush verdicts collected right before the drop so none are lost; the rest
    // stay pending/validating and fall into the "In progress" bucket.
    flushPending();
    setVlmUnavailable(true);
    setIsValidating(false);
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
  }, [flushPending]);

  const startValidation = useCallback(
    (hits, queryText, queryImage) => {
      if (!hits || hits.length === 0) return;
      // Skip validation when there's no query to validate against (e.g. filter-only searches)
      if (!queryText && !queryImage) return;

      cancelAllValidations();

      const currentGeneration = generationRef.current;
      const batchAbort = new AbortController();
      abortControllerRef.current = batchAbort;

      const initialMap = {};
      const validatable = [];
      hits.forEach((hit) => {
        const id = hit.id || hit.source?.base_key;
        if (!id) return;
        // Assets with no thumbnail can't be visually validated — mark them
        // terminally "skipped" (the grid groups these under "Lower relevance")
        // and never send them to the VLM.
        if (hit.thumbnail_exists !== true) {
          initialMap[id] = { status: "skipped", result: null };
        } else {
          initialMap[id] = { status: "pending", result: null };
          validatable.push(hit);
        }
      });
      setValidationMap(initialMap);
      setTotalToValidate(validatable.length);
      setValidatedCount(0);
      setIsValidating(validatable.length > 0);
      if (validatable.length === 0) return; // nothing validatable (all skipped)

      const v3Url = apiUrl.replace("v2", "v3");

      // Validation-result cache key: (queryHash, hitId). The model name
      // that produced each verdict is stored on the cached value (the
      // /vlm_validate/search_result response carries it as `model`), not
      // on the key. Keying on a status-probed model would introduce a
      // stale-probe bug when the backend is restarted with a different
      // model — writes would land under the wrong (stale) key. Model
      // swaps invalidate via the entry's TTL (validations: 24 h, capped
      // at 5000 entries in persistentStore.js DEFAULTS).
      const queryHash = hashRequest({ query_text: queryText || null, query_image: queryImage || null });

      // Build work items (only the validatable hits — skipped ones already have
      // a terminal verdict in initialMap and get no VLM call).
      const workItems = validatable
        .map((hit) => {
          const id = hit.id || hit.source?.base_key;
          if (!id) return null;

          let imageKey = null;
          if (hit.metadata?.explanations) {
            for (const exp of hit.metadata.explanations) {
              for (const mv of exp.matched_vectors || []) {
                if (mv.image) {
                  imageKey = mv.image;
                  break;
                }
              }
              if (imageKey) break;
            }
          }

          const body = {
            query_text: queryText || undefined,
            query_image: queryImage || undefined,
          };
          if (imageKey) {
            body.image_key = imageKey;
          } else {
            body.asset_url = hit.source?.base_key || id;
          }

          return { id, body };
        })
        .filter(Boolean);

      // Concurrency-limited queue
      let completed = 0;
      let nextIndex = 0;

      const processNext = () => {
        if (vlmUnavailableRef.current) return;
        if (batchAbort.signal.aborted) return;
        if (generationRef.current !== currentGeneration) return;
        if (nextIndex >= workItems.length) return;

        const idx = nextIndex++;
        const { id, body } = workItems[idx];

        // Short-circuit from the validation-result cache: same query + same
        // hit id is deterministic, so re-paint the verdict without hitting
        // the validator.
        const cacheKey = `${queryHash}:${id}`;
        const cachedResult = peekValidationCached(cacheKey);
        if (cachedResult) {
          const status = cachedResult.is_match ? "validated" : "rejected";
          pendingUpdatesRef.current[id] = { status, result: cachedResult };
          scheduleFlush();
          completed += 1;
          setValidatedCount(completed);
          if (completed >= workItems.length) {
            setIsValidating(false);
            flushPending();
          }
          processNext();
          return;
        }

        // Mark as validating
        pendingUpdatesRef.current[id] = { status: "validating", result: null };
        scheduleFlush();

        const attemptValidation = (retriesLeft) => {
          if (batchAbort.signal.aborted) return;
          if (generationRef.current !== currentGeneration) return;

          fetch(`${v3Url}/vlm_validate/search_result`, {
            method: "POST",
            headers: getHeaders(),
            body: JSON.stringify(body),
            signal: batchAbort.signal,
          })
            .then((response) => {
              if (response.status === 503) {
                // VLM unavailable — keep the verdicts we already have, leave the
                // rest in progress, surface the banner. (See markVlmUnavailable.)
                markVlmUnavailable();
                return null;
              }
              if ((response.status === 429 || response.status === 504) && retriesLeft > 0) {
                // Rate limited or gateway timeout — retry after delay
                setTimeout(() => attemptValidation(retriesLeft - 1), VALIDATION_CONFIG.RETRY_DELAY_MS);
                return null;
              }
              if (!response.ok) throw new Error(`HTTP ${response.status}`);
              return response.json();
            })
            .then((data) => {
              if (data === null) return; // Retry scheduled
              if (generationRef.current !== currentGeneration) return;
              const status = data.is_match ? "validated" : "rejected";
              setValidationCached(cacheKey, data);
              pendingUpdatesRef.current[id] = { status, result: data };
              scheduleFlush();

              completed += 1;
              setValidatedCount(completed);
              if (completed >= workItems.length) {
                setIsValidating(false);
                flushPending();
              }
              processNext();
            })
            .catch((err) => {
              if (generationRef.current !== currentGeneration) return;
              if (err.name === "AbortError") return;
              // A fetch network failure (TypeError) means we lost the connection
              // to the validator — treat it like a 503: preserve the verdicts so
              // far and leave the remaining hits in progress instead of marking
              // this one errored and pressing on against a dead endpoint.
              if (err.name === "TypeError") {
                markVlmUnavailable();
                return;
              }

              pendingUpdatesRef.current[id] = { status: "error", result: null };
              scheduleFlush();

              completed += 1;
              setValidatedCount(completed);
              if (completed >= workItems.length) {
                setIsValidating(false);
                flushPending();
              }
              processNext();
            });
        };

        attemptValidation(VALIDATION_CONFIG.MAX_RETRIES);
      };

      // Kick off initial batch (up to MAX_CONCURRENT)
      const initialBatch = Math.min(VALIDATION_CONFIG.MAX_CONCURRENT, workItems.length);
      for (let i = 0; i < initialBatch; i++) {
        processNext();
      }
    },
    [apiUrl, getHeaders, cancelAllValidations, markVlmUnavailable, scheduleFlush, flushPending]
  );

  return {
    validationMap,
    isValidating,
    validatedCount,
    totalToValidate,
    startValidation,
    cancelAllValidations,
    vlmUnavailable,
  };
}
