import React from "react";
import { Tooltip, Spinner, Banner } from "@kui/foundations-react";
import { CheckGlyph, CloseGlyph, WarningGlyph, SpinnerGlyph, InfoGlyph } from "./components/icons";
import { useSmartImageLoader } from "./hooks/useSmartImageLoader";
import CompactResultCard from "./components/CompactResultCard";
import CompactResultRow from "./components/CompactResultRow";
import T from "./kui/tokens";

// Shared style for the absolutely-positioned circular VLM badge in the top-left
// corner of a result tile. `bg`/`borderColor` vary per validation state.
const relevanceBadgeStyle = (bg, borderColor) => ({
  position: "absolute",
  top: 8,
  left: 8,
  zIndex: 10,
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  width: 24,
  height: 24,
  borderRadius: "9999px",
  background: bg,
  boxShadow: "0 2px 4px rgba(0,0,0,0.4)",
  border: `2px solid ${borderColor}`,
});

// Query relevance indicator component with async validation state support.
// Still exported and consumed by CompactResultCard / CompactResultRow as their
// per-tile/per-row VLM badge implementation — keep its signature intact.
export const QueryRelevanceIndicator = ({ queryRelevance, validationState }) => {
  // Pending / validating states
  if (validationState === "pending" || validationState === "validating") {
    return (
      <Tooltip slotContent={validationState === "validating" ? "Validating..." : "Waiting to validate"} side="top">
        <div style={relevanceBadgeStyle("#718096", "#a0aec0")}>
          <Spinner size="small" aria-label="Validating" />
        </div>
      </Tooltip>
    );
  }

  // Timeout / error states
  if (validationState === "timeout" || validationState === "error") {
    return (
      <Tooltip slotContent={validationState === "timeout" ? "Validation timed out" : "Validation error"} side="top">
        <div style={relevanceBadgeStyle(T.warning, "#fbb360")}>
          <WarningGlyph color="white" width={12} height={12} />
        </div>
      </Tooltip>
    );
  }

  // Validated / rejected states (existing behavior)
  if (!queryRelevance || typeof queryRelevance.is_match !== 'boolean') {
    return null;
  }

  const isMatch = queryRelevance.is_match;
  const confidence = queryRelevance.confidence;
  const similarityScore = queryRelevance.similarity_score;
  const reasoning = queryRelevance.reasoning;

  const tooltipLabel = `${isMatch ? 'Match' : 'No Match'}\nConfidence: ${(confidence * 100).toFixed(0)}%\nSimilarity: ${similarityScore}%${reasoning ? `\n${reasoning}` : ''}`;

  return (
    <Tooltip slotContent={<span style={{ whiteSpace: "pre-wrap" }}>{tooltipLabel}</span>} side="top">
      <div style={relevanceBadgeStyle(isMatch ? T.brand : T.danger, isMatch ? "#9ae6b4" : "#fc8181")}>
        {isMatch ? (
          <CheckGlyph color="white" width={12} height={12} />
        ) : (
          <CloseGlyph color="white" width={10} height={10} />
        )}
      </div>
    </Tooltip>
  );
};

// Fixed column widths for the Index (list) view. The header row below and each
// CompactResultRow must share these so columns line up.
const LIST_COLUMNS = [
  // Preview width must match CompactResultRow's thumbnail tile (120px) so the
  // "Filename" header and every subsequent column line up with the row values.
  { label: "Preview", w: "120px", align: "left" },
  { label: "Filename", flex: 1, align: "left" },
  { label: "Size", w: "78px", align: "left" },
  { label: "Modified", w: "104px", align: "left" },
  { label: "VLM", w: "30px", align: "center" },
  // Reserved actions column — the per-row download control (an absolute overlay)
  // draws here; sized for its widest state (spinner + cancel).
  { label: "", w: "64px", align: "left" },
];

// Stacked-section chrome (VLM on): one labeled header per validation bucket.
// The hex values are the redesign mockup's; they intentionally sit outside the
// theme tokens (chrome only — the tiles/rows keep the theme).
const SECTION_CHIP_BG = {
  validated: "rgba(118,185,0,.16)",
  // "Other results" reads as a neutral near-miss bucket, not an error — neutral
  // gray chrome instead of the old red-amber warning palette.
  rejected: "rgba(255,255,255,.06)",
  progress: "rgba(91,141,239,.16)",
};
const SECTION_PILL_BG = {
  validated: "rgba(118,185,0,.16)",
  rejected: "rgba(255,255,255,.08)",
  progress: "rgba(91,141,239,.18)",
};
const SECTION_PILL_FG = {
  validated: "#a5de15",
  rejected: "#b4b4b8",
  progress: "#8fb4f7",
};
const SECTION_ICON = {
  validated: <CheckGlyph color="#76b900" width={10} height={10} />,
  rejected: <InfoGlyph color="#9a9a9e" width={12} height={12} />,
};
// "In progress" icon: spinning while validation is live, frozen once it has
// halted (VLM unavailable) — a stalled batch shouldn't imply active work.
const PROGRESS_ICON_LIVE = (
  <SpinnerGlyph color="#5b8def" width={13} height={13} style={{ animation: "esSpin .8s linear infinite" }} />
);
const PROGRESS_ICON_HALTED = (
  <SpinnerGlyph color="#5b8def" width={13} height={13} />
);

// Disclosure chevron — points down when open, right when collapsed.
const SectionChevron = ({ open }) => (
  <span
    style={{
      flex: "none",
      display: "inline-flex",
      color: "#7a7a7e",
      transform: open ? "rotate(90deg)" : "rotate(0deg)",
      transition: "transform .15s",
    }}
  >
    <svg width="8" height="12" viewBox="0 0 7 11" fill="none" aria-hidden="true">
      <path d="M1 1l4.5 4.5L1 10" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  </span>
);

// Colored icon chip + title + count pill + hairline rule + chevron, with an
// optional subhead line beneath (e.g. "Other results" explains it's a lower-
// relevance bucket, not an error). The whole control toggles open/closed.
const SectionHeader = ({ variant, title, subhead, count, open, onToggle, halted }) => (
  <button
    type="button"
    onClick={onToggle}
    aria-expanded={open}
    aria-label={`${title} (${count})`}
    style={{
      display: "flex",
      flexDirection: "column",
      alignItems: "stretch",
      gap: 3,
      marginBottom: 13,
      width: "100%",
      background: "transparent",
      border: "none",
      cursor: "pointer",
      textAlign: "left",
      padding: 0,
      fontFamily: "inherit",
    }}
  >
    <span style={{ display: "flex", alignItems: "center", gap: 11, width: "100%" }}>
      <span
        style={{
          display: "flex",
          width: 24,
          height: 24,
          alignItems: "center",
          justifyContent: "center",
          borderRadius: 6,
          background: SECTION_CHIP_BG[variant],
        }}
      >
        {variant === "progress"
          ? (halted ? PROGRESS_ICON_HALTED : PROGRESS_ICON_LIVE)
          : SECTION_ICON[variant]}
      </span>
      <span style={{ fontSize: 17, fontWeight: 600, color: "#f4f4f5", whiteSpace: "nowrap" }}>
        {title}
      </span>
      <span
        style={{
          padding: "0 8px",
          borderRadius: "999px",
          fontSize: 13,
          fontWeight: 600,
          background: SECTION_PILL_BG[variant],
          color: SECTION_PILL_FG[variant],
          fontVariantNumeric: "tabular-nums",
        }}
      >
        {count.toLocaleString()}
      </span>
      <span style={{ flex: 1, height: 1, background: "rgba(255,255,255,.07)" }} />
      <SectionChevron open={open} />
    </span>
    {subhead && (
      <span style={{ fontSize: 11.5, color: "#7a7a7e", marginLeft: 35 }}>{subhead}</span>
    )}
  </button>
);

const HybridSearchResults = ({
  // NEW CONTRACT: the hub does all validation-merge / partition / facet / sort.
  // When VLM is on it hands us ordered, non-empty `sections` (one per bucket);
  // otherwise (or legacy callers) a single already-prepared list via `results`.
  sections = null,
  results = [],
  // Back-compat: older hub call sites pass the partitioned groups instead of a
  // single list. Accept them so the component keeps rendering, but no longer
  // render two sections — flatten into the single `results` region.
  validated = null,
  rejected = null,
  onItemClick,
  copyToClipboard,
  onFindSimilar,
  showScores = false,
  viewMode = "grid",
  gridSize = "L",
  isLoading = false,
  isEmpty = false,
  searchQuery = "",
  getHeaders,
  apiUrl,
  isValidating = false,
  validatedCount = 0,
  totalToValidate = 0,
  vlmUnavailable = false,
  vlmOn = false,
  emptyStateHints = [],
  downloadAsset,
  cancelDownload,
  downloadingUrl = null,
  queuedUrls = [],
}) => {
  // Resolve the single display list. Prefer the explicit `results` list; fall
  // back to flattening any validated/rejected groups a legacy parent passes.
  const items =
    results && results.length
      ? results
      : [...(validated || []), ...(rejected || [])];

  // Every item the loader should warm: across all sections when sectioned,
  // else the single display list. Keeps prefetch covering the full scroll area.
  const warmItems = sections ? sections.flatMap((s) => s.items) : items;

  // Once the user dismisses the "VLM validation unavailable" banner, keep it
  // dismissed for the rest of the session (survives re-searches and remounts)
  // rather than re-showing it after every search.
  const [vlmBannerDismissed, setVlmBannerDismissed] = React.useState(
    () => sessionStorage.getItem("vlmBannerDismissed") === "true"
  );

  // Per-section collapse state (keyed by section.key). Sections are open by
  // default — a key is present here only once the user collapses it.
  const [collapsedSections, setCollapsedSections] = React.useState({});
  const toggleSection = React.useCallback(
    (key) => setCollapsedSections((prev) => ({ ...prev, [key]: !prev[key] })),
    []
  );
  const dismissVlmBanner = React.useCallback(() => {
    sessionStorage.setItem("vlmBannerDismissed", "true");
    setVlmBannerDismissed(true);
  }, []);

  // Smart image loading for visible + buffer items. The cards/rows own their
  // own image fetch via NavigableAssetImage; this preserves the existing
  // prefetch/buffer warm-up wiring for the active list.
  useSmartImageLoader(warmItems, getHeaders, apiUrl, {
    bufferSize: 12,
    rootMargin: "300px", // Start loading earlier
    enabled: !isLoading && !isEmpty,
  });

  if (isLoading) {
    return (
      <div
        style={{
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          minHeight: "60vh",
          gap: 16,
        }}
      >
        <Spinner aria-label="Searching" />
        <p style={{ margin: 0, color: T.textSecondary, fontSize: "14px" }}>
          Searching…
        </p>
      </div>
    );
  }

  if (isEmpty) {
    return (
      <div style={{ textAlign: "center", padding: "48px 0" }}>
        <p style={{ fontSize: "16px", color: T.textSecondary }}>
          No results found{searchQuery ? ` for "${searchQuery}"` : ""}.
        </p>
        {emptyStateHints.length > 0 && (
          <div style={{ display: "flex", flexDirection: "column", gap: 4, marginTop: 12 }}>
            {emptyStateHints.map((hint) => (
              <p key={hint} style={{ fontSize: "14px", color: T.textMuted }}>
                {hint}
              </p>
            ))}
          </div>
        )}
      </div>
    );
  }

  const renderCardOrRow = (result, index) => {
    const ItemComponent = viewMode === "grid" ? CompactResultCard : CompactResultRow;
    return (
      <ItemComponent
        key={result.id || result.source?.base_key || `idx-${index}`}
        result={result}
        onItemClick={onItemClick}
        copyToClipboard={copyToClipboard}
        onFindSimilar={onFindSimilar}
        showScores={showScores}
        gridSize={gridSize}
        vlmOn={vlmOn}
        vlmUnavailable={vlmUnavailable}
        getHeaders={getHeaders}
        apiUrl={apiUrl}
        downloadAsset={downloadAsset}
        cancelDownload={cancelDownload}
        downloadingUrl={downloadingUrl}
        queuedUrls={queuedUrls}
      />
    );
  };

  // DIRECTION A — MOSAIC: CSS grid of square tiles.
  const renderGrid = (gridItems) => {
    const minTrack = gridSize === "S" ? "150px" : "190px";
    return (
      <div
        style={{
          display: "grid",
          gridTemplateColumns: `repeat(auto-fill, minmax(${minTrack}, 1fr))`,
          gap: "6px",
          width: "100%",
        }}
      >
        {gridItems.map((result, index) => renderCardOrRow(result, index))}
      </div>
    );
  };

  // Shared column-header row for the index (list) view — reused by the single
  // and the sectioned list renderers.
  const listColumnHeader = (
    <div
      style={{
        display: "flex",
        alignItems: "center",
        gap: "14px",
        padding: "9px 14px 9px 17px",
        background: "#0e0e10",
        borderBottom: `1px solid ${T.border}`,
        fontSize: "10px",
        fontWeight: 700,
        letterSpacing: ".06em",
        textTransform: "uppercase",
        color: T.textMuted,
      }}
    >
      {LIST_COLUMNS.map((col, i) => (
        <span
          key={col.label || `col-${i}`}
          style={{
            flex: col.flex != null ? col.flex : "none",
            width: col.w,
            minWidth: col.flex != null ? 0 : undefined,
            textAlign: col.align,
            whiteSpace: "nowrap",
          }}
        >
          {col.label}
        </span>
      ))}
    </div>
  );

  // DIRECTION B — INDEX (rows): bordered table with an aligned header row.
  const renderList = (listItems) => (
    <div
      style={{
        border: `1px solid ${T.border}`,
        borderRadius: "8px",
        overflow: "hidden",
      }}
    >
      {listColumnHeader}
      {listItems.map((result, index) => renderCardOrRow(result, index))}
    </div>
  );

  // VLM on (grid): render every bucket inside ONE grid so a card that migrates
  // between buckets (e.g. "In progress" → "Validated" when its verdict lands) is
  // a REORDER within the same parent — React moves the existing DOM node instead
  // of unmounting/remounting it. Separate per-section grids remount the card on
  // every migration, recreating its <img> and flashing the thumbnail as the
  // browser re-decodes the (cached) image. Full-width header tiles
  // (grid-column: 1 / -1) delimit the buckets; headers and cards are flat
  // siblings, each with a stable global key.
  const renderSectionedGrid = (secs) => {
    const minTrack = gridSize === "S" ? "150px" : "190px";
    const children = [];
    secs.forEach((section) => {
      const hasHeader = section.showHeader !== false && !!section.title;
      const open = !hasHeader || !collapsedSections[section.key];
      if (hasHeader) {
        children.push(
          <div
            key={`hdr-${section.key}`}
            style={{ gridColumn: "1 / -1", marginTop: children.length ? 20 : 0 }}
          >
            <SectionHeader
              variant={section.variant}
              title={section.title}
              subhead={section.subhead}
              count={section.items.length}
              open={open}
              onToggle={() => toggleSection(section.key)}
              halted={vlmUnavailable}
            />
          </div>
        );
      }
      if (open) {
        section.items.forEach((result, index) => children.push(renderCardOrRow(result, index)));
      }
    });
    return (
      <div
        style={{
          display: "grid",
          gridTemplateColumns: `repeat(auto-fill, minmax(${minTrack}, 1fr))`,
          gap: "6px",
          width: "100%",
        }}
      >
        {children}
      </div>
    );
  };

  // VLM on (list): one bordered table for all buckets, section header rows and
  // data rows interleaved as flat siblings — same no-remount rationale as the
  // grid renderer above.
  const renderSectionedList = (secs) => {
    const rows = [];
    secs.forEach((section) => {
      const hasHeader = section.showHeader !== false && !!section.title;
      const open = !hasHeader || !collapsedSections[section.key];
      if (hasHeader) {
        rows.push(
          <div key={`hdr-${section.key}`} style={{ padding: rows.length ? "18px 14px 2px" : "8px 14px 2px" }}>
            <SectionHeader
              variant={section.variant}
              title={section.title}
              subhead={section.subhead}
              count={section.items.length}
              open={open}
              onToggle={() => toggleSection(section.key)}
              halted={vlmUnavailable}
            />
          </div>
        );
      }
      if (open) {
        section.items.forEach((result, index) => rows.push(renderCardOrRow(result, index)));
      }
    });
    return (
      <div style={{ border: `1px solid ${T.border}`, borderRadius: "8px", overflow: "hidden" }}>
        {listColumnHeader}
        {rows}
      </div>
    );
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16, alignItems: "stretch" }}>
      {vlmUnavailable && !vlmBannerDismissed && (
        <Banner status="warning" onClose={dismissVlmBanner}>
          VLM validation unavailable. Pending validations remain in &quot;In progress&quot; category.
        </Banner>
      )}

      {/* Live validation progress; disappears on completion. */}
      {isValidating && totalToValidate > 0 && !vlmUnavailable && (
        <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "0 4px" }}>
          <span style={{ display: "inline-flex", transform: "scale(0.8)", transformOrigin: "center" }}>
            <Spinner size="small" aria-label="Validating" />
          </span>
          <span style={{ fontSize: "14px", color: T.textSecondary }}>
            Validating {validatedCount}/{totalToValidate}…
          </span>
        </div>
      )}

      {/* Stacked labeled sections (VLM on) or a single unlabeled region (VLM
          off / legacy single-list callers). The hub owns partition/facet/sort
          and only passes non-empty sections, so empty buckets self-omit. */}
      {sections
        ? viewMode === "grid"
          ? renderSectionedGrid(sections)
          : renderSectionedList(sections)
        : items.length > 0 && (viewMode === "grid" ? renderGrid(items) : renderList(items))}
    </div>
  );
};

export default HybridSearchResults;
