import React from 'react';
import { Skeleton } from '@kui/foundations-react';
import T from '../kui/tokens';

// Component-scoped keyframes. esFade/esSpin (index.css) don't cover the shimmer
// sweep or the staggered dot pulse, so they're inlined once here under unique
// names to avoid colliding with the global redesign keyframes.
const SKELETON_KEYFRAMES = `
@keyframes imageSkeletonShimmer {
  0% { background-position: -468px 0; }
  100% { background-position: 468px 0; }
}
@keyframes imageSkeletonPulse {
  0%, 80%, 100% { opacity: 0.3; transform: scale(0.8); }
  40% { opacity: 1; transform: scale(1); }
}
`;

/**
 * Animated skeleton loader for images
 * Provides a smooth loading experience while images are being fetched
 */
const ImageSkeleton = ({
  width = "200px",
  height = "150px",
  borderRadius = "md",
  variant = "ghost" // "ghost", "pulse", or "shimmer"
}) => {
  const radius = borderRadius === "md" ? T.radiusMd : borderRadius;

  if (variant === "shimmer") {
    return (
      <div
        style={{
          width,
          height,
          borderRadius: radius,
          position: "relative",
          overflow: "hidden",
          background: T.surfaceRaised,
        }}
      >
        <style>{SKELETON_KEYFRAMES}</style>
        <div
          style={{
            position: "absolute",
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background:
              "linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.1), transparent)",
            backgroundSize: "468px 100%",
            animation: "imageSkeletonShimmer 1.6s ease-in-out infinite",
          }}
        />
      </div>
    );
  }

  if (variant === "pulse") {
    return (
      <Skeleton
        style={{
          width,
          height,
          borderRadius: radius,
        }}
      />
    );
  }

  // Default "ghost" variant with subtle animated placeholder
  return (
    <div
      style={{
        width,
        height,
        borderRadius: radius,
        background: T.surfaceSunken,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        position: "relative",
        overflow: "hidden",
      }}
    >
      <style>{SKELETON_KEYFRAMES}</style>
      {/* Subtle background pattern */}
      <div
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          opacity: 0.1,
          backgroundImage:
            "radial-gradient(circle at 25% 25%, gray 2px, transparent 2px), radial-gradient(circle at 75% 75%, gray 2px, transparent 2px)",
          backgroundSize: "20px 20px",
        }}
      />

      {/* Animated dots indicator */}
      <div style={{ display: "flex", gap: "2px" }}>
        {[0, 1, 2].map((index) => (
          <div
            key={index}
            style={{
              width: "6px",
              height: "6px",
              background: "rgba(255,255,255,.28)",
              borderRadius: "9999px",
              animation: "imageSkeletonPulse 1.4s ease-in-out infinite",
              animationDelay: `${index * 0.2}s`,
            }}
          />
        ))}
      </div>
    </div>
  );
};

/**
 * Higher-order component that wraps images with loading states
 */
export const ImageWithSkeleton = ({
  src,
  alt,
  isLoading = false,
  hasError = false,
  skeletonProps = {},
  errorContent = "No Image",
  ...imageProps
}) => {
  if (hasError) {
    return (
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          background: T.surfaceSunken,
          color: T.textMuted,
          fontSize: "14px",
          fontWeight: 500,
          width: imageProps.width || imageProps.w || "200px",
          height: imageProps.height || imageProps.h || "150px",
          borderRadius:
            (imageProps.borderRadius === "md"
              ? T.radiusMd
              : imageProps.borderRadius) || T.radiusMd,
          border: `2px dashed ${T.border}`,
        }}
      >
        {errorContent}
      </div>
    );
  }

  if (isLoading || !src) {
    return (
      <ImageSkeleton
        width={imageProps.width || imageProps.w || "200px"}
        height={imageProps.height || imageProps.h || "150px"}
        borderRadius={imageProps.borderRadius || "md"}
        {...skeletonProps}
      />
    );
  }

  const { width, w, height, h, borderRadius, objectFit, ...rest } = imageProps;
  const imgRadius = borderRadius === "md" ? T.radiusMd : borderRadius;

  return (
    <img
      src={src}
      alt={alt}
      // No `loading="lazy"`: the app already gates fetches through
      // useSmartImageLoader (IntersectionObserver) + the blob cache, so the src
      // is a resolved blob URL by the time this renders. Worse, a lazy <img>
      // that React relocates in the DOM — which happens every time a card
      // migrates between the Validated / Rejected / In-progress buckets as its
      // VLM verdict lands — gets its lazy state re-evaluated by the browser and
      // re-decoded, flashing the thumbnail once per validated asset. `decoding`
      // async keeps the (already-decoded) bitmap painting smoothly on the move.
      decoding="async"
      style={{
        width: width || w,
        height: height || h,
        borderRadius: imgRadius,
        objectFit: objectFit,
      }}
      {...rest}
    />
  );
};

export default ImageSkeleton;
