import React, { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { Badge, Button, SegmentedControl, Slider, Switch, TextInput } from "@kui/foundations-react";
import { ChevronDownGlyph } from "./icons";
import {
  ADVANCED_SECTIONS,
  ALL_ADVANCED_FIELDS,
  DEBOUNCE_MS,
  buildAdvancedDefaults,
  countSetFields,
  validateField,
} from "../utils/advancedFilters";
import T from "../kui/tokens";

const MONO = T.mono;

// Fields whose edits are debounced before re-issuing the search (free text /
// numeric / date / slider). Toggles + segmented apply immediately.
const DEBOUNCED_TYPES = new Set(["text", "number", "date", "size", "slider"]);
const isDebounced = (type) => DEBOUNCED_TYPES.has(type);

// Pull just the debounced (editable) field names so the local draft tracks them
// and re-seeds when the committed values change underneath us (NL parse, reset).
function pickDraft(values) {
  const out = {};
  for (const s of ADVANCED_SECTIONS) {
    for (const f of s.fields) {
      if (isDebounced(f.type)) out[f.name] = values?.[f.name] ?? "";
    }
  }
  return out;
}

// ---- shared mini-controls (match the FilterRail dark styling) -------------

const SectionHeader = ({ title, open, onToggle, badge }) => (
  <button
    type="button"
    onClick={onToggle}
    style={{
      display: "flex",
      alignItems: "center",
      gap: 8,
      width: "100%",
      padding: "13px 20px",
      background: "none",
      border: "none",
      cursor: "pointer",
    }}
  >
    <span style={{ flex: 1, textAlign: "left", fontSize: 15, fontWeight: 500, color: "#cfcfd2", fontFamily: MONO }}>
      {title}
    </span>
    {badge}
    <ChevronDownGlyph
      width={14}
      height={14}
      color="#8a8a8e"
      style={{ transform: open ? "rotate(180deg)" : "rotate(0deg)", transition: "transform .15s" }}
    />
  </button>
);

const CountBadge = ({ n }) =>
  n > 0 ? (
    <Badge color="green" kind="solid">
      {n}
    </Badge>
  ) : null;

const DotBadge = ({ on }) =>
  on ? <span style={{ width: 7, height: 7, borderRadius: 999, background: T.brand, display: "inline-block" }} /> : null;

const FieldLabel = ({ children }) => (
  <div style={{ fontSize: 14, color: "#9a9a9e", marginBottom: 5, fontFamily: MONO }}>{children}</div>
);

/**
 * Advanced (structured, server-side) filters — the second tier below the
 * client-side drill-down facets in the rail. Each control binds to a
 * /search_hybrid request param; editing one re-issues the search. Text/number/
 * date/slider edits are debounced (~350ms) and validated before firing;
 * toggles + segmented apply immediately.
 */
const AdvancedFilters = ({
  values,
  fileExtensionInclude = "usd*",
  cutoffThreshold = "",
  openSections,
  onToggleSection,
  onApply, // (patch) => commit to searchParams (no search)
  onCommitSearch, // () => trigger the (debounced) re-search
  onReset, // () => reset advanced filters to defaults + re-search
}) => {
  const defaults = useMemo(
    () => buildAdvancedDefaults({ fileExtensionInclude, cutoffThreshold }),
    [fileExtensionInclude, cutoffThreshold]
  );

  const [draft, setDraft] = useState(() => pickDraft(values));
  const [errors, setErrors] = useState({});
  const timerRef = useRef(null);
  const dirtyRef = useRef(false);

  // Total advanced filters set to a non-default value — shown on the group
  // header as an at-a-glance active-filter count.
  const activeCount = countSetFields(ALL_ADVANCED_FIELDS, values, defaults);

  // Re-seed the draft when the committed values change externally (a parsed NL
  // query populating fields, Reset, or Clear-all) — but never mid-edit, so we
  // don't clobber what the user is typing before the debounce fires.
  const valuesKey = useMemo(() => JSON.stringify(pickDraft(values)), [values]);
  useEffect(() => {
    if (dirtyRef.current) return;
    setDraft(pickDraft(values));
    setErrors({});
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [valuesKey]);

  useEffect(() => () => clearTimeout(timerRef.current), []);

  // Debounced editable field (text/number/date/size/slider).
  const onEdit = useCallback(
    (name, raw) => {
      setDraft((d) => ({ ...d, [name]: raw }));
      const err = validateField(name, raw);
      setErrors((e) => ({ ...e, [name]: err || undefined }));
      dirtyRef.current = true;
      clearTimeout(timerRef.current);
      if (err) return; // invalid: hold the search, show inline error
      timerRef.current = setTimeout(() => {
        onApply({ [name]: raw });
        onCommitSearch();
        dirtyRef.current = false;
      }, DEBOUNCE_MS);
    },
    [onApply, onCommitSearch]
  );

  // Immediate field (toggle/segmented) — apply + search right away.
  const onImmediate = useCallback(
    (patch) => {
      onApply(patch);
      onCommitSearch();
    },
    [onApply, onCommitSearch]
  );

  const renderField = (f) => {
    const err = errors[f.name];
    if (f.type === "toggle") {
      const on = (values?.[f.name] ?? defaults[f.name]) === true;
      return (
        <div key={f.name} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "5px 0" }}>
          <span style={{ fontSize: 14.5, color: "#cfcfd2", fontFamily: MONO }}>{f.label}</span>
          <Switch size="small" checked={on} onCheckedChange={(c) => onImmediate({ [f.name]: c })} aria-label={f.label} />
        </div>
      );
    }

    if (f.type === "segmented") {
      const cur = values?.[f.name] ?? defaults[f.name];
      return (
        <div key={f.name} style={{ padding: "4px 0" }}>
          <FieldLabel>{f.label}</FieldLabel>
          <SegmentedControl
            size="tiny"
            value={String(cur)}
            onValueChange={(v) => {
              const opt = f.options.find((o) => String(o.value) === v);
              onImmediate({ [f.name]: opt ? opt.value : v });
            }}
            items={f.options.map((o) => ({ value: String(o.value), children: o.label }))}
            style={{ width: "100%" }}
          />
        </div>
      );
    }

    if (f.type === "slider") {
      const num = Number(draft[f.name]) || 0;
      return (
        <div key={f.name} style={{ padding: "4px 0" }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 6 }}>
            <span style={{ fontSize: 14, color: "#9a9a9e", fontFamily: MONO }}>{f.label}</span>
            <span style={{ fontSize: 14, color: "#e8e8ea", fontVariantNumeric: "tabular-nums" }}>
              {num > 0 ? num.toFixed(2) : "off"}
            </span>
          </div>
          <Slider
            min={f.min}
            max={f.max}
            step={f.step}
            value={num}
            aria-label={f.label}
            onValueChange={(v) => {
              // 0 = off → omit the param entirely.
              onEdit(f.name, v === (f.offValue === "" ? 0 : f.offValue) ? "" : v);
            }}
          />
        </div>
      );
    }

    // text / number / date / size
    const inputType = f.type === "date" ? "date" : f.type === "number" ? "number" : "text";
    return (
      <div key={f.name} style={{ padding: "4px 0" }}>
        <FieldLabel>{f.label}</FieldLabel>
        <TextInput
          size="small"
          type={inputType}
          value={draft[f.name] ?? ""}
          placeholder={f.placeholder}
          aria-label={f.label}
          status={err ? "error" : undefined}
          onValueChange={(v) => onEdit(f.name, v)}
          attributes={{ Input: { step: f.step, min: f.min, max: f.max } }}
        />
        {err && <div style={{ fontSize: 12.5, color: T.danger, marginTop: 3 }}>{err}</div>}
      </div>
    );
  };

  return (
    <div>
      {/* Group header — a static label with an active-count badge and Reset.
          Advanced filters is the only group in the rail, so it no longer
          collapses as a unit; each section below toggles on its own. */}
      <div style={{ display: "flex", alignItems: "center", minHeight: 57, padding: "0 20px", boxSizing: "border-box", gap: 8 }}>
        <span style={{ fontSize: 13, fontWeight: 700, letterSpacing: ".05em", textTransform: "uppercase", whiteSpace: "nowrap", color: "#8a8a8e" }}>
          Advanced filters
        </span>
        <CountBadge n={activeCount} />
        <span style={{ flex: 1 }} />
        <Button kind="tertiary" color="neutral" size="tiny" onClick={onReset} style={{ flex: "none" }}>
          Reset
        </Button>
      </div>

      {ADVANCED_SECTIONS.map((section) => {
          const open = !!openSections?.[section.key];
          const names = section.fields.map((f) => f.name);
          const setCount = countSetFields(names, values, defaults);
          const badge = section.badge === "dot" ? <DotBadge on={setCount > 0} /> : <CountBadge n={setCount} />;
          const isGrid = section.key === "dimension";
          return (
            <div key={section.key} style={{ borderTop: `1px solid ${T.border}` }}>
              <SectionHeader
                title={section.title}
                open={open}
                onToggle={() => onToggleSection(section.key)}
                badge={badge}
              />
              {open && (
                <div style={{ padding: "0 20px 16px" }}>
                  {isGrid ? (
                    <>
                      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 8 }}>
                        {section.fields.filter((f) => f.type === "number").map((f) => renderField(f))}
                      </div>
                      {section.fields.filter((f) => f.type !== "number").map((f) => renderField(f))}
                    </>
                  ) : (
                    section.fields.map((f) => renderField(f))
                  )}
                </div>
              )}
            </div>
          );
        })}
    </div>
  );
};

export default AdvancedFilters;
