import React from "react";
import { Button, Spinner } from "@kui/foundations-react";
import { DownloadGlyph, CloseGlyph } from "./icons";

const SIZE_MAP = { xs: "tiny", sm: "small", md: "medium", lg: "large" };

// Per-asset download control with three states, driven by the shared download
// manager: idle (download), active (spinner + cancel), queued (pending + cancel).
// Downloads run one at a time globally; clicking download enqueues the asset.
// No hover tooltips — a tooltip near a result-card edge forced an overflow that
// shifted the whole page layout on hover; aria-labels keep it accessible.
const DownloadControl = ({
  url,
  name,
  downloadingUrl = null,
  queuedUrls = [],
  onDownload,
  onCancel,
  size = "sm",
  // Result thumbnails sit inside a clickable card — stop clicks from also
  // opening the asset modal.
  stopPropagation = true,
}) => {
  const btnSize = SIZE_MAP[size] || "small";
  const isActive = !!url && url === downloadingUrl;
  const isQueued = !!url && queuedUrls.includes(url);
  const swallow = (e) => {
    if (stopPropagation && e) e.stopPropagation();
  };

  const cancelButton = (label) => (
    <Button
      kind="tertiary"
      color="danger"
      size={btnSize}
      aria-label={label}
      onClick={(e) => {
        swallow(e);
        onCancel?.(url);
      }}
    >
      <CloseGlyph width={11} height={11} strokeWidth={2.4} />
    </Button>
  );

  if (isActive) {
    return (
      <div style={{ display: "flex", alignItems: "center", gap: 2 }} onClick={swallow}>
        <span style={{ display: "flex", alignItems: "center", padding: "0 4px" }}>
          <Spinner size="small" />
        </span>
        {cancelButton("Cancel download")}
      </div>
    );
  }

  if (isQueued) {
    return (
      <div style={{ display: "flex", alignItems: "center", gap: 2 }} onClick={swallow}>
        <span style={{ display: "flex", alignItems: "center", padding: "0 4px", opacity: 0.6 }}>
          <Spinner size="small" />
        </span>
        {cancelButton("Remove from queue")}
      </div>
    );
  }

  return (
    <Button
      kind="tertiary"
      color="neutral"
      size={btnSize}
      aria-label="Download asset and dependencies"
      onClick={(e) => {
        swallow(e);
        onDownload?.(url, name);
      }}
    >
      <DownloadGlyph width={15} height={15} />
    </Button>
  );
};

export default React.memo(DownloadControl);
