"use client";

import { useCallback } from 'react';

const useIndeterminateInputRef = (ref, indeterminate) => useCallback((input) => {
  if (input) {
    input.indeterminate = indeterminate;
  }
  if (typeof ref === "function") {
    ref(input);
  } else if (ref) {
    ref.current = input;
  }
}, [indeterminate, ref]);

export { useIndeterminateInputRef };
