import React, { useState } from "react";
import { Badge, Button } from "@kui/foundations-react";
import { ChevronDownGlyph } from "./components/icons";
import T from "./kui/tokens";

const getSearchTypeColor = (searchType) => {
  const colors = {
    text: "blue",
    hybrid: "green",
    vector: "purple",
    image_similarity: "yellow",
    filter_only: "gray",
    text_to_vector: "teal",
  };
  return colors[searchType] || "gray";
};

/**
 * Compact, at-a-glance breakdown of why an asset matched. One row per
 * contributing signal (search type · field · score), sorted by score — no
 * progress bars, per-row expanders, or nested detail dumps. A small summary
 * line carries the total score and RRF rank.
 */
const SearchExplanations = ({
  explanations = [],
  totalScore = 0,
  rrfRank = null,
  showSummary = true,
  maxItems = 5,
}) => {
  const [showAll, setShowAll] = useState(false);

  if (!explanations || explanations.length === 0) {
    return null;
  }

  const sortedExplanations = [...explanations].sort((a, b) => b.score - a.score);
  const displayedExplanations = showAll ? sortedExplanations : sortedExplanations.slice(0, maxItems);

  return (
    <div>
      {showSummary && (
        <div
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            marginBottom: 8,
          }}
        >
          <span style={{ fontSize: 12, color: T.textMuted }}>
            {explanations.length} signal{explanations.length === 1 ? "" : "s"}
          </span>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            {rrfRank && (
              <Badge color="yellow" kind="solid">
                RRF #{rrfRank}
              </Badge>
            )}
            <span style={{ fontSize: 12, fontWeight: 700, color: T.accentText }}>
              Total {totalScore.toFixed(3)}
            </span>
          </div>
        </div>
      )}

      <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
        <thead>
          <tr>
            <th
              style={{
                color: T.textSecondary,
                padding: "6px 8px",
                textAlign: "left",
                fontWeight: 600,
                borderBottom: `1px solid ${T.border}`,
              }}
            >
              Type
            </th>
            <th
              style={{
                color: T.textSecondary,
                padding: "6px 8px",
                textAlign: "left",
                fontWeight: 600,
                borderBottom: `1px solid ${T.border}`,
              }}
            >
              Field
            </th>
            <th
              style={{
                color: T.textSecondary,
                padding: "6px 8px",
                textAlign: "right",
                fontWeight: 600,
                borderBottom: `1px solid ${T.border}`,
              }}
            >
              Score
            </th>
          </tr>
        </thead>
        <tbody>
          {displayedExplanations.map((explanation, index) => (
            <tr key={`${explanation.field}-${explanation.search_type}-${index}`}>
              <td style={{ padding: "4px 8px", borderBottom: `1px solid ${T.border}` }}>
                <Badge color={getSearchTypeColor(explanation.search_type)} kind="solid">
                  {explanation.search_type.replace(/_/g, " ")}
                </Badge>
              </td>
              <td
                style={{
                  padding: "4px 8px",
                  fontSize: 12,
                  fontFamily: T.mono,
                  borderBottom: `1px solid ${T.border}`,
                }}
              >
                {explanation.field}
              </td>
              <td
                style={{
                  padding: "4px 8px",
                  fontSize: 12,
                  textAlign: "right",
                  fontWeight: 600,
                  fontVariantNumeric: "tabular-nums",
                  borderBottom: `1px solid ${T.border}`,
                }}
              >
                {explanation.score.toFixed(3)}
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {explanations.length > maxItems && (
        <div
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            gap: 8,
            marginTop: 8,
          }}
        >
          <Button
            kind="tertiary"
            color="neutral"
            size="tiny"
            onClick={() => setShowAll(!showAll)}
            aria-label={showAll ? "Show less" : "Show more"}
          >
            <ChevronDownGlyph
              width={14}
              height={14}
              style={{ transform: showAll ? "rotate(180deg)" : "none" }}
            />
          </Button>
          <span style={{ fontSize: 12, color: T.textMuted }}>
            {showAll ? "Show less" : `Show ${explanations.length - maxItems} more`}
          </span>
        </div>
      )}
    </div>
  );
};

export default SearchExplanations;
