import React, { useState, useEffect } from "react";
import { defaultEmbeddingConfig, DEFAULT_TEXT_WEIGHT, DEFAULT_CROSS_FIELD_OPERATOR } from "./config";
import { Divider, SegmentedControl, Slider, Switch, TextInput } from "@kui/foundations-react";
import T from "./kui/tokens";

const MONO = T.mono;

// Friendly labels for the per-field text legs (mirrors main).
const FIELD_DISPLAY_NAMES = {
  name: "Name",
  "name.simple": "Name (simple)",
  "name.standard": "Name (standard)",
  "usd_properties.value": "USD Properties Value",
  "usd_properties.key": "USD Properties Key",
  "tags.tag": "Tag",
  "tags.value": "Tag Value",
  path: "Path",
  "path.tree": "Path Tree",
  "path.tree_reversed": "Path Tree Reversed",
  __VISION_METADATA_FIELDS__: "Vision Metadata (All Fields)",
};
const getFieldDisplayName = (fieldName) => FIELD_DISPLAY_NAMES[fieldName] || fieldName;

// Disclosure chevron for the collapsible per-field subsections.
const Chevron = ({ open }) => (
  <span
    style={{
      width: 14,
      height: 14,
      flex: "none",
      display: "inline-flex",
      alignItems: "center",
      justifyContent: "center",
      color: "#7a7a7e",
      transform: open ? "rotate(90deg)" : "rotate(0deg)",
      transition: "transform .15s",
    }}
  >
    <svg width="7" height="11" viewBox="0 0 7 11" fill="none" aria-hidden="true">
      <path d="M1 1l4.5 4.5L1 10" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  </span>
);

// The full default scoring config. The simplified UI below exposes only the
// top-level knobs (text/vector weight + enabled, cross-field operator, vector
// text expansion, RRF rank constant / window size); the per-field `fields`
// list and embedding wiring are kept intact so the backend request is still
// fully formed — power users get the simple surface, the model keeps the
// detailed config.
const DEFAULT_HYBRID_CONFIG = {
  rrf_config: {
    rank_constant: 60,
    // window_size: null,
    query_rank_constants: {}
  },
  vector_text_expansion: {
    enabled: false
  },
  hybrid_text: {
    enabled: true,
    weight: DEFAULT_TEXT_WEIGHT,
    fields: [
      { field: "name", nested: false, enabled: true, weight: 2.0, match_type: "fuzzy", fuzzy_max_expansions: 1, wildcard: true },
      { field: "name.simple", nested: false, enabled: true, weight: 2.0, match_type: "fuzzy", fuzzy_max_expansions: 1, wildcard: true },
      { field: "name.standard", nested: false, enabled: true, weight: 2.0, match_type: "fuzzy", fuzzy_max_expansions: 1, wildcard: true },
      { field: "usd_properties.value", nested: true, enabled: true, weight: 1.0, match_type: "fuzzy", fuzzy_max_expansions: 1, wildcard: true },
      { field: "usd_properties.key", nested: true, enabled: true, weight: 1.0, match_type: "fuzzy", fuzzy_max_expansions: 1, wildcard: true },
      { field: "tags.tag", nested: true, enabled: true, weight: 1.0, match_type: "fuzzy", fuzzy_max_expansions: 1, wildcard: true },
      { field: "tags.value", nested: true, enabled: true, weight: 1.0, match_type: "fuzzy", fuzzy_max_expansions: 1, wildcard: true },
      { field: "path", nested: false, enabled: true, weight: 1.0, match_type: "fuzzy", fuzzy_max_expansions: 1, wildcard: true },
      { field: "path.tree", nested: false, enabled: true, weight: 1.0, match_type: "fuzzy", fuzzy_max_expansions: 1, wildcard: true },
      { field: "path.tree_reversed", nested: false, enabled: true, weight: 1.0, match_type: "fuzzy", fuzzy_max_expansions: 1, wildcard: true },
      { field: "__VISION_METADATA_FIELDS__", nested: false, enabled: true, weight: 1.0, match_type: "fuzzy", fuzzy_max_expansions: 1, wildcard: true },
      // Exact-match name legs: boost results whose name matches the query exactly
      // (analyzer=keyword => whole query is one token), weighted above the fuzzy
      // name legs so a precise hit ranks first.
      { field: "name", nested: false, enabled: true, weight: 5.0, match_type: "exact", analyzer: "keyword", wildcard: false },
      { field: "name.standard", nested: false, enabled: true, weight: 5.0, match_type: "exact", analyzer: "keyword", wildcard: false },
    ],
    cross_field_operator: DEFAULT_CROSS_FIELD_OPERATOR
  },
  vector_fields: {
    [defaultEmbeddingConfig.field_name]: {
      enabled: true,
      weight: 1.0,
      field_name: defaultEmbeddingConfig.field_name,
      dimension: defaultEmbeddingConfig.dimension || 1024,
      // model_name: null
    }
  }
};

const SubLabel = ({ children }) => (
  <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 7 }}>{children}</div>
);

const Hairline = () => <Divider style={{ margin: "16px 0" }} />;

/**
 * Advanced scoring (hybrid search configuration) — the simplified, redesigned
 * surface. Top to bottom: similarity cutoff, text search (weight + cross-field
 * operator), vector search (weight + text expansion), and RRF (rank constant +
 * window size). Disabled subsections dim and ignore pointer events.
 *
 * Props:
 *   value / onChange — the scoring_config object (DEFAULT_HYBRID_CONFIG shape).
 *   cutoff / onCutoffChange — the similarity cutoff (searchParams.cutoff_threshold,
 *     a string; "" = no cutoff). onCutoffChange receives a string.
 *   embeddingConfig — keeps vector_fields aligned with the active server.
 */
const HybridSearchConfig = ({
  value = DEFAULT_HYBRID_CONFIG,
  onChange,
  cutoff = "",
  onCutoffChange,
  embeddingConfig = defaultEmbeddingConfig,
}) => {
  const [config, setConfig] = useState(value);
  // Per-field editors are powerful but long — collapsed by default.
  const [textFieldsOpen, setTextFieldsOpen] = useState(false);
  const [vectorFieldsOpen, setVectorFieldsOpen] = useState(false);

  // Sync internal state with prop value when it changes
  useEffect(() => {
    setConfig(value);
  }, [value]);

  // Keep vector_fields aligned with the active server's embedding config.
  useEffect(() => {
    if (embeddingConfig?.field_name) {
      const currentFieldNames = Object.keys(config.vector_fields);
      const currentDimensions = Object.values(config.vector_fields).map((v) => v.dimension);
      if (
        !currentFieldNames.includes(embeddingConfig.field_name) ||
        !currentDimensions.includes(embeddingConfig.dimension)
      ) {
        // Preserve the user's current weight/enabled when re-keying the field.
        const prev = Object.values(config.vector_fields)[0] || {};
        const newVectorFields = {
          [embeddingConfig.field_name]: {
            enabled: prev.enabled !== undefined ? prev.enabled : true,
            weight: prev.weight !== undefined ? prev.weight : 1.0,
            field_name: embeddingConfig.field_name,
            dimension: embeddingConfig.dimension || 1024,
          },
        };
        const newConfig = { ...config, vector_fields: newVectorFields };
        setConfig(newConfig);
        onChange?.(newConfig);
      }
    }
  }, [embeddingConfig]); // eslint-disable-line react-hooks/exhaustive-deps

  const updateConfig = (newConfig) => {
    setConfig(newConfig);
    onChange?.(newConfig);
  };

  const updateHybridText = (field, fieldValue) =>
    updateConfig({ ...config, hybrid_text: { ...config.hybrid_text, [field]: fieldValue } });

  const updateRRFConfig = (field, fieldValue) =>
    updateConfig({ ...config, rrf_config: { ...config.rrf_config, [field]: fieldValue } });

  // Per-field text leg editing (enable / weight / match type / fuzziness /
  // wildcard). Toggling match_type keeps fuzzy_max_expansions consistent.
  const updateHybridTextField = (fieldIndex, field, fieldValue) => {
    const newFields = config.hybrid_text.fields.map((f, i) => (i === fieldIndex ? { ...f, [field]: fieldValue } : f));
    if (field === "match_type" && fieldValue === "exact") {
      delete newFields[fieldIndex].fuzzy_max_expansions;
    } else if (field === "match_type" && fieldValue === "fuzzy") {
      newFields[fieldIndex].fuzzy_max_expansions = newFields[fieldIndex].fuzzy_max_expansions || 1;
    }
    updateConfig({ ...config, hybrid_text: { ...config.hybrid_text, fields: newFields } });
  };

  // Per-vector-field editing (enable / weight) for a single named field.
  const updateVectorField = (fieldName, field, fieldValue) =>
    updateConfig({
      ...config,
      vector_fields: {
        ...config.vector_fields,
        [fieldName]: { ...config.vector_fields[fieldName], [field]: fieldValue },
      },
    });

  // Vector enabled/weight applies across every configured vector field
  // (typically a single embedding field).
  const updateAllVectorFields = (field, fieldValue) => {
    const newVectorFields = {};
    Object.entries(config.vector_fields).forEach(([name, fc]) => {
      newVectorFields[name] = { ...fc, [field]: fieldValue };
    });
    updateConfig({ ...config, vector_fields: newVectorFields });
  };

  const textEnabled = config.hybrid_text.enabled;
  const textWeight = config.hybrid_text.weight ?? 0;
  const crossFieldOp = config.hybrid_text.cross_field_operator || "or";
  const firstVector = Object.values(config.vector_fields)[0] || {};
  const vectorEnabled = firstVector.enabled !== false;
  const vectorWeight = firstVector.weight ?? 0;
  const vectorExpansion = config.vector_text_expansion?.enabled || false;
  const rankConstant = config.rrf_config?.rank_constant ?? 60;
  const windowSize = config.rrf_config?.window_size ?? null;

  const textFields = config.hybrid_text?.fields || [];
  const activeTextFields = textFields.filter((f) => f.enabled).length;
  const vectorEntries = Object.entries(config.vector_fields || {});
  const activeVectorFields = vectorEntries.filter(([, fc]) => fc.enabled !== false).length;

  const cutoffNum = cutoff === "" || cutoff == null ? 0 : parseFloat(cutoff) || 0;

  const labelText = { fontSize: 12.5, color: "#cfcfd2" };
  const valueText = { fontSize: 12.5, fontWeight: 600, color: "#e8e8ea", fontVariantNumeric: "tabular-nums" };
  const helpText = { fontSize: 11, color: "#7a7a7e", lineHeight: 1.5 };
  const sectionTitle = { flex: 1, textAlign: "left", fontSize: 12.5, fontWeight: 600, color: "#e8e8ea" };
  const rrfFieldLabel = { display: "block", fontSize: 11.5, color: "#9a9a9e", marginBottom: 5 };
  // The collapsible per-field disclosure triggers are unstyled buttons.
  const disclosureButton = {
    display: "flex",
    alignItems: "center",
    width: "100%",
    gap: 8,
    padding: 0,
    background: "none",
    border: "none",
    cursor: "pointer",
    fontFamily: "inherit",
  };

  return (
    <div style={{ padding: 16 }}>
      {/* Similarity cutoff */}
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 9 }}>
        <span style={labelText}>Similarity cutoff</span>
        <span style={{ ...valueText, color: T.accentText }}>{cutoffNum.toFixed(2)}</span>
      </div>
      <Slider
        value={cutoffNum}
        min={0}
        max={1}
        step={0.01}
        aria-label="Similarity cutoff"
        onValueChange={(v) => onCutoffChange?.(v === 0 ? "" : String(v))}
      />
      <p style={{ ...helpText, marginTop: 8 }}>
        Matches scoring below the cutoff are hidden. Raise for precision, lower for recall.
      </p>

      <Hairline />

      {/* Text search */}
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        <span style={sectionTitle}>Text search</span>
        <Switch
          size="small"
          checked={textEnabled}
          onCheckedChange={(c) => updateHybridText("enabled", c)}
          aria-label="Enable text search"
        />
      </div>
      <div style={{ opacity: textEnabled ? 1 : 0.4, pointerEvents: textEnabled ? "auto" : "none", marginTop: 11 }}>
        <SubLabel>
          <span style={{ fontSize: 12, color: "#cfcfd2" }}>Text weight</span>
          <span style={{ fontSize: 12, fontWeight: 600, color: "#e8e8ea", fontVariantNumeric: "tabular-nums" }}>
            {textWeight.toFixed(1)}
          </span>
        </SubLabel>
        <Slider value={textWeight} min={0} max={5} step={0.1} aria-label="Text weight" onValueChange={(v) => updateHybridText("weight", v)} />
        <p style={{ ...helpText, margin: "11px 0 7px" }}>Cross-field operator</p>
        <SegmentedControl
          size="small"
          value={crossFieldOp}
          onValueChange={(v) => updateHybridText("cross_field_operator", v)}
          items={[
            { value: "or", children: "OR" },
            { value: "and", children: "AND" },
          ]}
          style={{ width: "100%" }}
        />

        {/* Per-field text legs: enable / weight / match type / fuzziness / wildcard */}
        <button type="button" style={{ ...disclosureButton, marginTop: 14 }} onClick={() => setTextFieldsOpen((o) => !o)}>
          <span style={{ flex: 1, textAlign: "left", fontSize: 12, color: "#cfcfd2" }}>Text search fields</span>
          <span style={{ fontSize: 11, color: "#7a7a7e", fontVariantNumeric: "tabular-nums" }}>
            {activeTextFields}/{textFields.length}
          </span>
          <Chevron open={textFieldsOpen} />
        </button>
        {textFieldsOpen && (
          <div style={{ marginTop: 10 }}>
            {textFields.map((f, index) => {
              const fuzzy = f.match_type !== "exact";
              return (
                <div
                  key={`${f.field}-${index}`}
                  style={{
                    border: `1px solid ${T.border}`,
                    borderRadius: 7,
                    background: "#0e0e10",
                    padding: 10,
                    marginBottom: 8,
                  }}
                >
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <span
                      style={{
                        flex: 1,
                        minWidth: 0,
                        fontSize: 12,
                        color: "#e8e8ea",
                        whiteSpace: "nowrap",
                        overflow: "hidden",
                        textOverflow: "ellipsis",
                      }}
                    >
                      {getFieldDisplayName(f.field)}
                    </span>
                    {f.nested && (
                      <span
                        style={{
                          fontSize: 9,
                          fontWeight: 600,
                          padding: "1px 5px",
                          borderRadius: 4,
                          background: "rgba(91,141,239,.16)",
                          color: "#8fb4f7",
                          textTransform: "uppercase",
                          letterSpacing: ".04em",
                        }}
                      >
                        Nested
                      </span>
                    )}
                    <Switch
                      size="small"
                      checked={!!f.enabled}
                      onCheckedChange={(c) => updateHybridTextField(index, "enabled", c)}
                      aria-label={`Enable ${f.field}`}
                    />
                  </div>
                  {f.enabled && (
                    <div style={{ marginTop: 10 }}>
                      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 5 }}>
                        <span style={{ fontSize: 11, color: "#9a9a9e" }}>Weight</span>
                        <span style={{ fontSize: 11, fontWeight: 600, color: "#e8e8ea", fontVariantNumeric: "tabular-nums" }}>
                          {(f.weight ?? 0).toFixed(1)}
                        </span>
                      </div>
                      <Slider
                        value={f.weight ?? 0}
                        min={0}
                        max={5}
                        step={0.1}
                        aria-label={`Weight for ${f.field}`}
                        onValueChange={(v) => updateHybridTextField(index, "weight", v)}
                      />
                      <p style={{ fontSize: 11, color: "#7a7a7e", margin: "11px 0 6px" }}>Match type</p>
                      <SegmentedControl
                        size="small"
                        value={fuzzy ? "fuzzy" : "exact"}
                        onValueChange={(v) => updateHybridTextField(index, "match_type", v)}
                        items={[
                          { value: "fuzzy", children: "Fuzzy" },
                          { value: "exact", children: "Exact" },
                        ]}
                        style={{ width: "100%" }}
                      />
                      {fuzzy && (
                        <div style={{ marginTop: 10 }}>
                          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 5 }}>
                            <span style={{ fontSize: 11, color: "#9a9a9e" }}>Fuzziness</span>
                            <span style={{ fontSize: 11, fontWeight: 600, color: "#e8e8ea", fontVariantNumeric: "tabular-nums" }}>
                              {f.fuzzy_max_expansions ?? 1}
                            </span>
                          </div>
                          <Slider
                            value={f.fuzzy_max_expansions ?? 1}
                            min={0}
                            max={5}
                            step={1}
                            aria-label={`Fuzziness for ${f.field}`}
                            onValueChange={(v) => updateHybridTextField(index, "fuzzy_max_expansions", v)}
                          />
                        </div>
                      )}
                      <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 11 }}>
                        <span style={{ flex: 1, fontSize: 11, color: "#9a9a9e" }}>Wildcard</span>
                        <Switch
                          size="small"
                          checked={f.wildcard !== false}
                          onCheckedChange={(c) => updateHybridTextField(index, "wildcard", c)}
                          aria-label={`Wildcard for ${f.field}`}
                        />
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>

      <Hairline />

      {/* Vector search */}
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        <span style={sectionTitle}>Vector search</span>
        <Switch
          size="small"
          checked={vectorEnabled}
          onCheckedChange={(c) => updateAllVectorFields("enabled", c)}
          aria-label="Enable vector search"
        />
      </div>
      <div style={{ opacity: vectorEnabled ? 1 : 0.4, pointerEvents: vectorEnabled ? "auto" : "none", marginTop: 11 }}>
        <SubLabel>
          <span style={{ fontSize: 12, color: "#cfcfd2" }}>Vector weight</span>
          <span style={{ fontSize: 12, fontWeight: 600, color: "#e8e8ea", fontVariantNumeric: "tabular-nums" }}>
            {vectorWeight.toFixed(1)}
          </span>
        </SubLabel>
        <Slider value={vectorWeight} min={0} max={5} step={0.1} aria-label="Vector weight" onValueChange={(v) => updateAllVectorFields("weight", v)} />

        {/* Per-field vector legs: enable / weight per embedding field */}
        <button type="button" style={{ ...disclosureButton, marginTop: 14 }} onClick={() => setVectorFieldsOpen((o) => !o)}>
          <span style={{ flex: 1, textAlign: "left", fontSize: 12, color: "#cfcfd2" }}>Vector search fields</span>
          <span style={{ fontSize: 11, color: "#7a7a7e", fontVariantNumeric: "tabular-nums" }}>
            {activeVectorFields}/{vectorEntries.length}
          </span>
          <Chevron open={vectorFieldsOpen} />
        </button>
        {vectorFieldsOpen && (
          <div style={{ marginTop: 10 }}>
            {vectorEntries.map(([fieldName, fc]) => {
              const on = fc.enabled !== false;
              return (
                <div
                  key={fieldName}
                  style={{
                    border: `1px solid ${T.border}`,
                    borderRadius: 7,
                    background: "#0e0e10",
                    padding: 10,
                    marginBottom: 8,
                  }}
                >
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontSize: 12, color: "#e8e8ea", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
                        {fieldName}
                      </div>
                      {fc.dimension != null && (
                        <div style={{ fontSize: 10, color: "#7a7a7e" }}>Dimension: {fc.dimension}</div>
                      )}
                    </div>
                    <Switch
                      size="small"
                      checked={on}
                      onCheckedChange={(c) => updateVectorField(fieldName, "enabled", c)}
                      aria-label={`Enable ${fieldName}`}
                    />
                  </div>
                  {on && (
                    <div style={{ marginTop: 10 }}>
                      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 5 }}>
                        <span style={{ fontSize: 11, color: "#9a9a9e" }}>Weight</span>
                        <span style={{ fontSize: 11, fontWeight: 600, color: "#e8e8ea", fontVariantNumeric: "tabular-nums" }}>
                          {(fc.weight ?? 0).toFixed(1)}
                        </span>
                      </div>
                      <Slider
                        value={fc.weight ?? 0}
                        min={0}
                        max={5}
                        step={0.1}
                        aria-label={`Weight for ${fieldName}`}
                        onValueChange={(v) => updateVectorField(fieldName, "weight", v)}
                      />
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginTop: 13 }}>
        <span style={{ flex: 1, textAlign: "left", fontSize: 12, color: "#cfcfd2" }}>Vector text expansion</span>
        <Switch
          size="small"
          checked={vectorExpansion}
          onCheckedChange={(c) => updateConfig({ ...config, vector_text_expansion: { enabled: c } })}
          aria-label="Enable vector text expansion"
        />
      </div>

      <Hairline />

      {/* Reciprocal Rank Fusion */}
      <div style={{ fontSize: 12.5, fontWeight: 600, color: "#e8e8ea", marginBottom: 5 }}>Reciprocal Rank Fusion</div>
      <p style={{ ...helpText, marginBottom: 12 }}>
        Combines text and vector results by rank. Higher rank constant spreads weight more evenly across results.
      </p>
      <div style={{ display: "flex", gap: 10 }}>
        <div style={{ flex: 1 }}>
          <label style={rrfFieldLabel}>Rank constant</label>
          <TextInput
            size="small"
            type="number"
            value={String(rankConstant)}
            attributes={{ Input: { min: 1, max: 1000, style: { fontFamily: MONO } } }}
            onValueChange={(v) => updateRRFConfig("rank_constant", parseInt(v, 10) || 60)}
          />
        </div>
        <div style={{ flex: 1 }}>
          <label style={rrfFieldLabel}>Window size</label>
          <TextInput
            size="small"
            inputMode="numeric"
            placeholder="auto"
            value={windowSize == null ? "" : String(windowSize)}
            attributes={{ Input: { inputMode: "numeric", style: { fontFamily: MONO } } }}
            onValueChange={(v) => {
              const raw = v.replace(/[^0-9]/g, "");
              updateRRFConfig("window_size", raw === "" ? null : parseInt(raw, 10));
            }}
          />
        </div>
      </div>
    </div>
  );
};

export default HybridSearchConfig;
export { DEFAULT_HYBRID_CONFIG };
