// Advanced (structured, server-side) filters for the Explorer filter rail.
//
// Each control maps 1:1 to a POST /search_hybrid request parameter (the exact
// names in services/deepsearch_api/.../routers_v2/models.py). Editing one of
// these re-issues the search server-side — unlike the client-side drill-down
// facets above them, which only re-slice the current result page.
//
// This module is the pure core (no React): the section/field catalog, the
// validation rules, and the "is this field set / how many in this section are
// set" helpers that drive the collapsed-section badges and the group Reset.
// AdvancedFilters.jsx renders it; the tests exercise it directly.

export const DEBOUNCE_MS = 350;

// file_size_* must be an integer + unit, e.g. "10MB" (models.py pattern).
export const SIZE_RE = /^\d+[KMGT]B$/;
// Date inputs are ISO YYYY-MM-DD.
export const DATE_RE = /^\d{4}-\d{2}-\d{2}$/;

const SIZE_FIELDS = new Set(["file_size_greater_than", "file_size_less_than"]);
const DATE_FIELDS = new Set([
  "created_after",
  "created_before",
  "modified_after",
  "modified_before",
]);

/**
 * Validate a single field's raw string value. Empty is always valid (it maps
 * to an omitted param). Returns an error message string, or null when valid.
 */
export function validateField(name, value) {
  const v = value == null ? "" : String(value).trim();
  if (v === "") return null;

  if (SIZE_FIELDS.has(name)) {
    return SIZE_RE.test(v) ? null : "Use an integer + unit, e.g. 10MB";
  }
  if (DATE_FIELDS.has(name)) {
    if (!DATE_RE.test(v)) return "Use YYYY-MM-DD";
    const d = new Date(`${v}T00:00:00Z`);
    if (Number.isNaN(d.getTime()) || d.toISOString().slice(0, 10) !== v) {
      return "Not a real date";
    }
    return null;
  }
  if (name === "limit") {
    const n = Number(v);
    if (!Number.isInteger(n) || n < 1 || n > 10000) return "1–10000";
    return null;
  }
  return null;
}

/**
 * True when `value` differs from this field's default — i.e. the user has
 * actively set it. Empty string / null always count as "not set". Used for the
 * per-section count badges and to decide what Reset must clear.
 */
export function isFieldSet(name, value, defaults = {}) {
  // An absent value means the field hasn't been provided — treat as not set
  // (otherwise an absent boolean would read as "changed from its default").
  if (value === undefined) return false;
  const def = defaults[name];
  if (typeof def === "boolean") return value !== def;
  const v = value == null ? "" : String(value).trim();
  if (v === "") return false;
  const d = def == null ? "" : String(def).trim();
  return v !== d;
}

/** How many of `fieldNames` are set to a non-default value. */
export function countSetFields(fieldNames, values = {}, defaults = {}) {
  return fieldNames.reduce(
    (n, name) => n + (isFieldSet(name, values[name], defaults) ? 1 : 0),
    0
  );
}

/**
 * Reduce a values object to only the keys covered by the advanced sections,
 * dropping any that equal their default (so callers can serialize / diff just
 * the active advanced filters). Booleans at their default are dropped too.
 */
export function activeAdvancedParams(values = {}, defaults = {}) {
  const out = {};
  for (const name of ALL_ADVANCED_FIELDS) {
    if (isFieldSet(name, values[name], defaults)) out[name] = values[name];
  }
  return out;
}

