import React, { useEffect, useState } from "react";
import { Toast } from "@kui/foundations-react";
import T from "../kui/tokens";

// ---------------------------------------------------------------------------
// Kaizen Foundations ships a presentational `<Toast>` only — there is no
// `useToast` hook, `<Toaster>`, or imperative queue like Chakra had. To keep
// the app's public toast API identical (`useBrandedToast()` → `toast(opts)`
// + `globalToastRender`) we implement a tiny module-level toast store here and
// render it through the `<BrandedToaster>` mounted once at the app root.
// ---------------------------------------------------------------------------

// Maps a toast "status"/"kind" to its Kaizen Toast semantic status. Success uses
// the NVIDIA-green success state; errors use danger red; warnings amber; info
// blue. Anything unknown falls back to "info" (matching the old behavior where
// status had to be one of success|error|warning|info).
const STATUS_TO_KAIZEN = {
  success: "success",
  error: "error",
  warning: "warning",
  info: "info",
};

const kaizenStatus = (status) => STATUS_TO_KAIZEN[status] || "info";

// --- Module-level toast store ----------------------------------------------
// A minimal pub/sub queue. `toast(opts)` pushes; the mounted <BrandedToaster>
// subscribes and renders. Lives at module scope so any caller (even outside the
// React tree, like the previous Chakra render fn) can fire a toast.
let activeToasts = [];
const listeners = new Set();
let nextSeq = 1;

const emit = () => {
  for (const fn of listeners) fn(activeToasts);
};

const subscribe = (fn) => {
  listeners.add(fn);
  fn(activeToasts);
  return () => listeners.delete(fn);
};

const dismissToast = (id) => {
  const before = activeToasts.length;
  activeToasts = activeToasts.filter((t) => t.id !== id);
  if (activeToasts.length !== before) emit();
};

const isActiveToast = (id) => activeToasts.some((t) => t.id === id);

// Push (or refresh) a toast. Returns its id. Mirrors Chakra's default options:
// 5s duration, closable, bottom-right (position is handled by <BrandedToaster>).
const pushToast = (options = {}) => {
  const id = options.id ?? `${options.status || "info"}:${options.title || ""}`;
  const duration = options.duration ?? 5000;
  const entry = {
    id,
    seq: nextSeq++,
    status: options.status,
    title: options.title,
    description: options.description,
    duration,
  };
  // Replace any existing toast with the same id (refresh in place) so the
  // dedupe path that updates an existing toast keeps working.
  activeToasts = [...activeToasts.filter((t) => t.id !== id), entry];
  emit();
  return id;
};

// --- The on-palette toast card ---------------------------------------------
// A single Kaizen Toast carrying the title + optional description, with the
// status icon/accent supplied by Kaizen. Auto-dismisses after `duration`.
const BrandedToast = ({ toast }) => {
  useEffect(() => {
    if (!toast.duration || toast.duration === Infinity) return undefined;
    const handle = setTimeout(() => dismissToast(toast.id), toast.duration);
    return () => clearTimeout(handle);
  }, [toast.id, toast.duration]);

  return (
    <Toast
      status={kaizenStatus(toast.status)}
      onClose={() => dismissToast(toast.id)}
      title={typeof toast.title === "string" ? toast.title : undefined}
      style={{ minWidth: 300, maxWidth: 420 }}
    >
      <span style={{ display: "flex", flexDirection: "column", gap: 1, minWidth: 0 }}>
        {toast.title && (
          <span style={{ fontWeight: 600, color: T.textPrimary }}>{toast.title}</span>
        )}
        {toast.description && (
          <span style={{ fontSize: 12, color: T.textSecondary }}>{toast.description}</span>
        )}
      </span>
    </Toast>
  );
};

/**
 * Root-level toast outlet. Mount ONCE near the app root (e.g. in index.js,
 * inside the dark ThemeProvider) so toasts fired via `useBrandedToast()` /
 * `toast(...)` have somewhere to render. Pinned bottom-right to match the old
 * Chakra `toastOptions` position.
 */
export const BrandedToaster = () => {
  const [toasts, setToasts] = useState(activeToasts);
  useEffect(() => subscribe(setToasts), []);
  if (!toasts.length) return null;
  return (
    <div
      style={{
        position: "fixed",
        bottom: 16,
        right: 16,
        zIndex: 2000,
        display: "flex",
        flexDirection: "column",
        gap: 10,
        pointerEvents: "none",
      }}
    >
      {[...toasts]
        .sort((a, b) => a.seq - b.seq)
        .map((t) => (
          <div key={t.id} style={{ pointerEvents: "auto" }}>
            <BrandedToast toast={t} />
          </div>
        ))}
    </div>
  );
};

/**
 * Per-call helper kept for backward compatibility. Previously returned a Chakra
 * `render` function; Kaizen's Toast has no render slot, so this is now a no-op
 * compatible value (callers that spread it into `toast({ render: ... })` simply
 * get an ignored `render`).
 */
export const brandedToast = ({ kind = "info", title, description } = {}) => () => null;

/**
 * Compatibility export. The old Chakra wiring passed this as
 * `toastOptions.defaultOptions.render`; Kaizen has no equivalent render slot,
 * so this is kept as a harmless no-op so the existing `index.js` import does
 * not break. Toast styling now lives in <BrandedToaster> above.
 */
export const globalToastRender = () => null;

/**
 * Drop-in replacement for the previous `useBrandedToast`. Returns a function
 * callable as `toast({ title, description, status, duration })` where `status`
 * is one of success|error|warning|info. Dedupes by nature: it derives a stable
 * id from `status + title`, so firing the same toast again while it's still
 * visible updates the existing one instead of stacking duplicates. Pass an
 * explicit `id` to override.
 */
export const useBrandedToast = () => {
  return (options = {}) => {
    const id = options.id ?? `${options.status || "info"}:${options.title || ""}`;
    if (isActiveToast(id)) return id; // same nature already showing — don't stack
    return pushToast({ id, ...options });
  };
};
