"use client";

import { useRef, useEffect, useCallback } from 'react';

const useDelayedOpen = ({
  disabled,
  delay,
  providerContext,
  setOpen
}) => {
  const timerRef = useRef(null);
  useEffect(() => {
    return () => {
      if (timerRef.current) {
        clearTimeout(timerRef.current);
      }
    };
  }, []);
  const onOpen = useCallback(() => {
    if (disabled) {
      return;
    }
    if (timerRef.current) {
      clearTimeout(timerRef.current);
      timerRef.current = null;
    }
    const timeSinceLastClose = Date.now() - providerContext.lastCloseTimestamp.current;
    const effectiveDelay = timeSinceLastClose < providerContext.skipDelayDuration ? 0 : delay;
    if (effectiveDelay <= 0) {
      setOpen(true);
    } else {
      timerRef.current = setTimeout(() => {
        timerRef.current = null;
        setOpen(true);
      }, effectiveDelay);
    }
  }, [disabled, delay, providerContext.lastCloseTimestamp, providerContext.skipDelayDuration, setOpen]);
  const onClose = useCallback(() => {
    if (timerRef.current) {
      clearTimeout(timerRef.current);
      timerRef.current = null;
    }
    setOpen(false);
    providerContext.lastCloseTimestamp.current = Date.now();
  }, [setOpen, providerContext.lastCloseTimestamp]);
  return {
    onOpen,
    onClose
  };
};

export { useDelayedOpen };
