// Client-side downscaling of user-uploaded query images before they are sent
// to the search service and the per-hit VLM validator. Large uploads (modern
// phone/camera photos can be 4000+ px wide, several MB) are needless load on
// the backend — the embedding models and VLMs operate at far smaller
// resolutions. Downscaling here keeps request payloads small and the service
// responsive without any visible loss for search/validation purposes.

// Resize a base64 data-URL image so its longest side is at most `maxDimension`
// pixels, preserving aspect ratio. Returns a Promise resolving to a new base64
// data URL (JPEG).
//
//  - Aspect ratio is always preserved.
//  - The image is only ever downscaled, never upscaled: if it already fits
//    within `maxDimension`, the original data URL is returned untouched.
//  - A non-positive (`<= 0`) or non-finite `maxDimension` disables resizing
//    entirely and returns the original data URL — this is how callers opt out.
//  - On any decode/encode error the original data URL is returned so an upload
//    is never silently dropped; the search simply proceeds with the full image.
export const resizeImage = (base64String, maxDimension) =>
  new Promise((resolve) => {
    // Opt-out / no-op guards.
    if (!base64String || !Number.isFinite(maxDimension) || maxDimension <= 0) {
      resolve(base64String);
      return;
    }

    const img = new window.Image();
    img.onload = () => {
      const { width: srcW, height: srcH } = img;

      // Already within bounds — return the original so we don't re-encode
      // (and potentially enlarge) a small image.
      if (srcW <= maxDimension && srcH <= maxDimension) {
        resolve(base64String);
        return;
      }

      const scale = maxDimension / Math.max(srcW, srcH);
      const width = Math.round(srcW * scale);
      const height = Math.round(srcH * scale);

      const canvas = document.createElement("canvas");
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext("2d");

      // White background so images with transparency (e.g. PNG) flatten to a
      // sensible backdrop rather than black when encoded as JPEG.
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);

      try {
        resolve(canvas.toDataURL("image/jpeg", 0.92));
      } catch (err) {
        // toDataURL can throw on tainted canvases; fall back to the original.
        console.error("Image resize failed; sending original image:", err);
        resolve(base64String);
      }
    };
    img.onerror = (err) => {
      console.error("Image decode failed; sending original image:", err);
      resolve(base64String);
    };
    img.src = base64String;
  });
