import React from "react";
import { Badge, Checkbox, Select, SegmentedControl, Slider, Switch } from "@kui/foundations-react";
import { PhysicsGlyph } from "./icons";
import T from "../kui/tokens";

const MONO = T.mono;

// File-type options for the Friendly "File type" select. These compile to the
// exact same `file_extension_include` param the Raw field edits — "usd*" is the
// common default; "All file types" clears the filter.
const FILE_TYPE_OPTIONS = [
  { value: "usd*", children: "USD (usd/usda/usdc/usdz)" },
  { value: "usd", children: "usd" },
  { value: "usda", children: "usda" },
  { value: "usdc", children: "usdc" },
  { value: "usdz", children: "usdz" },
  { value: "", children: "All file types" },
];

// A single facet checkbox row (drill-down faceting). `dimmed` greys a 0-count
// option that is not itself selected. Checkbox + trailing count Badge.
const FacetRow = ({ label, count, checked, dimmed, onToggle, mono }) => (
  <div style={{ display: "flex", alignItems: "center", gap: 11, padding: "6px 4px" }}>
    <div style={{ flex: 1, minWidth: 0 }}>
      <Checkbox
        checked={!!checked}
        onCheckedChange={onToggle}
        slotLabel={
          <span
            style={{
              fontSize: 15,
              fontFamily: mono ? MONO : undefined,
              color: checked ? T.textPrimary : dimmed ? T.textMuted : "#cfcfd2",
              fontVariantNumeric: "tabular-nums",
            }}
          >
            {label}
          </span>
        }
      />
    </div>
    <Badge color="gray" kind="outline">
      {count}
    </Badge>
  </div>
);

// A static (non-collapsible) section label. The whole rail toggles via the
// MetaBar "Show / Close filters" button, so individual sections never collapse.
const SectionHeader = ({ label, icon, upper }) => (
  <div style={{ display: "flex", alignItems: "center", gap: icon ? 8 : 0, width: "100%", padding: "16px 20px" }}>
    {icon}
    <span
      style={{
        flex: 1,
        textAlign: "left",
        fontSize: upper ? 14.5 : 15,
        fontWeight: upper ? 600 : 500,
        letterSpacing: upper ? ".05em" : undefined,
        textTransform: upper ? "uppercase" : undefined,
        color: "#cfcfd2",
        fontFamily: upper ? undefined : MONO,
      }}
    >
      {label}
    </span>
  </div>
);

// One labeled "≥/≤" numeric slider row inside a section. `value`/onChange in
// real units; 0 = "any".
const SliderRow = ({ label, valueLabel, value, max, step, onChange }) => (
  <div style={{ padding: "12px 4px 2px" }}>
    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 9 }}>
      <span style={{ fontSize: 14.5, color: "#cfcfd2", fontFamily: MONO }}>{label}</span>
      <span style={{ fontSize: 14, color: "#e8e8ea", fontVariantNumeric: "tabular-nums" }}>{valueLabel}</span>
    </div>
    <Slider
      min={0}
      max={max || 100}
      step={step || 1}
      value={value}
      onValueChange={(v) => onChange(v)}
      aria-label={label}
    />
  </div>
);

const FilterRail = ({
  mode = "raw", // "raw" | "friendly" — which editor is shown; both write the same searchParams
  onModeChange, // (mode) => void
  objectClass, // { show, options: [{value,label,count,checked,dimmed,onToggle}] }
  dimension, // { show, max, value, valueLabel, onChange } — rendered inside the SimReady section
  physics, // { show, rigid:{checked,count,onToggle}, collider:{...},
  //            minMass, minMassLabel, maxMass, onMinMass, minDensity, minDensityLabel, maxDensity, onMinDensity }
  fileType, // { show, value, onChange } — Friendly-only select mapping to file_extension_include
  preview, // { checked, onToggle } — "show only results with previews" display toggle
  footer, // ReactNode (the Advanced/raw filters group); manages its own padding
}) => {
  // The SimReady section groups physics + dimension. It is gated on physics
  // (the SimReady catalog): dimension rides along inside it, but never shows on
  // its own when the deployment has no SimReady filters.
  // Raw | Friendly toggle is hidden for now — we show Raw only. The Friendly
  // view and its controls are kept in code; flip this to re-enable the toggle.
  const SHOW_MODE_TOGGLE = false;
  const showSimReady = physics?.show;
  const friendly = SHOW_MODE_TOGGLE && mode === "friendly";
  // In Friendly mode, only controls whose catalog fields exist are shown.
  const hasAnyFriendly = objectClass?.show || showSimReady || fileType?.show;
  return (
    <div
      style={{
        flex: "none",
        width: 268,
        background: T.surfaceNav,
        borderRight: `1px solid ${T.border}`,
        overflowY: "auto",
      }}
    >
      {/* Raw | Friendly toggle — pinned so it stays reachable while the rail
          scrolls. Switching modes only changes the editing UI; the underlying
          /search_hybrid params (searchParams) are untouched, so the query is
          identical across a Raw → Friendly → Raw round-trip. Hidden for now. */}
      {SHOW_MODE_TOGGLE && (
        <div
          style={{
            position: "sticky",
            top: 0,
            zIndex: 1,
            background: T.surfaceNav,
            borderBottom: `1px solid ${T.border}`,
            padding: "12px 16px",
          }}
        >
          <SegmentedControl
            size="small"
            value={friendly ? "friendly" : "raw"}
            onValueChange={(v) => onModeChange?.(v)}
            items={[
              { value: "raw", children: "Raw" },
              { value: "friendly", children: "Friendly" },
            ]}
            style={{ width: "100%" }}
          />
        </div>
      )}

      {/* Display option: keep assets that have no thumbnail in the results, or
          hide them (default). Not a search param — a client-side display filter
          on `thumbnail_exists`. Assets with no preview can't be VLM-validated, so
          validation is skipped for them and they land under "Lower relevance". */}
      {preview && (
        <div style={{ borderBottom: `1px solid ${T.border}`, padding: "14px 20px" }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 12 }}>
            <span style={{ fontSize: 14.5, color: "#cfcfd2", fontFamily: MONO }}>Only with previews</span>
            <Switch
              size="small"
              checked={!!preview.checked}
              onCheckedChange={(c) => preview.onToggle?.(c)}
              aria-label="Only with previews"
            />
          </div>
          <div style={{ fontSize: 12, lineHeight: 1.45, color: T.textMuted, marginTop: 7 }}>
            Off includes assets that have no thumbnail.
          </div>
        </div>
      )}

      {friendly ? (
        <>
          {/* object_class */}
          {objectClass?.show && (
            <div style={{ borderBottom: `1px solid ${T.border}` }}>
              <SectionHeader label="object_class" />
              <div style={{ display: "flex", flexDirection: "column", padding: "0 16px 16px" }}>
                {objectClass.options.map((o) => (
                  <FacetRow key={o.value} {...o} />
                ))}
              </div>
            </div>
          )}

          {/* SimReady — physics toggles + mass/density/dimension sliders */}
          {showSimReady && (
            <div style={{ borderBottom: `1px solid ${T.border}` }}>
              <SectionHeader
                label="SimReady"
                upper
                icon={<PhysicsGlyph width={13} height={13} color="var(--text-color-brand)" />}
              />
              <div style={{ display: "flex", flexDirection: "column", padding: "0 16px 16px" }}>
                {physics.show && (
                  <>
                    <FacetRow
                      mono
                      label="physics_rigid_body"
                      count={physics.rigid.count}
                      checked={physics.rigid.checked}
                      onToggle={physics.rigid.onToggle}
                    />
                    <FacetRow
                      mono
                      label="has_collider"
                      count={physics.collider.count}
                      checked={physics.collider.checked}
                      onToggle={physics.collider.onToggle}
                    />
                    <SliderRow
                      label="physics_mass ≥"
                      valueLabel={physics.minMassLabel}
                      value={physics.minMass}
                      max={physics.maxMass}
                      step={5}
                      onChange={physics.onMinMass}
                    />
                    <SliderRow
                      label="physics_density ≥"
                      valueLabel={physics.minDensityLabel}
                      value={physics.minDensity}
                      max={physics.maxDensity}
                      step={10}
                      onChange={physics.onMinDensity}
                    />
                  </>
                )}
                {dimension?.show && (
                  <SliderRow
                    label="dimension ≤"
                    valueLabel={dimension.valueLabel}
                    value={dimension.value}
                    max={dimension.max}
                    step={1}
                    onChange={dimension.onChange}
                  />
                )}
              </div>
            </div>
          )}

          {/* File type — maps to the same file_extension_include param */}
          {fileType?.show && (
            <div style={{ borderBottom: `1px solid ${T.border}` }}>
              <SectionHeader label="File type" upper />
              <div style={{ padding: "0 16px 16px" }}>
                <Select
                  size="small"
                  value={fileType.value ?? ""}
                  onValueChange={(v) => fileType.onChange?.(v)}
                  items={FILE_TYPE_OPTIONS}
                />
              </div>
            </div>
          )}

          {!hasAnyFriendly && (
            <div style={{ padding: "16px 20px", fontSize: 13, lineHeight: 1.5, color: T.textMuted }}>
              No friendly filters are available for this deployment. Switch to{" "}
              <strong style={{ color: "#cfcfd2" }}>Raw</strong> to edit filters directly.
            </div>
          )}
        </>
      ) : (
        footer
      )}
    </div>
  );
};

export default FilterRail;
