import React from "react";
import TopBarPanel from "./TopBarPanel";
import HybridSearchConfig from "../HybridSearchConfig";
import { TargetGlyph } from "./icons";
import T from "../kui/tokens";

/**
 * Advanced scoring popover — opened from the top-bar crosshair button. Hosts the
 * full hybrid search configuration (similarity cutoff, text/vector weighting,
 * RRF). Replaces the old cog-icon AdvancedHybridDrawer.
 */
const AdvancedScoringPanel = ({
  isOpen,
  onClose,
  hybridConfig,
  setHybridConfig,
  embeddingConfig,
  cutoff,
  onCutoffChange,
}) => (
  <TopBarPanel
    isOpen={isOpen}
    onClose={onClose}
    width={340}
    icon={<TargetGlyph width={16} height={16} color="#cfcfd2" />}
    title="Advanced scoring"
    headerRight={
      <span style={{ fontSize: 10, fontWeight: 600, letterSpacing: ".05em", textTransform: "uppercase", color: T.textMuted }}>
        Hybrid search
      </span>
    }
  >
    <HybridSearchConfig
      value={hybridConfig}
      onChange={setHybridConfig}
      embeddingConfig={embeddingConfig}
      cutoff={cutoff}
      onCutoffChange={onCutoffChange}
    />
  </TopBarPanel>
);

export default AdvancedScoringPanel;
