import { apiUrl as defaultApiUrl, defaultEmbeddingConfig, AUTH_CONFIG, FEATURE_FLAGS, SERVER_MAPPING, DEFAULT_CUTOFF_THRESHOLD, DEFAULT_FILE_EXTENSION_INCLUDE, IMAGE_MAX_DIMENSION } from "./config";
