const clamp = (value, [min, max]) => {
  return Math.min(max, Math.max(min, value));
};
const convertValueToPercentage = (value, min, max) => {
  const maxSteps = max - min;
  if (maxSteps <= 0 || !Number.isFinite(maxSteps)) {
    return 0;
  }
  const percentPerStep = 100 / maxSteps;
  const percentage = percentPerStep * (value - min);
  return clamp(percentage, [0, 100]);
};
const generateSteps = (min, max, step) => {
  if (step <= 0 || min >= max || !Number.isFinite(max - min)) {
    return [];
  }
  const steps = [];
  for (let value = min; value <= max; value += step) {
    steps.push(value);
  }
  if (steps[steps.length - 1] !== max) {
    steps.push(max);
  }
  return steps;
};
const formatStep = (value, options = {
  maximumSignificantDigits: 2
}, locale = "en-US") => {
  return new Intl.NumberFormat(locale, options).format(value);
};

export { clamp, convertValueToPercentage, formatStep, generateSteps };
