import { useCallback, useState } from "react";

/**
 * Drop-in replacement for Chakra's `useDisclosure` so the Explorer can drop the
 * @chakra-ui dependency. Same surface: `{ isOpen, onOpen, onClose, onToggle,
 * setIsOpen }`, controllable initial state via `{ defaultIsOpen }`.
 */
export default function useDisclosure({ defaultIsOpen = false } = {}) {
  const [isOpen, setIsOpen] = useState(defaultIsOpen);
  const onOpen = useCallback(() => setIsOpen(true), []);
  const onClose = useCallback(() => setIsOpen(false), []);
  const onToggle = useCallback(() => setIsOpen((o) => !o), []);
  return { isOpen, onOpen, onClose, onToggle, setIsOpen };
}
