// Client-side helpers for the LLM query parsing ("AI search") flow. The field
// catalog — labels, the request params each filter controls, and their
// comma-join semantics — now comes from the server via GET /llm_parse/fields,
// so this module no longer mirrors the server-side field registry.

// Every searchParams key the AI flow may set. When AI search runs it resets all
// of these (so drawer settings are ignored), then applies the mapped params.
export const AI_FILTER_FIELDS = [
  "file_name",
  "exclude_file_name",
  "file_extension_include",
  "file_extension_exclude",
  "search_path",
  "exclude_search_path",
  "filter_url_regexp",
  "filter_by_properties",
  "filter_by_properties_numeric",
  "exclude_filter_by_properties",
  "filter_by_tags",
  "vision_metadata",
  "file_size_greater_than",
  "file_size_less_than",
  "created_after",
  "created_before",
  "modified_after",
  "modified_before",
  "created_by",
  "exclude_created_by",
  "modified_by",
  "exclude_modified_by",
];

/** Union two comma-joined token strings, preserving order and dropping dupes. */
export function mergeCsv(a, b) {
  const seen = new Set();
  const out = [];
  for (const part of [a, b]) {
    String(part || "")
      .split(",")
      .map((t) => t.trim())
      .filter(Boolean)
      .forEach((t) => {
        if (!seen.has(t)) {
          seen.add(t);
          out.push(t);
        }
      });
  }
  return out.join(",");
}

// --- Active-filter chips (results page) ------------------------------------
//
// Derive removable chips directly from the live searchParams, so the chips and
// the Filters drawer are two views of one state: removing a chip clears the
// param (drawer updates); editing the drawer updates the chips. Independent of
// the search-bar text and the AI-mode toggle.

// Strip leading/trailing "*" wildcards. Done with index scanning rather than a
// regex: `/^\*+|\*+$/`'s `\*+$` branch backtracks in O(n²) on adversarial input
// like "a" + "*".repeat(n) + "b" (a long "*" run not anchored to the start and
// not reaching the end), which a crafted search param could use to hang the tab.
const _stripWild = (s) => {
  const str = String(s);
  let start = 0;
  let end = str.length;
  while (start < end && str.charCodeAt(start) === 42) start++;
  while (end > start && str.charCodeAt(end - 1) === 42) end--;
  return str.slice(start, end);
};

const _PROP_KEY_LABEL = {
  "physics:rigidBodyEnabled": "rigid body",
  "physics:collisionEnabled": "collider",
  wikidata_class: "class",
};

// Turn a USD-property token (key=value / key=~*value* / key=) into a chip label.
function prettyProperty(token) {
  const eq = token.indexOf("=");
  if (eq === -1) return token;
  const key = token.slice(0, eq);
  const val = _stripWild(token.slice(eq + 1).replace(/^~/, ""));
  const niceKey = _PROP_KEY_LABEL[key] || key;
  if (!val) return niceKey; // existence filter -> just the name
  return `${niceKey}: ${val}`;
}

// Friendly labels for the numeric property keys the rail emits.
const _NUM_KEY_LABEL = {
  "physics:mass": "mass",
  "physics:density": "density",
  __polygon_count: "polygons",
};
const _OP_SYM = { ">=": "≥", "<=": "≤", ">": ">", "<": "<", "=": "=" };

// Turn a numeric-property token ("physics:mass>=10") into a chip label
// ("mass ≥ 10"); falls back to the raw token for unknown shapes.
function prettyNumeric(token) {
  // Linear despite the SAST backtracking flag (false positive): `^` pins the
  // match to one start position, the lazy `(.*?)` scans once to the leftmost
  // operator, and `(.+)$` consumes to end without backtracking — verified O(n)
  // on adversarial input up to 1.6M chars. Suppressed rather than rewritten.
  const m = String(token).match(/^(.*?)(<=|>=|<|>|=)(.+)$/); // NOSONAR

  if (!m) return token;
  const [, key, op, val] = m;
  const niceKey = _NUM_KEY_LABEL[key] || key;
  return `${niceKey} ${_OP_SYM[op] || op} ${val}`;
}

/**
 * Map the active searchParams onto a flat list of removable filter chips.
 * Each chip: { id, label, paramKey, token? } or { id, label, paramKeys: [] }.
 * Comma-joined fields produce one chip per token (token set, so removal drops
 * just that token); grouped bbox dimensions collapse into a single chip.
 */
export function searchParamsToChips(params = {}) {
  const chips = [];
  const val = (k) => String(params[k] ?? "").trim();
  const tokens = (k) =>
    val(k)
      .split(",")
      .map((t) => t.trim())
      .filter(Boolean);
  const single = (k, label) => {
    if (val(k)) chips.push({ id: k, label, paramKey: k });
  };

  tokens("file_extension_include").forEach((t) => chips.push({ id: `ext:${t}`, label: `type: ${t}`, paramKey: "file_extension_include", token: t }));
  tokens("file_extension_exclude").forEach((t) => chips.push({ id: `xext:${t}`, label: `not type: ${t}`, paramKey: "file_extension_exclude", token: t }));
  single("file_name", `name: ${_stripWild(val("file_name"))}`);
  single("exclude_file_name", `not name: ${_stripWild(val("exclude_file_name"))}`);
  single("search_path", `path: ${_stripWild(val("search_path"))}`);
  single("exclude_search_path", `not path: ${_stripWild(val("exclude_search_path"))}`);
  single("filter_url_regexp", `url: ${val("filter_url_regexp")}`);
  tokens("filter_by_properties").forEach((t) => chips.push({ id: `prop:${t}`, label: prettyProperty(t), paramKey: "filter_by_properties", token: t }));
  tokens("filter_by_properties_include_any").forEach((t) => chips.push({ id: `anyprop:${t}`, label: prettyProperty(t), paramKey: "filter_by_properties_include_any", token: t }));
  tokens("exclude_filter_by_properties").forEach((t) => chips.push({ id: `xprop:${t}`, label: `not ${prettyProperty(t)}`, paramKey: "exclude_filter_by_properties", token: t }));
  tokens("filter_by_properties_numeric").forEach((t) => chips.push({ id: `num:${t}`, label: prettyNumeric(t), paramKey: "filter_by_properties_numeric", token: t }));
  tokens("filter_by_tags").forEach((t) => chips.push({ id: `tag:${t}`, label: `tag: ${t.replace(/^=/, "").replace(/=$/, "")}`, paramKey: "filter_by_tags", token: t }));
  tokens("vision_metadata").forEach((t) => chips.push({ id: `vis:${t}`, label: `vision: ${t}`, paramKey: "vision_metadata", token: t }));
  single("file_size_greater_than", `file size ≥ ${val("file_size_greater_than")}`);
  single("file_size_less_than", `file size ≤ ${val("file_size_less_than")}`);
  single("created_after", `created ≥ ${val("created_after")}`);
  single("created_before", `created ≤ ${val("created_before")}`);
  single("modified_after", `modified ≥ ${val("modified_after")}`);
  single("modified_before", `modified ≤ ${val("modified_before")}`);
  single("created_by", `by: ${val("created_by")}`);
  single("exclude_created_by", `not by: ${val("exclude_created_by")}`);
  single("modified_by", `modified by: ${val("modified_by")}`);
  single("exclude_modified_by", `not modified by: ${val("exclude_modified_by")}`);

  // Collapse equal-on-all-axes bbox bounds (the AI "dimension" case) into one chip.
  const maxAxes = ["max_bbox_x", "max_bbox_y", "max_bbox_z"];
  const minAxes = ["min_bbox_x", "min_bbox_y", "min_bbox_z"];
  const maxV = maxAxes.map(val);
  if (maxV.every(Boolean) && maxV[0] === maxV[1] && maxV[1] === maxV[2]) {
    chips.push({ id: "dimmax", label: `dimensions ≤ ${maxV[0]}m`, paramKeys: maxAxes });
  }
  const minV = minAxes.map(val);
  if (minV.every(Boolean) && minV[0] === minV[1] && minV[1] === minV[2]) {
    chips.push({ id: "dimmin", label: `dimensions ≥ ${minV[0]}m`, paramKeys: minAxes });
  }
  return chips;
}
