import React from "react";
import { HorizontalLogo } from "@kui/foundations-react";
import { getVersion } from "../version";
import CompactSearchBar from "./CompactSearchBar";
import T from "../kui/tokens";

const HAIRLINE_R = "linear-gradient(to right, transparent, rgba(255,255,255,.20))";
const HAIRLINE_L = "linear-gradient(to left, transparent, rgba(255,255,255,.20))";

/**
 * Google-style landing state: an enlarged NVIDIA mark above a subtle stylized
 * "USD SEARCH" mono wordmark (flanked by fading hairlines) over a hero pill
 * search bar. No heading, example chips, toggles, or secondary controls —
 * focus is entirely on the search interaction. Footer shows the version chip.
 */
const LandingHero = ({
  searchQuery,
  onSearchQueryChange,
  onSubmit,
  onImageClick,
  onCancel,
  onClearImage,
  imageBase64,
  isLoading,
  canSubmitEmpty = false,
}) => {
  return (
    <div
      data-testid="landing-hero"
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        minHeight: "calc(100vh - 32px)",
        padding: "64px 16px",
        background: T.surfaceBase,
        position: "relative",
      }}
    >
      <div
        style={{
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          gap: "14px",
          marginBottom: "40px",
        }}
      >
        <HorizontalLogo style={{ height: "52px", width: "auto" }} aria-label="NVIDIA" />
        <div style={{ display: "flex", alignItems: "center", gap: "19px" }}>
          <span style={{ width: "45px", height: "1px", background: HAIRLINE_R }} />
          <span
            style={{
              whiteSpace: "nowrap",
              fontSize: "18px",
              fontWeight: 500,
              letterSpacing: ".44em",
              textTransform: "uppercase",
              color: "#82828a",
              fontFamily: T.mono,
              paddingLeft: ".44em",
            }}
          >
            USD Search
          </span>
          <span style={{ width: "45px", height: "1px", background: HAIRLINE_L }} />
        </div>
      </div>

      <CompactSearchBar
        size="hero"
        value={searchQuery}
        onChange={onSearchQueryChange}
        onSubmit={onSubmit}
        onImageClick={onImageClick}
        onCancel={onCancel}
        onClearImage={onClearImage}
        imageBase64={imageBase64}
        isLoading={isLoading}
        canSubmitEmpty={canSubmitEmpty}
        autoFocus
      />

      <div style={{ position: "absolute", bottom: "16px", right: "24px" }}>
        <span style={{ fontSize: "11px", color: T.textMuted }}>v{getVersion()}</span>
      </div>
    </div>
  );
};

export default LandingHero;
