    <text
      x="10"
      y="10"
      textAnchor="middle"
      dominantBaseline="central"
      fontSize="7"
      fontWeight="700"
      fontFamily="system-ui, sans-serif"
      fill="currentColor"
      stroke="none"
    >
      AI
    </text>
    {/* sparkles, top-right (filled) */}
