import React, { useState } from "react";
import { Badge, Button, ProgressBar, Spinner } from "@kui/foundations-react";
import TopBarPanel from "./TopBarPanel";
import { DownloadGlyph, CubeGlyph, RetryGlyph, CloseGlyph, ChevronDownGlyph } from "./icons";
import { summaryString } from "../utils/downloadQueue";
import T from "../kui/tokens";

const formatBytes = (n) => {
  if (n == null) return "";
  if (n >= 1073741824) return `${(n / 1073741824).toFixed(1)} GB`;
  if (n >= 1048576) return `${(n / 1048576).toFixed(1)} MB`;
  if (n >= 1024) return `${Math.round(n / 1024)} KB`;
  return `${n} B`;
};

// downloading / queued first, then completed / failed at the bottom.
const STATUS_ORDER = { downloading: 0, queued: 1, completed: 2, failed: 2 };

// Status label color (Badge) + queued-bar track tint, keyed by download state.
const STATUS_META = {
  downloading: { label: "Downloading", badge: "blue", barBg: "rgba(91,141,239,.18)" },
  queued: { label: "Queued", badge: "yellow", barBg: "rgba(224,165,42,.16)" },
  completed: { label: "Completed", badge: "green", barBg: "rgba(118,185,0,.16)" },
  failed: { label: "Failed", badge: "red", barBg: "rgba(242,97,107,.16)" },
};

const REASON_LABELS = {
  no_access_or_missing: "no access / missing",
  deleted: "deleted",
  download_failed: "download failed",
};

const skippedCount = (item) => {
  const s = item.summary || {};
  return (s.skipped_no_access_or_missing || 0) + (s.skipped_deleted || 0) + (s.download_failed || 0);
};

// Reliable per-reason breakdown straight from the download's own summary header.
const reasonBreakdown = (item) => {
  const s = item.summary || {};
  const out = [];
  if (s.skipped_no_access_or_missing) out.push(`${s.skipped_no_access_or_missing} no access / missing`);
  if (s.skipped_deleted) out.push(`${s.skipped_deleted} deleted`);
  if (s.download_failed) out.push(`${s.download_failed} download failed`);
  return out;
};

const baseName = (url) => (url || "").split("?")[0].split("/").filter(Boolean).pop() || url || "";

// "N files · 18.7 MB" — prefer the bundle info captured at enqueue (matches the
// asset modal's download control), then the completed summary, then live bytes.
const metaLineFor = (item, live) => {
  if (item.fileCount != null || item.totalSize != null) {
    const files = item.fileCount != null ? `${item.fileCount} files` : null;
    const size = item.totalSize != null ? formatBytes(item.totalSize) : null;
    return [files, size].filter(Boolean).join(" · ") || "asset + dependencies";
  }
  if (item.status === "completed") {
    const files = item.summary?.downloaded != null ? `${item.summary.downloaded} files` : null;
    const size = item.size != null ? formatBytes(item.size) : null;
    return [files, size].filter(Boolean).join(" · ") || "asset + dependencies";
  }
  if (item.status === "downloading" && live) {
    const size = live.bytes ? formatBytes(live.bytes) : null;
    return [size, `${live.elapsed}s`].filter(Boolean).join(" · ");
  }
  if (item.status === "failed" && item.error) return item.error;
  return "asset + dependencies";
};

const DownloadRow = ({ item, live, apiUrl, getHeaders, onRetry, onRemove, onCancel }) => {
  const m = STATUS_META[item.status] || STATUS_META.queued;
  const terminal = item.status === "completed" || item.status === "failed";
  const showBar = item.status === "downloading" || item.status === "queued";
  const nSkipped = skippedCount(item);

  // Lazily fetched per-file skipped list (download/asset?manifest_only=true ->
  // { skipped: [{url, reason}] }). Only fetched when the user expands.
  const [expanded, setExpanded] = useState(false);
  const [loading, setLoading] = useState(false);
  const [skipped, setSkipped] = useState(null); // null = not loaded

  const toggleExpand = async () => {
    const next = !expanded;
    setExpanded(next);
    if (next && skipped == null && !loading) {
      setLoading(true);
      try {
        const res = await fetch(
          `${apiUrl}/download/asset?asset_url=${encodeURIComponent(item.url)}&manifest_only=true`,
          { method: "GET", headers: getHeaders ? getHeaders() : undefined }
        );
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const data = await res.json();
        setSkipped(Array.isArray(data.skipped) ? data.skipped : []);
      } catch (e) {
        setSkipped([]); // fall back to the reason breakdown + manifest.json note
      } finally {
        setLoading(false);
      }
    }
  };

  return (
    <div style={{ borderRadius: 8, background: T.surfaceRaised, marginBottom: 6 }}>
      <div style={{ display: "flex", alignItems: "flex-start", gap: 11, padding: 10 }}>
        <div
          style={{
            flex: "none",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            width: 38,
            height: 38,
            background: T.surfaceRaised,
            border: `1px solid ${T.border}`,
            borderRadius: 6,
            color: "rgba(255,255,255,.22)",
          }}
        >
          <CubeGlyph width={18} height={18} strokeWidth={1.4} />
        </div>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <span style={{ flex: 1, minWidth: 0, fontSize: 12.5, fontWeight: 500, color: "#e8e8ea", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
              {item.name || baseName(item.url) || "asset"}
            </span>
            {item.status === "failed" && (
              <Button kind="tertiary" color="neutral" size="tiny" aria-label="Retry" onClick={() => onRetry?.(item.id)}>
                <RetryGlyph width={14} height={14} />
              </Button>
            )}
            <Button
              kind="tertiary"
              color="neutral"
              size="tiny"
              aria-label={terminal ? "Remove" : "Cancel"}
              onClick={() => (terminal ? onRemove?.(item.id) : onCancel?.(item.id))}
            >
              <CloseGlyph width={13} height={13} strokeWidth={2.4} />
            </Button>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 7, marginTop: 3 }}>
            <Badge color={m.badge} kind="solid">
              {m.label}
            </Badge>
            <span style={{ width: 3, height: 3, borderRadius: 999, background: "#48484c", flex: "none" }} />
            <span style={{ fontSize: 11, color: "#7a7a7e", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", fontVariantNumeric: "tabular-nums" }}>
              {metaLineFor(item, live)}
            </span>
            {item.status === "completed" && nSkipped > 0 && (
              <>
                <span style={{ width: 3, height: 3, borderRadius: 999, background: "#48484c", flex: "none" }} />
                <button
                  type="button"
                  onClick={toggleExpand}
                  aria-label={expanded ? "Hide skipped files" : "Show skipped files"}
                  style={{ display: "flex", alignItems: "center", gap: 3, background: "none", border: "none", padding: 0, cursor: "pointer", color: "#e0a52a", fontSize: 11, fontWeight: 600, whiteSpace: "nowrap" }}
                >
                  {nSkipped} skipped
                  <ChevronDownGlyph
                    width={11}
                    height={11}
                    style={{ transform: expanded ? "rotate(180deg)" : "none", transition: "transform .15s" }}
                  />
                </button>
              </>
            )}
          </div>
          {showBar && (
            <div style={{ marginTop: 7 }}>
              {item.status === "downloading" ? (
                <ProgressBar kind="indeterminate" size="small" aria-label="Downloading" />
              ) : (
                <div style={{ height: 4, borderRadius: 999, background: m.barBg, overflow: "hidden" }} />
              )}
            </div>
          )}
        </div>
      </div>

      {/* Expanded skip analysis */}
      {expanded && (
        <div style={{ padding: "0 10px 10px 59px" }}>
          {/* Reliable reason breakdown straight from the download's summary. */}
          {reasonBreakdown(item).map((line) => (
            <div key={line} style={{ fontSize: 11, color: "#e0a52a", marginBottom: 3 }}>
              {line}
            </div>
          ))}
          {/* Best-effort per-file names (re-analyzed from the asset's manifest). */}
          {loading ? (
            <div style={{ display: "flex", alignItems: "center", gap: 7, color: "#8a8a8e", fontSize: 11, marginTop: 3 }}>
              <Spinner size="small" /> Loading file names…
            </div>
          ) : skipped && skipped.length > 0 ? (
            <div style={{ display: "flex", flexDirection: "column", gap: 4, marginTop: 5 }}>
              {skipped.map((s, i) => (
                <div key={`${s.url}-${i}`} style={{ display: "flex", alignItems: "center", gap: 7, minWidth: 0 }}>
                  <CloseGlyph width={10} height={10} strokeWidth={2.6} color="#f2616b" style={{ flex: "none" }} />
                  <span style={{ fontSize: 11, color: "#cfcfd2", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", flex: 1, minWidth: 0 }} title={s.url}>
                    {baseName(s.url)}
                  </span>
                  <span style={{ fontSize: 10.5, color: "#7a7a7e", flex: "none", whiteSpace: "nowrap" }}>
                    {REASON_LABELS[s.reason] || s.reason}
                  </span>
                </div>
              ))}
            </div>
          ) : (
            <div style={{ fontSize: 10.5, color: "#7a7a7e", marginTop: 3 }}>
              Per-file names are listed in <span style={{ fontFamily: T.mono }}>manifest.json</span> inside the downloaded ZIP.
            </div>
          )}
        </div>
      )}
    </div>
  );
};

/**
 * Downloads tray — opened from the top-bar Downloads button. Tracks every
 * download (downloading / queued / completed / failed) with a per-row status,
 * meta line, progress bar, and Retry / Remove actions. Completed bundles that
 * skipped files show a "N skipped" affordance that expands to list each skipped
 * file + reason (fetched from the bundle manifest). Summary: "N active · M done
 * · K failed".
 */
const DownloadsTray = ({
  isOpen,
  onClose,
  downloads = [],
  downloadProgress = null,
  apiUrl = "",
  getHeaders,
  onRetry,
  onRemove,
  onCancel,
}) => {
  const sorted = [...downloads].sort((a, b) => (STATUS_ORDER[a.status] ?? 9) - (STATUS_ORDER[b.status] ?? 9));
  const summary = summaryString(downloads);

  return (
    <TopBarPanel
      isOpen={isOpen}
      onClose={onClose}
      width={380}
      icon={<DownloadGlyph width={16} height={16} color="var(--text-color-brand)" />}
      title="Downloads"
      headerRight={
        <span style={{ fontSize: 11.5, color: "#8a8a8e", fontVariantNumeric: "tabular-nums" }}>{summary}</span>
      }
    >
      <div style={{ padding: 8 }}>
        {sorted.length === 0 ? (
          <div style={{ fontSize: 12.5, color: T.textMuted, padding: "16px 10px", textAlign: "center" }}>
            No downloads yet. Use the download button on a result or in an asset's details.
          </div>
        ) : (
          sorted.map((item) => (
            <DownloadRow
              key={item.id}
              item={item}
              live={downloadProgress && downloadProgress.url === item.url ? downloadProgress : null}
              apiUrl={apiUrl}
              getHeaders={getHeaders}
              onRetry={onRetry}
              onRemove={onRemove}
              onCancel={onCancel}
            />
          ))
        )}
      </div>
    </TopBarPanel>
  );
};

export default DownloadsTray;
