import React, { useCallback, useEffect, useMemo, useRef, useState } from "react";
import NavigableAssetImage from "./NavigableAssetImage";
import T from "../kui/tokens";

// Kill the browser's native image ghost-drag so mousedown/move drives panning
// instead of dragging the <img> itself. pointer-events:none on the image lets
// the drag target the wrapper (nav arrows are separate elements and keep their
// own pointer events). Scoped to a unique wrapper class so the descendant rule
// survives the inline-style migration (sibling pattern: ImageSkeleton.jsx).
const PREVIEW_IMG_RULE = `
.zoomable-asset-preview img {
  -webkit-user-drag: none;
  user-drag: none;
  pointer-events: none;
}
`;

const MIN_ZOOM = 1;
const MAX_ZOOM = 6;
const STEP = 0.25;

const clamp = (v) => Math.min(MAX_ZOOM, Math.max(MIN_ZOOM, v));

/**
 * Wraps NavigableAssetImage with scroll-wheel zoom, drag-to-pan, and a small
 * zoom toolbar — mirroring the DependencyGraphView pan/zoom model.
 *
 * The image element is memoized so pan/zoom state changes only re-style the
 * cheap transform wrapper; the (expensive) NavigableAssetImage subtree — with
 * its image-loading hooks — is NOT re-rendered while interacting. That is what
 * keeps the zoom smooth, exactly like the graph viewer (which transforms only
 * static SVG/divs).
 */
const ZoomableAssetPreview = ({ result, getHeaders, apiUrl, borderRadius = "10px" }) => {
  const [zoom, setZoom] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const drag = useRef(null);

  // Refs mirror state so the stable (never-rebound) event callbacks read the
  // current values without re-creating handlers on every pan/zoom render.
  const panRef = useRef(pan);
  const zoomRef = useRef(zoom);
  panRef.current = pan;
  zoomRef.current = zoom;

  const resultKey = result?.id || result?.source?.base_key || result?.url;

  // Reset when the asset changes (modal reused for a different item).
  useEffect(() => {
    setZoom(1);
    setPan({ x: 0, y: 0 });
  }, [resultKey]);

  const resetView = useCallback(() => {
    setZoom(1);
    setPan({ x: 0, y: 0 });
  }, []);

  const applyZoom = useCallback((delta) => {
    setZoom((z) => {
      const nz = clamp(z + delta);
      if (nz <= MIN_ZOOM) setPan({ x: 0, y: 0 });
      return nz;
    });
  }, []);

  const onWheel = useCallback(
    (e) => {
      e.preventDefault();
      applyZoom(e.deltaY < 0 ? STEP : -STEP);
    },
    [applyZoom]
  );

  const onMouseDown = useCallback((e) => {
    drag.current = { sx: e.clientX, sy: e.clientY, px: panRef.current.x, py: panRef.current.y };
  }, []);

  const onMouseMove = useCallback((e) => {
    const d = drag.current;
    if (!d || zoomRef.current <= MIN_ZOOM) return; // panning only meaningful when zoomed
    setPan({ x: d.px + (e.clientX - d.sx), y: d.py + (e.clientY - d.sy) });
  }, []);

  const endDrag = useCallback(() => {
    drag.current = null;
  }, []);

  const zoomed = zoom > MIN_ZOOM;

  // Stable image element — survives pan/zoom re-renders untouched.
  const image = useMemo(
    () => (
      <NavigableAssetImage
        result={result}
        getHeaders={getHeaders}
        apiUrl={apiUrl}
        width="100%"
        height="100%"
        borderRadius="0"
      />
    ),
    [result, getHeaders, apiUrl]
  );

  const btnSx = {
    width: "26px",
    height: "26px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    background: "rgba(20,20,22,.82)",
    border: `1px solid ${T.borderStrong}`,
    borderRadius: "6px",
    color: "#e6e6e9",
    cursor: "pointer",
    fontSize: "15px",
    lineHeight: "1",
    userSelect: "none",
  };

  return (
    <div
      className="zoomable-asset-preview"
      onWheel={onWheel}
      onMouseDown={onMouseDown}
      onMouseMove={onMouseMove}
      onMouseUp={endDrag}
      onMouseLeave={endDrag}
      onDoubleClick={resetView}
      onDragStart={(e) => e.preventDefault()}
      style={{
        position: "relative",
        width: "100%",
        height: "100%",
        overflow: "hidden",
        borderRadius,
        cursor: zoomed ? "grab" : "default",
        touchAction: "none",
        userSelect: "none",
      }}
    >
      <style>{PREVIEW_IMG_RULE}</style>
      <div
        style={{
          position: "absolute",
          inset: 0,
          transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})`,
          transformOrigin: "center center",
          transition: drag.current ? "none" : "transform .12s ease-out",
          willChange: "transform",
        }}
      >
        {image}
      </div>

      {/* Zoom toolbar */}
      <div
        style={{
          position: "absolute",
          bottom: "10px",
          right: "10px",
          display: "flex",
          gap: "6px",
          alignItems: "center",
          zIndex: 5,
        }}
        onMouseDown={(e) => e.stopPropagation()}
        onDoubleClick={(e) => e.stopPropagation()}
        onWheel={(e) => e.stopPropagation()}
      >
        <button type="button" title="Zoom out" style={btnSx} onClick={() => applyZoom(-STEP)}>
          −
        </button>
        <button
          type="button"
          title="Reset zoom"
          style={{ ...btnSx, width: "auto", paddingLeft: "8px", paddingRight: "8px", fontSize: "11px", fontVariantNumeric: "tabular-nums" }}
          onClick={resetView}
        >
          {Math.round(zoom * 100)}%
        </button>
        <button type="button" title="Zoom in" style={btnSx} onClick={() => applyZoom(STEP)}>
          +
        </button>
      </div>
    </div>
  );
};

export default ZoomableAssetPreview;
