// ---------------------------------------------------------------------------
// Facet/value extraction for search hits.
//
// These read the per-hit metadata the redesigned UI surfaces — file type,
// object class, polygon count, dimension, and SimReady physics props — from a
// /search_hybrid SearchResult. The backend returns no per-query facet
// aggregation, so the filter rail computes drill-down counts CLIENT-SIDE over
// the current result page using these accessors (OR-within-group /
// AND-across-groups). Every accessor degrades gracefully to null/false so a
// corpus without SimReady props simply yields empty facet groups.
//
// `source.usd_properties` shape is defensive: it may arrive as an array of
// single-key objects ([{ "physics:mass": "90.3" }]), an array of
// {key,value(_*)} records, or a plain object ({ "physics:mass": 90.3 }).
// ---------------------------------------------------------------------------

// Material/texture leaf extensions for the dependency-graph classifier and for
// excluding non-geometry from facets where relevant.
export const MATERIAL_EXTS = new Set([
  "mdl", "png", "jpg", "jpeg", "exr", "dds", "hdr", "tga", "tif", "tiff",
  "mtlx", "bmp", "gif", "webp",
]);

/** Lowercase file extension (no dot) from a hit's filename, or "" if unknown. */
export function getFileType(hit) {
  const name = hit?.source?.name || hit?.source?.path || "";
  const m = /\.([a-z0-9]+)\s*$/i.exec(name);
  return m ? m[1].toLowerCase() : "";
}

/**
 * Look up a USD property value by key across the several shapes
 * `source.usd_properties` can take. Returns the raw value (string/number/bool)
 * or undefined.
 */
export function getUsdProp(hit, key) {
  const props = hit?.source?.usd_properties;
  if (props == null) return undefined;
  if (Array.isArray(props)) {
    for (const entry of props) {
      if (entry == null) continue;
      // { key: "physics:mass", value: 90.3 } / value_text / value_bool
      if (entry.key === key) {
        return entry.value ?? entry.value_text ?? entry.value_bool ?? entry.value_number;
      }
      // { "physics:mass": "90.3" }
      if (Object.prototype.hasOwnProperty.call(entry, key)) {
        return entry[key];
      }
    }
    return undefined;
  }
  if (typeof props === "object") {
    return props[key];
  }
  return undefined;
}

/** True when a USD property key is present at all (existence semantics). */
export function hasUsdProp(hit, key) {
  return getUsdProp(hit, key) !== undefined;
}

function toNumber(v) {
  if (v == null || v === "") return null;
  const n = typeof v === "number" ? v : parseFloat(String(v));
  return Number.isFinite(n) ? n : null;
}

function toBool(v) {
  if (v === true || v === false) return v;
  if (v == null) return false;
  const s = String(v).trim().toLowerCase();
  return s === "true" || s === "1" || s === "yes";
}

/**
 * Human-readable object class. Prefers the SimReady wikidata_class USD
 * property; falls back to the vision-generated object type (first token).
 */
export function getObjectClass(hit) {
  const wikidata = getUsdProp(hit, "wikidata_class");
  if (wikidata != null && String(wikidata).trim()) {
    return String(wikidata).trim().toLowerCase();
  }
  const vt = hit?.source?.vision_generated_metadata?.vision_generated_object_type;
  if (vt && String(vt).trim()) {
    return String(vt).split(",")[0].trim().toLowerCase();
  }
  return null;
}

/**
 * SimReady asset category from the `simready_metadata_type` USD property:
 * sign, prop, scene, roadmark, vehicle, traffic_light. Lowercased, or null.
 */
export function getCategory(hit) {
  const c = getUsdProp(hit, "simready_metadata_type");
  if (c != null && String(c).trim()) {
    return String(c).trim().toLowerCase();
  }
  return null;
}

/** Mesh polygon count (geometry complexity) or null. */
export function getPolygonCount(hit) {
  return toNumber(getUsdProp(hit, "__polygon_count"));
}

/** Largest bounding-box axis in meters, or null. */
export function getDimension(hit) {
  const d = hit?.source?.usd_dimensions;
  if (!d) return null;
  const axes = [d.bbox_dimension_x, d.bbox_dimension_y, d.bbox_dimension_z]
    .map(toNumber)
    .filter((n) => n != null);
  if (!axes.length) return null;
  return Math.max(...axes);
}

/** Physics mass in kilograms, or null. */
export function getMass(hit) {
  return toNumber(getUsdProp(hit, "physics:mass"));
}

/** Physics density, or null. */
export function getDensity(hit) {
  return toNumber(getUsdProp(hit, "physics:density"));
}

/** Whether the asset has rigid-body physics. */
export function getRigidBody(hit) {
  const v = getUsdProp(hit, "physics:rigidBodyEnabled");
  return v === undefined ? false : toBool(v);
}

/** Whether the asset has collision geometry. */
export function getHasCollider(hit) {
  const v = getUsdProp(hit, "physics:collisionEnabled");
  return v === undefined ? false : toBool(v);
}

/** True when any SimReady physics property is present on the hit. */
export function hasPhysics(hit) {
  return (
    hasUsdProp(hit, "physics:rigidBodyEnabled") ||
    hasUsdProp(hit, "physics:collisionEnabled") ||
    getMass(hit) != null ||
    getDensity(hit) != null
  );
}

/** Final relevance score for sorting/display (RRF first, raw score fallback). */
export function getScore(hit) {
  const s = hit?.rrf_score ?? hit?.score;
  return typeof s === "number" ? s : null;
}

/** Basename of a storage URL, stripped of path + scheme prefix. */
export function urlBasename(url) {
  if (!url) return "";
  const noQuery = String(url).split("?")[0];
  const parts = noQuery.split("/").filter(Boolean);
  return parts.length ? parts[parts.length - 1] : noQuery;
}
