import React from "react";

/**
 * ErrorBoundary
 *
 * Catches render-time exceptions in its child subtree so a single broken
 * component (e.g. a malformed result tile) cannot unmount the entire app.
 *
 * Props:
 *   - children:   subtree to protect
 *   - fallback:   optional (error, reset) => ReactNode override. When
 *                 provided, replaces the default token-styled fallback.
 *   - name:       optional string label included in the default fallback
 *
 * Behavior:
 *   - getDerivedStateFromError updates state so the next render shows the
 *     fallback.
 *   - componentDidCatch logs the error and React component stack to the
 *     console so the throw is visible in DevTools.
 *   - The default fallback (see ErrorBoundaryFallback) exposes a "Reset"
 *     button which clears the error state and re-renders the children.
 */
class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
    this.reset = this.reset.bind(this);
  }

  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }

  componentDidCatch(error, info) {
    // eslint-disable-next-line no-console
    console.error("ErrorBoundary caught:", error, info);
  }

  reset() {
    this.setState({ hasError: false, error: null });
  }

  render() {
    const { hasError, error } = this.state;
    const { children, fallback, name } = this.props;

    if (!hasError) {
      return children;
    }

    if (typeof fallback === "function") {
      return fallback(error, this.reset);
    }

    // Lazy-require the token-styled fallback so that unit tests which always
    // supply a custom `fallback` prop do not need to resolve
    // @kui/foundations-react.
    // eslint-disable-next-line global-require
    const ErrorBoundaryFallback = require("./ErrorBoundaryFallback").default;
    return (
      <ErrorBoundaryFallback error={error} reset={this.reset} name={name} />
    );
  }
}

export default ErrorBoundary;
