import { useCallback, useLayoutEffect, useRef } from "react";

/**
 * Returns a callback with a *stable identity* that always invokes the latest
 * `callback` passed in (the useEvent / useEffectEvent pattern). Unlike
 * `useCallback`, the returned function never changes reference across renders,
 * so passing it to a `React.memo`'d child won't bust the memo — even when the
 * underlying handler closes over values (or other unmemoized functions) that
 * change every render.
 *
 * Only safe for handlers invoked in response to events (clicks, etc.), never
 * during render: the latest `callback` is swapped in after commit.
 */
export default function useStableCallback(callback) {
  const ref = useRef(callback);
  useLayoutEffect(() => {
    ref.current = callback;
  });
  return useCallback((...args) => ref.current(...args), []);
}
