import React from "react";
import { Tag } from "@kui/foundations-react";
import { CloseGlyph } from "./icons";

/**
 * Inline, removable chips for the active search filters. Derived from
 * searchParams (see searchParamsToChips), so they stay in sync with the Filters
 * drawer both ways and persist regardless of the search-bar text or AI mode.
 * Removing a chip clears that filter (param / token) and re-runs the search.
 * Rendered as dismissible Kaizen Tags — clicking the chip removes the filter.
 */
const InterpretedQueryChips = ({ chips = [], onRemove }) => {
  if (!chips.length) return null;
  return (
    <div style={{ display: "flex", alignItems: "center", gap: "7px", flexWrap: "wrap" }} data-testid="filter-chips">
      {chips.map((chip) => (
        <Tag
          key={chip.id}
          color="gray"
          density="compact"
          onClick={() => onRemove?.(chip)}
          aria-label={`Remove ${chip.label}`}
        >
          {chip.label}
          <CloseGlyph width={11} height={11} strokeWidth={2.4} />
        </Tag>
      ))}
    </div>
  );
};

export default InterpretedQueryChips;
