/**
 * Two-tier client-side cache for hybrid-search responses and per-hit VLM
 * validation verdicts. Memory layer is a synchronous LRU `Map`; the IDB
 * layer (via `persistentStore`) survives reload.
 *
 * Contract:
 *  - **Search cache is NEVER authoritative**. `peekCached` returns the
 *    cached hits for a stale-while-revalidate render — the caller MUST
 *    still fire `/search_hybrid` and swap in fresh results when they
 *    arrive. The 5-min TTL bounds how stale the placeholder can be.
 *  - **Validation cache IS authoritative** for `(queryHash, hitId)` —
 *    Inference Hub at temp=0 is deterministic, so a hit may safely
 *    short-circuit the fetch. 24h TTL guards against VLM model upgrades.
 *
 * Memory-layer LRU semantics:
 *  - On get hit: refresh recency by delete + set (ts unchanged).
 *  - On set at cap: evict the oldest entry (Map insertion order).
 *  - TTL is checked on every memory get and re-applied at the IDB layer.
 *
 * Cache keys for search responses are produced by `hashRequest(body)`,
 * which recursively sorts object keys before serialising so two
 * equivalent payloads hash to the same value. Arrays preserve order.
 * Hash is FNV-1a 32-bit returned as 8-char lowercase hex.
 *
 * Validation keys are `${queryHash}:${hitId}`.
 */

import { openStore } from "./persistentStore";

export const SEARCH_TTL_MS = 5 * 60 * 1000; // 5 minutes (placeholder freshness)
export const VALIDATION_TTL_MS = 24 * 60 * 60 * 1000; // 24 hours
export const MEMORY_CAP_SEARCH = 50;
export const MEMORY_CAP_VALIDATION = 200;

// Back-compat exports — read by some older call sites + tests.
export const MAX_SEARCH_CACHE = MEMORY_CAP_SEARCH;
export const SEARCH_CACHE_TTL_MS = SEARCH_TTL_MS;

const searchMemory = new Map();
const validationMemory = new Map();

const searchIdb = openStore("searches");
const validationIdb = openStore("validations");
const hitsIdb = openStore("hits");

// ---------- LRU memory tier ----------

function memGet(map, key, ttl) {
  const entry = map.get(key);
  if (entry === undefined) return undefined;
  if (Date.now() - entry.ts > ttl) {
    map.delete(key);
    return undefined;
  }
  // Refresh recency without changing ts.
  map.delete(key);
  map.set(key, entry);
  return entry.data;
}

function memSet(map, key, data, cap) {
  if (!map.has(key) && map.size >= cap) {
    map.delete(map.keys().next().value);
  }
  map.set(key, { data, ts: Date.now() });
}

// ---------- Public synchronous peeks (hot path) ----------

/**
 * Synchronously peek the search cache. Returns the cached hits or
 * `undefined`. Used to render an instant placeholder while the real
 * /search_hybrid call is in flight.
 */
export function peekCached(key) {
  return memGet(searchMemory, key, SEARCH_TTL_MS);
}

/** Synchronous peek of the validation cache. */
export function peekValidationCached(key) {
  return memGet(validationMemory, key, VALIDATION_TTL_MS);
}

// ---------- Async two-tier API ----------

/**
 * Two-tier read: memory first, then IDB. Returns cached data or
 * `undefined`. Hydrates the memory layer on an IDB hit.
 */
export async function getCached(key) {
  const fromMemory = memGet(searchMemory, key, SEARCH_TTL_MS);
  if (fromMemory !== undefined) return fromMemory;
  const fromIdb = await searchIdb.get(key);
  if (fromIdb !== undefined) {
    memSet(searchMemory, key, fromIdb, MEMORY_CAP_SEARCH);
    return fromIdb;
  }
  return undefined;
}

/** Two-tier write: memory + IDB (fire-and-forget). */
export function setCached(key, data) {
  memSet(searchMemory, key, data, MEMORY_CAP_SEARCH);
  searchIdb.set(key, data).catch(() => {});
}

export async function getValidationCached(key) {
  const fromMemory = memGet(validationMemory, key, VALIDATION_TTL_MS);
  if (fromMemory !== undefined) return fromMemory;
  const fromIdb = await validationIdb.get(key);
  if (fromIdb !== undefined) {
    memSet(validationMemory, key, fromIdb, MEMORY_CAP_VALIDATION);
    return fromIdb;
  }
  return undefined;
}

export function setValidationCached(key, data) {
  memSet(validationMemory, key, data, MEMORY_CAP_VALIDATION);
  validationIdb.set(key, data).catch(() => {});
}

/**
 * Per-hit upsert. Stores a slim metadata bag keyed by hit ID so future
 * searches that include the same hit can pre-warm renders without
 * waiting for the network. Not authoritative; the backend response is.
 */
export function upsertHit(hit, query) {
  const id = hit?.id || hit?.source?.base_key;
  if (!id) return;
  const slim = {
    id,
    source: hit.source,
    metadata: hit.metadata,
    last_seen_query: query || null,
    last_seen_ts: Date.now(),
  };
  hitsIdb.set(id, slim).catch(() => {});
}

export async function upsertHits(hits, query) {
  if (!hits || !hits.length) return;
  for (const h of hits) upsertHit(h, query);
}

// ---------- Hydration on app mount ----------

/**
 * Pre-warm the memory tier from IDB with the hottest entries by
 * accessed_ts. Called once at app mount so the first cache lookup
 * after a reload doesn't pay the IDB round-trip latency.
 */
export async function hydrate() {
  try {
    const searchTop = await searchIdb.mostRecent(20);
    for (const { key, data } of searchTop) {
      memSet(searchMemory, key, data, MEMORY_CAP_SEARCH);
    }
    const validationTop = await validationIdb.mostRecent(200);
    for (const { key, data } of validationTop) {
      memSet(validationMemory, key, data, MEMORY_CAP_VALIDATION);
    }
  } catch (e) {
    console.warn("[searchCache] hydrate failed:", e);
  }
}

/** Idle sweep — drop expired entries from both IDB stores. */
export async function evictStale() {
  try {
    await Promise.all([
      searchIdb.evictStale(),
      validationIdb.evictStale(),
      hitsIdb.evictStale(),
    ]);
  } catch {}
}

// ---------- Misc ----------

export function clearSearchCache() {
  searchMemory.clear();
  validationMemory.clear();
  searchIdb.clear().catch(() => {});
  validationIdb.clear().catch(() => {});
  hitsIdb.clear().catch(() => {});
}

export function size() {
  return searchMemory.size;
}

// ---------- Stable hash for request bodies ----------

function stableStringify(value) {
  if (value === null || typeof value !== "object") {
    return JSON.stringify(value);
  }
  if (Array.isArray(value)) {
    return "[" + value.map((v) => stableStringify(v)).join(",") + "]";
  }
  const keys = Object.keys(value).sort();
  const parts = [];
  for (const k of keys) {
    parts.push(JSON.stringify(k) + ":" + stableStringify(value[k]));
  }
  return "{" + parts.join(",") + "}";
}

/**
 * FNV-1a 32-bit hash of a stable-stringified request body. Returns
 * 8-char lowercase hex. Collision risk at our cache sizes is
 * astronomically low.
 */
export function hashRequest(requestBody) {
  const s = stableStringify(requestBody);
  let h = 0x811c9dc5;
  for (let i = 0; i < s.length; i++) {
    h ^= s.charCodeAt(i) & 0xff;
    h = (h + ((h << 1) + (h << 4) + (h << 7) + (h << 8) + (h << 24))) >>> 0;
  }
  return ("00000000" + h.toString(16)).slice(-8);
}

// Dev debug handle on window.
if (typeof window !== "undefined" && process.env.NODE_ENV !== "production") {
  window.__searchCache = {
    peekCached,
    getCached,
    setCached,
    peekValidationCached,
    getValidationCached,
    setValidationCached,
    upsertHit,
    upsertHits,
    hydrate,
    evictStale,
    clearSearchCache,
    size,
    hashRequest,
  };
}
