import React, { useCallback, useRef, useState } from "react";
import { Spinner } from "@kui/foundations-react";
import { MATERIAL_EXTS, urlBasename } from "../utils/assetFacets";
import { BackArrowGlyph } from "./icons";
import T from "../kui/tokens";

// --- Layout constants (ported from the mock's buildGraph, app.html L3843) ----
const CANVAS_W = 1080;
const CANVAS_H = 600;
const X0 = 30;
const X1 = 430;
const X2 = 820;
const W0 = 230;
const W1 = 210;
const W2 = 200;
const ROOT_CENTER = 300;
const NODE_H = 40;
const SPAN1 = 540; // vertical span used to distribute components
const SPAN2 = 580; // vertical span used to distribute leaves
const MAX_LEAVES_PER_COMP = 3; // cap leaves per component for layout sanity

/** Lowercase extension (no dot) of a url's basename, or "". */
function extOf(url) {
  const m = /\.([a-z0-9]+)\s*$/i.exec(urlBasename(url));
  return m ? m[1].toLowerCase() : "";
}

/** True when a url points at a material/texture leaf (dashed pill). */
function isMaterialLeaf(url) {
  return MATERIAL_EXTS.has(extOf(url));
}

/** Cubic-bezier edge path with control points at the midpoint x (mock L3887). */
function edgePath(x1, y1, x2, y2) {
  const mx = (x1 + x2) / 2;
  return `M ${x1} ${y1} C ${mx} ${y1}, ${mx} ${y2}, ${x2} ${y2}`;
}

/**
 * Distribute `n` items evenly within `span`, vertically centered in the canvas.
 * Mirrors the mock: step = span/(n-1), start = (CANVAS_H - span)/2. A single
 * item is centered; zero items yields an empty list.
 */
function distribute(n, span) {
  if (n <= 0) return [];
  const start = (CANVAS_H - span) / 2;
  if (n === 1) return [CANVAS_H / 2];
  const step = span / (n - 1);
  return Array.from({ length: n }, (_, i) => start + i * step);
}

/**
 * Build the 3-column node-link graph from forward-dependency data.
 *
 * - Column 0: the root.
 * - Column 1: direct children of root (edges where node_1_url === rootUrl).
 * - Column 2: children of column-1 nodes (capped), classified by extension into
 *   material/texture (dashed) vs. component-style.
 *
 * Nodes are deduped by url; edges are taken from `data.edges`.
 */
function buildGraph(rootUrl, data) {
  const edges = Array.isArray(data?.edges) ? data.edges : [];

  // Adjacency: parent url -> ordered, deduped list of child urls.
  const childrenOf = new Map();
  for (const e of edges) {
    const p = e?.node_1_url;
    const c = e?.node_2_url;
    if (!p || !c) continue;
    if (!childrenOf.has(p)) childrenOf.set(p, []);
    const list = childrenOf.get(p);
    if (!list.includes(c)) list.push(c);
  }

  const comps = childrenOf.get(rootUrl) || [];

  // Resolve component -> its (capped, deduped) leaves; dedupe leaves globally so
  // a shared material doesn't get drawn twice.
  const seenLeaves = new Set();
  const compLeaves = comps.map((compUrl) => {
    const leaves = (childrenOf.get(compUrl) || [])
      .filter((u) => u !== compUrl && u !== rootUrl)
      .slice(0, MAX_LEAVES_PER_COMP)
      .filter((u) => {
        if (seenLeaves.has(u)) return false;
        seenLeaves.add(u);
        return true;
      });
    return { compUrl, leaves };
  });

  const nodes = [];
  const drawEdges = [];

  // --- root ---
  nodes.push({
    key: "root",
    type: "root",
    label: urlBasename(rootUrl),
    left: X0,
    top: ROOT_CENTER - NODE_H / 2,
    width: W0,
  });

  const compTops = distribute(comps.length, SPAN1);
  const totalLeaves = compLeaves.reduce((a, c) => a + c.leaves.length, 0);
  const leafTops = distribute(totalLeaves, SPAN2);

  let leafIndex = 0;
  compLeaves.forEach(({ compUrl, leaves }, i) => {
    const cTop = compTops[i];
    const ckey = "c" + i;
    nodes.push({
      key: ckey,
      type: "comp",
      label: urlBasename(compUrl),
      left: X1,
      top: cTop - NODE_H / 2,
      width: W1,
    });
    drawEdges.push({
      key: "e-" + ckey,
      d: edgePath(X0 + W0, ROOT_CENTER, X1, cTop),
      stroke: "#76b900",
      width: 1.6,
      opacity: 0.55,
    });

    leaves.forEach((leafUrl, j) => {
      const lTop = leafTops[leafIndex];
      leafIndex++;
      const lkey = "l" + i + "-" + j;
      const material = isMaterialLeaf(leafUrl);
      nodes.push({
        key: lkey,
        type: material ? "leaf" : "comp",
        label: urlBasename(leafUrl),
        left: X2,
        top: lTop - NODE_H / 2,
        width: W2,
      });
      drawEdges.push({
        key: "e-" + lkey,
        d: edgePath(X1 + W1, cTop, X2, lTop),
        stroke: "rgba(255,255,255,.16)",
        width: 1.2,
        opacity: 1,
      });
    });
  });

  return { nodes, edges: drawEdges, hasDeps: comps.length > 0 };
}

/** Per-type node visual styling (ported from app.html L4036-4041). */
function nodeStyle(type) {
  const isRoot = type === "root";
  const isComp = type === "comp";
  return {
    bg: isRoot ? "#76b900" : isComp ? "#202024" : "#141417",
    border: isRoot
      ? "none"
      : isComp
      ? "1px solid rgba(255,255,255,.16)"
      : "1px dashed rgba(255,255,255,.22)",
    color: isRoot ? "#0a0a0a" : isComp ? "#ededf0" : "#9a9a9e",
    weight: isRoot ? 600 : 500,
    dot: isRoot ? "rgba(0,0,0,.45)" : isComp ? "#76b900" : "rgba(255,255,255,.3)",
  };
}

/**
 * Full-bleed node-link dependency graph view. Self-contained presentational
 * component: the hub renders it in place of the results body while the top app
 * bar stays above it.
 */
const GRAPH_MIN_ZOOM = 0.3;
const GRAPH_MAX_ZOOM = 3;
const GRAPH_STEP = 0.25;

const clampZoom = (v) => Math.min(GRAPH_MAX_ZOOM, Math.max(GRAPH_MIN_ZOOM, v));

const DependencyGraphView = ({ rootUrl, rootName, data, loading = false, onBack }) => {
  const { nodes, edges, hasDeps } = buildGraph(rootUrl, data);
  const title = rootName || urlBasename(rootUrl);

  // Pan/zoom on the (otherwise fixed-size) canvas. The canvas is centered in the
  // viewport via the -50%/-50% translate, then offset by `pan` and scaled.
  const [zoom, setZoom] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const drag = useRef(null);

  const resetView = useCallback(() => {
    setZoom(1);
    setPan({ x: 0, y: 0 });
  }, []);

  const onWheel = useCallback((e) => {
    e.preventDefault();
    setZoom((z) => clampZoom(z + (e.deltaY < 0 ? GRAPH_STEP : -GRAPH_STEP)));
  }, []);

  const onPanStart = useCallback(
    (e) => {
      drag.current = { sx: e.clientX, sy: e.clientY, px: pan.x, py: pan.y };
    },
    [pan]
  );

  const onPanMove = useCallback((e) => {
    if (!drag.current) return;
    setPan({
      x: drag.current.px + (e.clientX - drag.current.sx),
      y: drag.current.py + (e.clientY - drag.current.sy),
    });
  }, []);

  const endPan = useCallback(() => {
    drag.current = null;
  }, []);

  const zoomBtnSx = {
    width: "28px",
    height: "28px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    background: T.surfaceRaised,
    border: `1px solid ${T.borderStrong}`,
    borderRadius: "6px",
    color: "#cfcfd2",
    cursor: "pointer",
    fontSize: "16px",
    lineHeight: "1",
    userSelect: "none",
  };

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        flex: 1,
        minHeight: 0,
        animation: "esFade .35s ease",
      }}
    >
      {/* Sub-header */}
      <div
        style={{
          flex: "none",
          display: "flex",
          alignItems: "center",
          gap: "14px",
          padding: "13px 22px",
          borderBottom: `1px solid ${T.border}`,
        }}
      >
        <button
          type="button"
          onClick={onBack}
          style={{
            display: "flex",
            alignItems: "center",
            gap: "7px",
            height: "32px",
            paddingLeft: "9px",
            paddingRight: "12px",
            background: T.surfaceRaised,
            border: `1px solid ${T.borderStrong}`,
            borderRadius: "6px",
            cursor: "pointer",
            color: "#cfcfd2",
            fontSize: "12.5px",
          }}
        >
          <BackArrowGlyph width="15" height="15" />
          Back
        </button>
        <div style={{ fontSize: "13px", color: T.textSecondary }}>
          Dependency graph ·{" "}
          <span style={{ color: "#f4f4f5" }}>{title}</span>
        </div>
        <div style={{ flex: 1 }} />
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: "16px",
            fontSize: "11.5px",
            color: "#7a7a7e",
          }}
        >
          <div style={{ display: "flex", alignItems: "center", gap: "6px" }}>
            <div style={{ width: "9px", height: "9px", borderRadius: "3px", background: "#76b900" }} />
            Root
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: "6px" }}>
            <div
              style={{
                width: "9px",
                height: "9px",
                borderRadius: "3px",
                background: "#2b2b30",
                border: "1px solid rgba(255,255,255,.18)",
              }}
            />
            Component
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: "6px" }}>
            <div
              style={{
                width: "9px",
                height: "9px",
                borderRadius: "3px",
                background: "transparent",
                border: "1px dashed rgba(255,255,255,.3)",
              }}
            />
            Material / Texture
          </div>
        </div>
      </div>

      {/* Canvas — pan/zoom viewport */}
      <div
        onWheel={hasDeps ? onWheel : undefined}
        onMouseDown={hasDeps ? onPanStart : undefined}
        onMouseMove={hasDeps ? onPanMove : undefined}
        onMouseUp={endPan}
        onMouseLeave={endPan}
        onDoubleClick={hasDeps ? resetView : undefined}
        style={{
          flex: 1,
          position: "relative",
          overflow: "hidden",
          cursor: hasDeps ? (drag.current ? "grabbing" : "grab") : "default",
          touchAction: "none",
          background:
            "radial-gradient(circle at 50% 40%, rgba(118,185,0,.05), transparent 60%)",
        }}
      >
        {loading ? (
          <div
            style={{
              position: "absolute",
              inset: 0,
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              justifyContent: "center",
              gap: "14px",
              color: T.textMuted,
            }}
          >
            <Spinner size="medium" aria-label="Loading dependencies" />
            <div style={{ fontSize: "14px" }}>Loading dependencies…</div>
          </div>
        ) : hasDeps ? (
          <div
            style={{
              position: "absolute",
              left: "50%",
              top: "50%",
              width: `${CANVAS_W}px`,
              height: `${CANVAS_H}px`,
              transform: `translate(-50%, -50%) translate(${pan.x}px, ${pan.y}px) scale(${zoom})`,
              transformOrigin: "center center",
              transition: drag.current ? "none" : "transform .12s ease-out",
              willChange: "transform",
            }}
          >
            <svg
              width={CANVAS_W}
              height={CANVAS_H}
              style={{ position: "absolute", inset: 0, overflow: "visible" }}
            >
              {edges.map((e) => (
                <path
                  key={e.key}
                  d={e.d}
                  fill="none"
                  stroke={e.stroke}
                  strokeWidth={e.width}
                  strokeOpacity={e.opacity}
                />
              ))}
            </svg>
            {nodes.map((n, i) => {
              const s = nodeStyle(n.type);
              return (
                <div
                  key={n.key}
                  style={{
                    position: "absolute",
                    left: `${n.left}px`,
                    top: `${n.top}px`,
                    width: `${n.width}px`,
                    height: `${NODE_H}px`,
                    display: "flex",
                    alignItems: "center",
                    gap: "9px",
                    paddingLeft: "13px",
                    paddingRight: "13px",
                    boxSizing: "border-box",
                    borderRadius: "8px",
                    background: s.bg,
                    border: s.border,
                    animation: "esRise .4s ease both",
                    animationDelay: `${i * 35}ms`,
                  }}
                >
                  <div
                    style={{
                      width: "7px",
                      height: "7px",
                      borderRadius: "2px",
                      flex: "none",
                      background: s.dot,
                    }}
                  />
                  <div
                    style={{
                      flex: 1,
                      fontSize: "12px",
                      fontWeight: s.weight,
                      color: s.color,
                      whiteSpace: "nowrap",
                      overflow: "hidden",
                      textOverflow: "ellipsis",
                    }}
                  >
                    {n.label}
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div
            style={{
              position: "absolute",
              inset: 0,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              color: T.textMuted,
              fontSize: "14px",
            }}
          >
            No dependencies
          </div>
        )}

        {/* Zoom toolbar */}
        {hasDeps && !loading && (
          <div
            style={{
              position: "absolute",
              bottom: "16px",
              right: "16px",
              display: "flex",
              gap: "7px",
              alignItems: "center",
              zIndex: 5,
            }}
            onMouseDown={(e) => e.stopPropagation()}
            onDoubleClick={(e) => e.stopPropagation()}
          >
            <button type="button" title="Zoom out" style={zoomBtnSx} onClick={() => setZoom((z) => clampZoom(z - GRAPH_STEP))}>
              −
            </button>
            <button
              type="button"
              title="Reset view"
              style={{ ...zoomBtnSx, width: "auto", paddingLeft: "10px", paddingRight: "10px", fontSize: "11.5px", fontVariantNumeric: "tabular-nums" }}
              onClick={resetView}
            >
              {Math.round(zoom * 100)}%
            </button>
            <button type="button" title="Zoom in" style={zoomBtnSx} onClick={() => setZoom((z) => clampZoom(z + GRAPH_STEP))}>
              +
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default DependencyGraphView;
