import React from "react";
import { createPortal } from "react-dom";
import T from "../kui/tokens";

/**
 * A floating panel anchored under the top bar's right cluster (Downloads tray /
 * Advanced scoring) — a Kaizen-token-styled popover surface. Renders a
 * full-viewport click-catcher to dismiss, plus the panel chrome (header with
 * icon + title + optional right adornment). Body is scrollable. Rendered
 * through a portal so the fixed positioning is relative to the viewport
 * regardless of any animated transform ancestors.
 */
const TopBarPanel = ({ isOpen, onClose, width = 380, icon, title, headerRight, children }) => {
  if (!isOpen) return null;
  return createPortal(
    <>
      <div style={{ position: "fixed", inset: 0, zIndex: 1400 }} onClick={onClose} />
      <div
        style={{
          position: "fixed",
          top: "62px",
          right: "20px",
          zIndex: 1401,
          width: `${width}px`,
          maxWidth: "calc(100vw - 40px)",
          maxHeight: "80vh",
          display: "flex",
          flexDirection: "column",
          background: T.surfaceOverlay,
          border: `1px solid ${T.borderStrong}`,
          borderRadius: T.radiusLg,
          boxShadow: "0 20px 60px rgba(0,0,0,.55)",
          overflow: "hidden",
        }}
      >
        <div
          style={{
            flex: "none",
            display: "flex",
            alignItems: "center",
            gap: "10px",
            padding: "14px 16px",
            borderBottom: `1px solid ${T.border}`,
          }}
        >
          {icon}
          <span style={{ flex: 1, fontSize: "13.5px", fontWeight: 600, color: T.textPrimary }}>
            {title}
          </span>
          {headerRight}
        </div>
        <div style={{ flex: 1, overflowY: "auto" }}>{children}</div>
      </div>
    </>,
    document.body
  );
};

export default TopBarPanel;
