/**
 * Derive landing-vs-results state. Landing iff: no completed query,
 * no active image, no results, no in-flight request. Pulled to its own
 * module so tests can import it without dragging in Chakra (whose CJS
 * exports do not resolve under jest's default moduleFileExtensions).
 */
export const computeIsLanding = ({ lastSearchQuery, imageBase64, results, isLoading }) =>
  !lastSearchQuery && !imageBase64 && (!results || results.length === 0) && !isLoading;
