import React from "react";
import { Button } from "@kui/foundations-react";
import T from "../kui/tokens";

/**
 * Default token-styled fallback rendered by ErrorBoundary when no custom
 * `fallback` prop is supplied. Split into its own module so the
 * ErrorBoundary class itself can be unit-tested without importing the
 * full Kaizen Foundations surface.
 */
const ErrorBoundaryFallback = ({ error, reset, name }) => {
  const message = error && error.message ? error.message : String(error);
  return (
    <div
      style={{
        background: T.dangerDim,
        color: T.textPrimary,
        border: `1px solid ${T.danger}`,
        borderRadius: T.radiusMd,
        padding: 16,
        margin: 8,
      }}
    >
      <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 8 }}>
        Something went wrong{name ? ` in ${name}` : ""}
      </div>
      <div style={{ marginBottom: 12, fontFamily: T.mono, fontSize: 13 }}>
        Error: {message}
      </div>
      <Button kind="primary" color="danger" size="small" onClick={reset}>
        Reset
      </Button>
    </div>
  );
};

export default ErrorBoundaryFallback;
