/**
 * Verified, per-source authentication status — a plain "signed in / not signed
 * in" model.
 *
 * The legacy `isAuthSatisfied` only checked whether a credential *string*
 * existed in localStorage, so a revoked/expired token still read "signed in".
 * This module fixes that by actually sending the stored credential and asking
 * the backend whether it accepts it.
 *
 * It deliberately does NOT try to detect whether a source is "open" (public,
 * no-login). An earlier version probed anonymously and reported "Open · no
 * sign-in" when `/info/backend/storage` answered 200 without credentials — but
 * that endpoint answers 200 for Nucleus servers too, which *do* require sign-in
 * for real data, so the badge was misleading. We now report only two states:
 * you have a working credential (Signed in) or you don't (Not signed in).
 *
 * It is a plain observable, not a React context: the source/auth UI is spread
 * across two independently-mounted trees (`AuthButton` on the landing screen,
 * `HeaderIcons` on results) that already coordinate purely through `window`
 * events + localStorage. So this module keeps the cache + probe de-dup in one
 * place and notifies via a new `auth-status-changed` CustomEvent. A small
 * `useAuthStatus(serverKey)` hook wraps subscribe/verify for React callers.
 */

import { useEffect, useState } from "react";
import { apiUrl as defaultApiUrl } from "../config";
import { buildAuthHeaders, hasStoredCredential } from "./authStorage";

export const AUTH_STATUS = Object.freeze({
  SIGNED_IN: "signed_in", // credential sent AND backend accepted it (200)
  NOT_SIGNED_IN: "not_signed_in", // no credential stored, or it was rejected (401/403)
  CHECKING: "checking", // probe in flight
  UNKNOWN: "unknown", // never probed, or network/CORS/5xx error — treat as not-signed-in visually
});

export const AUTH_STATUS_CHANGED_EVENT = "auth-status-changed";

// How long a resolved status is trusted before `verifySource` will re-probe.
const TTL_MS = 60_000;

// serverKey -> { status, ts }
const cache = new Map();
// serverKey -> Promise<status> (collapses concurrent probes for the same source)
const inflight = new Map();
// serverKey -> last resolved *real* status (used for keep-last-good on errors)
const lastGood = new Map();

const norm = (serverKey) => serverKey || "";

const REAL_STATES = [AUTH_STATUS.SIGNED_IN, AUTH_STATUS.NOT_SIGNED_IN];

function emit(serverKey, status) {
  if (typeof window === "undefined") return;
  window.dispatchEvent(
    new CustomEvent(AUTH_STATUS_CHANGED_EVENT, { detail: { serverKey, status } })
  );
}

// Write the cache and fire the change event only on an actual transition.
function setStatus(serverKey, status) {
  const key = norm(serverKey);
  const prev = cache.get(key);
  cache.set(key, { status, ts: Date.now() });
  if (REAL_STATES.includes(status)) lastGood.set(key, status);
  if (!prev || prev.status !== status) emit(key, status);
}

function backendStorageUrl() {
  return defaultApiUrl ? `${defaultApiUrl}/info/backend/storage` : `/info/backend/storage`;
}

function baseHeaders(serverKey) {
  const headers = { "Content-Type": "application/json" };
  if (serverKey) headers["x-usdsearch-storage-backend"] = serverKey;
  return headers;
}

/**
 * Verify one source's credential against `GET /info/backend/storage`.
 *
 * With no stored credential the answer is simply NOT_SIGNED_IN — we don't probe
 * anonymously to guess whether the source is "open", because that reads 200 for
 * sign-in-required Nucleus servers too and produced a misleading badge. When a
 * credential *is* present we send it and let the backend judge it: 200 means it
 * was accepted (SIGNED_IN), 401/403 means it was rejected (NOT_SIGNED_IN).
 */
async function probe(serverKey, signal) {
  const authHeaders = buildAuthHeaders(serverKey, null);
  // The authoritative "did we actually store a credential" — buildAuthHeaders
  // returns {} when the selected method's slot is empty (incl. S3's empty
  // username).
  const sentCreds = Object.keys(authHeaders).length > 0;
  if (!sentCreds) return AUTH_STATUS.NOT_SIGNED_IN;

  const res = await fetch(backendStorageUrl(), {
    method: "GET",
    headers: { ...baseHeaders(serverKey), ...authHeaders },
    signal,
  });

  if (res.ok) return AUTH_STATUS.SIGNED_IN;
  if (res.status === 401 || res.status === 403) return AUTH_STATUS.NOT_SIGNED_IN;
  // 5xx / 404 / other: don't flip a working badge to red — report UNKNOWN and
  // let the caller keep the last-known-good status.
  return AUTH_STATUS.UNKNOWN;
}

/**
 * Probe (or return a fresh cached result for) a source. Resolves to one of the
 * four real states (or the kept last-good on a transient error). Concurrent
 * calls for the same source share one network round-trip.
 */
export function verifySource(serverKey, { force = false } = {}) {
  const key = norm(serverKey);

  if (inflight.has(key)) return inflight.get(key);

  const cached = cache.get(key);
  if (
    !force &&
    cached &&
    cached.status !== AUTH_STATUS.CHECKING &&
    Date.now() - cached.ts < TTL_MS
  ) {
    return Promise.resolve(cached.status);
  }

  setStatus(key, AUTH_STATUS.CHECKING);

  const controller = typeof AbortController !== "undefined" ? new AbortController() : null;
  const run = (async () => {
    let result;
    try {
      result = await probe(key, controller ? controller.signal : undefined);
    } catch (e) {
      result = AUTH_STATUS.UNKNOWN;
    }
    if (result === AUTH_STATUS.UNKNOWN && lastGood.has(key)) {
      result = lastGood.get(key); // keep-last-good over a transient failure
    }
    setStatus(key, result);
    return result;
  })();

  const tracked = run.finally(() => {
    if (inflight.get(key) === tracked) inflight.delete(key);
  });
  inflight.set(key, tracked);
  return tracked;
}

/**
 * Synchronous best-guess for render. Returns the cached status if present;
 * otherwise CHECKING when a credential is stored (a probe is warranted) or
 * UNKNOWN when none is. Never returns SIGNED_IN before a probe confirms it.
 */
export function getAuthStatus(serverKey) {
  const key = norm(serverKey);
  const cached = cache.get(key);
  if (cached) return cached.status;
  return hasStoredCredential(key, null) ? AUTH_STATUS.CHECKING : AUTH_STATUS.UNKNOWN;
}

/** Raw cache read (no synchronous fallback). `undefined` = never probed. */
export function getCachedStatus(serverKey) {
  return cache.get(norm(serverKey))?.status;
}

/** Drop one source's cached status and re-verify it if it had been probed. */
export function invalidate(serverKey) {
  const key = norm(serverKey);
  const had = cache.has(key);
  cache.delete(key);
  lastGood.delete(key);
  if (had) {
    verifySource(key, { force: true });
  } else {
    emit(key, getAuthStatus(key));
  }
}

/** Drop every cached status and re-verify each source that had been probed. */
export function invalidateAll() {
  const keys = Array.from(cache.keys());
  cache.clear();
  lastGood.clear();
  keys.forEach((key) => verifySource(key, { force: true }));
}

/**
 * Force a source to NOT_SIGNED_IN immediately — used when a live `/search_hybrid`
 * request 401s, so the badge tells the truth without waiting for a re-probe.
 */
export function markNotSignedIn(serverKey) {
  setStatus(serverKey, AUTH_STATUS.NOT_SIGNED_IN);
}

/** Subscribe to status transitions. Returns an unsubscribe fn. */
export function subscribe(listener) {
  if (typeof window === "undefined") return () => {};
  const handler = (e) => listener(e.detail || {});
  window.addEventListener(AUTH_STATUS_CHANGED_EVENT, handler);
  return () => window.removeEventListener(AUTH_STATUS_CHANGED_EVENT, handler);
}

// How long to wait after the last `auth-updated` before re-verifying. The
// credential inputs fire `auth-updated` on every keystroke; re-probing per
// keystroke both hammered the backend and, worse, could flip the status to
// SIGNED_IN mid-type and auto-close the sign-in popover. Debouncing means we
// only re-check once the user has settled.
export const AUTH_REVERIFY_DEBOUNCE_MS = 700;

let reverifyTimer = null;

// Credentials changed → the stored-cred → verified mapping may have flipped, so
// re-verify — but debounced, so typing a username/password/API key doesn't
// re-probe (and auto-close the popover) on every keystroke. Server switched →
// re-verify the newly-selected source immediately (a deliberate, discrete
// action, not mid-typing). The module owns these so individual components don't
// each re-wire invalidation.
if (typeof window !== "undefined") {
  window.addEventListener("auth-updated", () => {
    if (reverifyTimer) clearTimeout(reverifyTimer);
    reverifyTimer = setTimeout(() => {
      reverifyTimer = null;
      invalidateAll();
    }, AUTH_REVERIFY_DEBOUNCE_MS);
  });
  window.addEventListener("server-changed", (e) => {
    const key = e?.detail?.server;
    if (key !== undefined) invalidate(key);
  });
}

/** Test-only: clear all in-memory state (cache, in-flight probes, last-good). */
export function __resetForTests() {
  cache.clear();
  inflight.clear();
  lastGood.clear();
  if (reverifyTimer) {
    clearTimeout(reverifyTimer);
    reverifyTimer = null;
  }
}

/** React hook: verified status for a source, kept live via the event bus. */
export function useAuthStatus(serverKey) {
  const [status, setStatus_] = useState(() => getAuthStatus(serverKey));
  useEffect(() => {
    const key = norm(serverKey);
    setStatus_(getAuthStatus(serverKey));
    verifySource(serverKey);
    const unsub = subscribe(({ serverKey: changed }) => {
      if (changed === key) setStatus_(getAuthStatus(serverKey));
    });
    return unsub;
  }, [serverKey]);
  return status;
}
