/**
 * Merge VLM validation verdicts onto sorted hits WITHOUT churning object identity.
 *
 * The results grid re-partitions on every validation flush. If each recompute
 * minted a fresh object for every hit (`{...hit, _validationState}`), `React.memo`
 * on the cards would be useless — every card would re-render and its thumbnail
 * would churn. This keeps identity stable: a hit whose verdict (status + result
 * reference) is unchanged returns the SAME object across calls, so only the hits
 * that actually changed this flush get a new object (and re-render). Hits with no
 * verdict return the raw hit, which is already stable within a result set.
 *
 * @param {Array} sorted - hits in display order (the sorted `results`; the hit
 *   objects are the same references as in `results`, stable within a result set).
 * @param {Object|null} validationMap - `{ [id]: { status, result } }`.
 * @param {Map} cache - identity cache, `id -> { status, result, obj }`, mutated in
 *   place. The CALLER must reset this Map when the underlying `results` array
 *   identity changes (new search/page) — otherwise a cached `obj` built from a
 *   now-replaced hit could be reused. `entry.result` is compared by reference,
 *   which is safe because `useAsyncValidation` writes a verdict's `result` object
 *   once and never mutates it.
 * @returns {Array} merged hits in the same order as `sorted`.
 */
export function mergeWithIdentity(sorted, validationMap, cache) {
  return sorted.map((hit) => {
    const id = hit.id || hit.source?.base_key;
    const entry = id && validationMap ? validationMap[id] : null;

    if (!entry) {
      // No verdict yet → the raw hit is already a stable reference. Drop any
      // stale cache entry so a later verdict rebuilds cleanly.
      if (id) cache.delete(id);
      return hit;
    }

    const cached = cache.get(id);
    if (cached && cached.status === entry.status && cached.result === entry.result) {
      return cached.obj; // unchanged verdict → same reference → React.memo skips it
    }

    const obj = { ...hit, _validationState: entry.status };
    if (entry.result) obj.query_relevance = entry.result;
    cache.set(id, { status: entry.status, result: entry.result, obj });
    return obj;
  });
}
