import React, { useState } from "react";
import { Badge } from "@kui/foundations-react";
import NavigableAssetImage from "./NavigableAssetImage";
import DownloadControl from "./DownloadControl";
import { CheckGlyph, WarningGlyph, SpinnerGlyph, InfoGlyph } from "./icons";
import { getObjectClass } from "../utils/assetFacets";
import { formatFileSize, formatDate, middleTruncate } from "../utils/formatUtils";
import T from "../kui/tokens";

/**
 * One dense index row — the list-view counterpart to CompactResultCard.
 * Columns align with the header rendered by HybridSearchResults:
 *   preview 120 · Filename flex · Size 78 · Modified 104 · VLM 30 · actions 64.
 * Click anywhere on the row → onItemClick(result).
 */

// Inline placeholder cube — shown when the thumbnail has no image.
const CubePlaceholder = () => (
  <div
    style={{
      position: "absolute",
      inset: 0,
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      color: "rgba(255,255,255,.13)",
    }}
  >
    <svg
      width="20"
      height="20"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="1.4"
      strokeLinejoin="round"
      aria-hidden="true"
    >
      <path d="M12 2 3 7v10l9 5 9-5V7z" />
      <path d="M3 7l9 5 9-5M12 12v10" />
    </svg>
  </div>
);

// Small per-state VLM cell badge — a state-colored Kaizen Badge carrying the glyph.
const VlmBadge = ({ validationState, halted = false }) => {
  const inProgress = validationState === "pending" || validationState === "validating";
  const rejected = validationState === "rejected";
  // No thumbnail → couldn't be validated. Neutral badge, never a green check.
  const skipped = validationState === "skipped";

  let color;
  let Glyph;
  let title;
  let spin = false;

  if (inProgress) {
    color = "blue";
    Glyph = SpinnerGlyph;
    // Freeze the spinner once validation has halted (VLM unavailable).
    spin = !halted;
    title = halted ? "Validation paused — VLM unavailable" : "VLM validating…";
  } else if (rejected) {
    color = "yellow";
    Glyph = WarningGlyph;
    title = "VLM rejected — likely false positive";
  } else if (skipped) {
    color = "gray";
    Glyph = InfoGlyph;
    title = "Validation skipped — no preview image to check";
  } else {
    color = "green";
    Glyph = CheckGlyph;
    title = "VLM validated";
  }

  return (
    <span title={title} style={{ display: "inline-flex" }}>
      <Badge color={color} kind="solid">
        <Glyph
          width={10}
          height={10}
          style={spin ? { animation: "esSpin .8s linear infinite" } : undefined}
        />
      </Badge>
    </span>
  );
};

const CompactResultRow = ({
  result,
  onItemClick,
  getHeaders,
  apiUrl,
  downloadAsset,
  cancelDownload,
  downloadingUrl,
  queuedUrls,
  copyToClipboard,
  onFindSimilar,
  vlmOn = true,
  vlmUnavailable = false,
}) => {
  const [hovered, setHovered] = useState(false);

  const baseKey = result.source?.base_key || result.source?.url || result.id;
  const filename = result.source?.name || baseKey?.split("/").pop() || "Unknown";
  const size = result.source?.size_bytes ?? result.source?.size;
  const modified =
    result.source?.modified ?? result.source?.modified_timestamp ?? result.source?.last_modified;

  const objectClass = getObjectClass(result);

  // Show the VLM cell only when validation ran for this hit.
  const validationState = result._validationState;
  const showVlmBadge = vlmOn && !!validationState;

  const tooltipParts = [filename];
  if (size != null) tooltipParts.push(formatFileSize(size));
  if (modified) tooltipParts.push(formatDate(modified));
  const tooltip = tooltipParts.join(" · ");

  return (
    <div style={{ position: "relative", width: "100%" }} role="group">
      <button
        type="button"
        onClick={() => onItemClick?.(result)}
        onMouseEnter={() => setHovered(true)}
        onMouseLeave={() => setHovered(false)}
        title={tooltip}
        aria-label={filename}
        style={{
          display: "flex",
          alignItems: "center",
          gap: "14px",
          width: "100%",
          paddingTop: "7px",
          paddingBottom: "7px",
          paddingLeft: "17px",
          paddingRight: "14px",
          background: hovered ? "rgba(118,185,0,.06)" : "transparent",
          border: "none",
          borderBottom: "1px solid rgba(255,255,255,.05)",
          cursor: "pointer",
          textAlign: "left",
          position: "relative",
          transition: "background .12s",
        }}
      >
        {/* 3px green left bar — revealed on hover/focus */}
        <div
          style={{
            position: "absolute",
            left: 0,
            top: 0,
            bottom: 0,
            width: "3px",
            background: T.brand,
            opacity: hovered ? 1 : 0,
            transition: "opacity .12s",
          }}
        />

        {/* Preview — 120×84 thumbnail tile */}
        <div
          style={{
            position: "relative",
            width: "120px",
            height: "84px",
            flex: "none",
            background: T.surfaceRaised,
            border: `1px solid ${T.border}`,
            borderRadius: "5px",
            overflow: "hidden",
          }}
        >
          <CubePlaceholder />
          <NavigableAssetImage
            result={result}
            getHeaders={getHeaders}
            apiUrl={apiUrl}
            width="100%"
            height="100%"
            borderRadius="0"
            navigable={false}
          />
        </div>

        {/* Asset — name + sub-line */}
        <div style={{ flex: 1, minWidth: 0 }}>
          <span
            style={{
              display: "block",
              fontSize: "13px",
              fontWeight: 500,
              color: hovered ? "#fff" : "#e6e6e9",
              whiteSpace: "nowrap",
              overflow: "hidden",
              textOverflow: "ellipsis",
              transition: "color .12s",
            }}
          >
            {middleTruncate(filename, 56)}
          </span>
          {objectClass && (
            <span
              style={{
                display: "block",
                fontSize: "11px",
                color: T.textMuted,
                marginTop: "2px",
                whiteSpace: "nowrap",
                overflow: "hidden",
                textOverflow: "ellipsis",
              }}
            >
              {objectClass}
            </span>
          )}
        </div>

        {/* Size */}
        <span
          style={{
            width: "78px",
            flex: "none",
            fontSize: "12px",
            color: "#9a9a9e",
            fontVariantNumeric: "tabular-nums",
          }}
        >
          {size != null ? formatFileSize(size) : "—"}
        </span>

        {/* Modified */}
        <span style={{ width: "104px", flex: "none", fontSize: "12px", color: "#9a9a9e" }}>
          {modified ? formatDate(modified) : "—"}
        </span>

        {/* VLM */}
        <span style={{ width: "30px", flex: "none", display: "flex", justifyContent: "center" }}>
          {showVlmBadge && <VlmBadge validationState={validationState} halted={vlmUnavailable} />}
        </span>

        {/* Reserved actions column — the download control (absolute overlay
            below) draws here, keeping the Match value clear of its wider
            active state. */}
        <span style={{ width: "64px", flex: "none" }} />
      </button>

      {/* Download control — sibling overlay (avoids nesting buttons), pinned to
          the right edge of the row. */}
      {baseKey && (downloadAsset || cancelDownload) && (
        <div style={{ position: "absolute", right: "6px", top: "50%", transform: "translateY(-50%)", zIndex: 2 }}>
          <DownloadControl
            url={baseKey}
            name={filename}
            downloadingUrl={downloadingUrl}
            queuedUrls={queuedUrls}
            onDownload={downloadAsset}
            onCancel={cancelDownload}
            size="sm"
          />
        </div>
      )}
    </div>
  );
};

// Memoized — see the note on CompactResultCard's default export.
export default React.memo(CompactResultRow);
