// ---------------------------------------------------------------------------
// Kaizen design-token aliases for inline styles.
//
// The Explorer is a Create-React-App project (no Tailwind), so we consume the
// Kaizen Foundations tokens as CSS variables — supplied by
// `@kui/foundations-react/base.css`, imported once at the app root. These
// aliases keep the per-component inline styles readable and consistent and map
// the app's old Chakra semantic-token roles (accent / appSurface / textMuted …)
// onto the equivalent Kaizen variable, so the migration is a mechanical swap.
//
// Everything must render inside the dark `<ThemeProvider theme="dark" global>`
// for these to resolve to the dark palette + NVIDIA green (#76B900) brand.
// ---------------------------------------------------------------------------

export const T = {
  // Surfaces (sunken → base → raised → overlay). The near-black dark ladder.
  surfaceBase: 'var(--background-color-surface-base)', //        page canvas
  surfaceSunken: 'var(--background-color-surface-sunken)', //    recessed wells (inputs)
  surfaceRaised: 'var(--background-color-surface-raised)', //    cards, tiles, chips
  surfaceOverlay: 'var(--background-color-surface-overlay)', //  popovers, modals, menus
  surfaceNav: 'var(--background-color-surface-navigation)', //   top bar / filter-rail chrome
  blanket: 'var(--background-color-surface-blanket)', //         modal scrim

  // Foreground
  textPrimary: 'var(--text-color-primary)',
  textSecondary: 'var(--text-color-secondary)',
  textMuted: 'var(--text-color-subtle)',
  textDisabled: 'var(--text-color-disabled)',
  textPlaceholder: 'var(--text-color-placeholder)',
  textInverse: 'var(--text-color-inverse)', //                   text on the green fill

  // Brand (NVIDIA green #76B900) — the one accent.
  brand: 'var(--background-color-interaction-primary-base)',
  brandHover: 'var(--background-color-interaction-primary-hover)',
  brandText: 'var(--text-color-brand)', //                       brand-green ink
  accentText: 'var(--text-color-accent-green)', //               bright green numerals
  brandDim: 'var(--background-color-accent-green-subtle)', //     tinted hover backgrounds
  brandBorder: 'var(--border-color-brand)',

  // Borders — hairline separators.
  border: 'var(--border-color-base)',
  borderStrong: 'var(--border-color-interaction-hover)',

  // Feedback (status) — VLM states, download states, errors.
  info: 'var(--text-color-feedback-info)', //                    blue  — in progress / downloading
  infoDim: 'var(--background-color-feedback-info)',
  warning: 'var(--text-color-feedback-warning)', //              amber — rejected / queued
  warningDim: 'var(--background-color-feedback-warning)',
  danger: 'var(--text-color-feedback-danger)', //                red   — failed / error
  dangerDim: 'var(--background-color-feedback-danger)',
  success: 'var(--text-color-feedback-success)', //              green — validated / done

  // Type
  mono: "'JetBrains Mono', ui-monospace, SFMono-Regular, monospace",

  // Radii (mock spec: inputs 6px, buttons/cards 6–8px, popovers 10px, panel 12px)
  radiusSm: '6px',
  radiusMd: '8px',
  radiusLg: '10px',
  radiusPanel: '12px',
};

export default T;
