import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Button, Spinner } from '@kui/foundations-react';
import { BackArrowGlyph, ArrowRightGlyph } from './icons';
import { ImageWithSkeleton } from './ImageSkeleton';
import { loadImage, getCachedOffsets, loadProgressiveImages, revokeImage, peekCachedImage } from '../utils/imageLoader';
import T from '../kui/tokens';

/**
 * Navigable asset image component with left-right arrow navigation.
 * Supports img_offset parameter for viewing multiple images per asset.
 *
 * @param {Object} [parentLoadingState] - Optional offset-0 loading state from a
 *   parent `useSmartImageLoader`. Shape: `{ loading: bool, error: Error|null, data: string|null }`.
 *   When present, the component does NOT self-load at offset 0 — it consumes the
 *   parent's state instead, eliminating duplicate React renders for the same asset.
 *   Higher offsets (when the user navigates via the right arrow) still self-load.
 *   Callers without a parent loader (e.g. `AssetDetailsModal`) can omit this prop;
 *   the component then falls back to self-loading offset 0 like before.
 */
const NavigableAssetImage = ({
  result,
  getHeaders,
  apiUrl,
  width = "100%",
  height = "120px",
  borderRadius = "md",
  parentLoadingState,
  // When false, the asset's other images can't be paged through (no hover
  // arrows). Used by the dense index rows, whose thumbnail is far too small
  // for the nav controls to be usable.
  navigable = true,
  ...imageProps
}) => {
  const elementRef = useRef(null);
  const [currentOffset, setCurrentOffset] = useState(0);
  // Synchronously seed from the in-memory image cache so re-mounts (e.g.,
  // toggling list/grid view) re-show the thumbnail instantly, skipping the
  // loading-skeleton flash that an async cache-then-render path would cause.
  const initialAssetUrl = result?.source?.base_key || result?.source?.url || result?.id;
  const initialCached = peekCachedImage(initialAssetUrl, apiUrl || '', 0, result);
  const [localIsLoading, setLocalIsLoading] = useState(false);
  const [localImageData, setLocalImageData] = useState(initialCached);
  const [localError, setLocalError] = useState(null);
  const [isHovered, setIsHovered] = useState(false);
  const [maxOffset, setMaxOffset] = useState(null); // null means unknown, 0 means only one image
  const [isLoadingProgressive, setIsLoadingProgressive] = useState(false);
  const [progressiveCount, setProgressiveCount] = useState(0); // thumbnails retrieved so far during discovery
  const [hasAttemptedProgressive, setHasAttemptedProgressive] = useState(false);
  const [hasLoadingError, setHasLoadingError] = useState(false);
  const [navCount, setNavCount] = useState(0);

  // Track blob: URLs created by this component instance so we can revoke them
  // on unmount. We deliberately do NOT revoke on offset change: a single card's
  // lifetime is bounded, and holding ~10 blob URLs in memory while it is
  // mounted is fine. Per-offset revocation creates a race with the module-level
  // imageCache, which would return the now-revoked URL on backtrack navigation
  // (right then left) and produce a broken <img>.
  const localUrlsRef = useRef([]);

  const assetUrl = result?.source?.base_key || result?.source?.url || result?.id;

  // When the parent owns offset-0 loading, derive the displayed values from it.
  // Otherwise use the local self-loaded state. Higher offsets always use local state.
  const useParentForOffsetZero = !!parentLoadingState && currentOffset === 0;
  const imageData = useParentForOffsetZero ? parentLoadingState.data : localImageData;
  const isLoading = useParentForOffsetZero ? parentLoadingState.loading : localIsLoading;
  const error = useParentForOffsetZero ? parentLoadingState.error : localError;

  // Load image for current offset
  const loadCurrentImage = useCallback(async (offset) => {
    if (!assetUrl || !getHeaders) return;

    const effectiveApiUrl = apiUrl || '';
    // Synchronous cache peek before flipping to loading state — avoids the
    // skeleton-flash on view-mode toggle / remount when the bytes are still
    // in the in-memory image cache from the prior render.
    const peeked = peekCachedImage(assetUrl, effectiveApiUrl, offset, offset === 0 ? result : null);
    if (peeked) {
      setLocalImageData(peeked);
      setLocalError(null);
      setHasLoadingError(false);
      return;
    }

    setLocalIsLoading(true);
    setLocalError(null);
    setHasLoadingError(false);

    try {
      // Pass the result object only for offset 0 to enable vector image detection
      const resultForVectorDetection = offset === 0 ? result : null;
      const data = await loadImage(assetUrl, getHeaders, effectiveApiUrl, false, offset, resultForVectorDetection);
      if (typeof data === 'string' && data.startsWith('blob:')) {
        if (!localUrlsRef.current.includes(data)) {
          localUrlsRef.current.push(data);
        }
      }
      setLocalImageData(data);
    } catch (err) {
      setLocalError(err);
      setLocalImageData(null);
      // Set loading error state for non-404 errors
      if (err.status && err.status !== 404) {
        setHasLoadingError(true);
      }
    } finally {
      setLocalIsLoading(false);
    }
  }, [assetUrl, getHeaders, apiUrl, result]);

  // Keep the latest loader in a ref so the offset-load effect below can depend
  // on the STABLE assetUrl instead of loadCurrentImage. loadCurrentImage's
  // identity changes whenever `result` gets a new reference — and every VLM
  // validation tick rebuilds each hit object ({...hit, _validationState}) — so
  // depending on it re-ran the loader for every card on every validation update,
  // flashing the skeleton for any thumbnail not yet cached. Keying on assetUrl
  // loads once per asset.
  const loadCurrentImageRef = useRef(loadCurrentImage);
  loadCurrentImageRef.current = loadCurrentImage;

  // Reset per-asset navigation/discovery state when the underlying asset changes.
  // The virtualized list keys rows by index (VirtualizedResults.jsx), so React
  // reuses a single NavigableAssetImage instance for different assets as the user
  // searches or scrolls. Without this reset, one asset's discovered image count
  // (maxOffset), current page (currentOffset), progress counter, and
  // already-attempted flag would leak onto the next asset.
  const prevAssetUrlRef = useRef(assetUrl);
  useEffect(() => {
    if (prevAssetUrlRef.current === assetUrl) return;
    prevAssetUrlRef.current = assetUrl;
    setCurrentOffset(0);
    setMaxOffset(null);
    setProgressiveCount(0);
    setIsLoadingProgressive(false);
    setHasAttemptedProgressive(false);
    setHasLoadingError(false);
    setLocalError(null);
    setNavCount(0);
    // Re-seed offset-0 from the in-memory cache for the new asset, mirroring the
    // synchronous mount-time seeding so the thumbnail doesn't flash a skeleton.
    setLocalImageData(peekCachedImage(assetUrl, apiUrl || '', 0, result));
  }, [assetUrl, apiUrl, result]);

  // Load image when currentOffset changes (including initial load at offset 0).
  // Skip when the parent owns offset-0 state — avoids duplicate render churn.
  useEffect(() => {
    if (currentOffset === 0 && parentLoadingState) {
      return;
    }
    loadCurrentImageRef.current(currentOffset);
    // Keyed on assetUrl (stable per asset), NOT loadCurrentImage, so a
    // validation-driven `result` re-reference does not re-trigger a reload.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [assetUrl, currentOffset, parentLoadingState]);

  // Note: we deliberately do NOT revoke blob: URLs on unmount.
  // The module-level imageCache still references those URLs and the user
  // may re-mount this card (view-mode toggle, scroll-back, etc.) — revoking
  // here breaks the cached thumbnail. The cache's overwrite-revoke at
  // imageLoader.setCachedImage:143-146 handles bounded cleanup when an
  // entry is replaced; that's the only point where revocation is safe.

  // Handle case where we discover there's only one image and user is on a higher offset
  useEffect(() => {
    if (maxOffset === 0 && currentOffset > 0) {
      // Clear any error state from the failed higher offset and reset to offset 0
      setLocalError(null);
      setHasLoadingError(false);
      setLocalImageData(null); // Clear current image data to force reload
      setCurrentOffset(0);
      // The loadCurrentImage(0) will be triggered by the currentOffset change
    }
  }, [maxOffset, currentOffset]);

  // Progressive loading when user first navigates
  const startProgressiveLoading = useCallback(async () => {
    if (!assetUrl || !getHeaders || isLoadingProgressive || hasAttemptedProgressive) return;

    setIsLoadingProgressive(true);
    setHasAttemptedProgressive(true);
    setProgressiveCount(0);

    try {
      const effectiveApiUrl = apiUrl || '';
      const { images, maxOffset: discoveredMax } = await loadProgressiveImages(
        assetUrl,
        getHeaders,
        effectiveApiUrl,
        1, // Start from offset 1
        20, // Max parallel requests (use global limit)
        result, // Pass result for vector image detection on offset 0
        setProgressiveCount // Live count of thumbnails retrieved so far
      );

      setMaxOffset(discoveredMax);

      // If no additional images found, we only have offset 0
      if (discoveredMax < 1) {
        setMaxOffset(0); // Only one image (offset 0)
      }
    } catch (err) {
      console.error('Progressive loading failed:', err);
      setMaxOffset(0); // Only one image (offset 0)
    } finally {
      setIsLoadingProgressive(false);
    }
  }, [assetUrl, getHeaders, apiUrl, isLoadingProgressive, hasAttemptedProgressive, result]);

  // Get available offsets from cache
  const effectiveApiUrl = apiUrl || '';
  const availableOffsets = getCachedOffsets(assetUrl || '', effectiveApiUrl);
  const canGoLeft = currentOffset > 0;

  // Determine if we can go right and if arrow should be shown
  let canGoRight = false;
  let showRightArrow = false;

  if (maxOffset === null && !hasAttemptedProgressive) {
    // Haven't attempted discovery yet, show enabled right arrow
    canGoRight = true;
    showRightArrow = true;
  } else if (maxOffset === null && hasAttemptedProgressive) {
    // Discovery in progress, check cache
    canGoRight = availableOffsets.includes(currentOffset + 1);
    showRightArrow = canGoRight;
  } else if (maxOffset !== null) {
    // Discovery complete
    if (maxOffset === 0) {
      // Single image case - show disabled right arrow if we're on offset 0
      canGoRight = false;
      showRightArrow = currentOffset === 0;
    } else {
      // Multiple images - normal navigation
      canGoRight = currentOffset < maxOffset;
      showRightArrow = canGoRight;
    }
  }

  // Navigation handlers
  const handlePrevious = useCallback(() => {
    if (!canGoLeft) return;
    const newOffset = currentOffset - 1;
    setCurrentOffset(newOffset);
  }, [canGoLeft, currentOffset]);

  const handleNext = useCallback(() => {
    if (!canGoRight) return;

    const newOffset = currentOffset + 1;
    setCurrentOffset(newOffset);
    setNavCount(n => n + 1);

    // Defer progressive discovery to the SECOND right-arrow click. A single
    // curious click should not probe up to 10 offsets in parallel.
    if (navCount >= 1 && !hasAttemptedProgressive) {
      startProgressiveLoading();
    }
  }, [canGoRight, currentOffset, hasAttemptedProgressive, navCount, startProgressiveLoading]);

  // Determine what to display
  let src = null;
  let hasError = false;
  let errorMessage = "No Image";

  if (imageData) {
    src = imageData;
  } else if (result?.source?.image && currentOffset === 0 && !isLoading) {
    // Use fallback base64 image only for offset 0 if API failed and we're not loading
    src = `data:image/png;base64,${result.source.image}`;
  } else if (error && !result?.source?.image) {
    hasError = true;

    if (error.status === 404) {
      errorMessage = currentOffset === 0 ? "Image Not Found" : "No More Images";
    } else if (error.status === 403) {
      errorMessage = "Access Denied";
    } else if (error.status >= 400 && error.status < 500) {
      errorMessage = "Invalid Request";
    } else if (error.status >= 500) {
      errorMessage = "Server Error";
    } else {
      errorMessage = "Load Failed";
    }
  }

  const showNavigation = navigable && isHovered && (canGoLeft || showRightArrow);

  return (
    <div
      ref={elementRef}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      style={{ position: "relative", width, height }}
    >
      <ImageWithSkeleton
        src={src}
        alt="Asset thumbnail"
        isLoading={isLoading && !result?.source?.image}
        hasError={hasError}
        width="100%"
        height="100%"
        borderRadius={borderRadius}
        objectFit="cover"
        skeletonProps={{
          variant: "ghost"
        }}
        errorContent={errorMessage}
        {...imageProps}
      />

      {/* Navigation arrows - only visible on hover */}
      {showNavigation && (
        <>
          {/* Left arrow */}
          {canGoLeft && (
            <span
              style={{
                position: "absolute",
                left: "8px",
                top: "50%",
                transform: "translateY(-50%)",
              }}
            >
              <Button
                kind="secondary"
                color="neutral"
                size="small"
                onClick={(e) => {
                  e.stopPropagation();
                  handlePrevious();
                }}
                aria-label="Previous image"
                disabled={isLoading}
                style={{
                  background: "rgba(0,0,0,0.7)",
                  color: "white",
                }}
              >
                <BackArrowGlyph width={16} height={16} />
              </Button>
            </span>
          )}

          {/* Right arrow */}
          {showRightArrow && (
            <span
              style={{
                position: "absolute",
                right: "8px",
                top: "50%",
                transform: "translateY(-50%)",
                opacity: canGoRight ? 1 : 0.5,
              }}
            >
              <Button
                kind="secondary"
                color="neutral"
                size="small"
                onClick={(e) => {
                  e.stopPropagation();
                  if (canGoRight) {
                    handleNext();
                  }
                }}
                aria-label="Next image"
                disabled={isLoading || !canGoRight}
                style={{
                  background: "rgba(0,0,0,0.7)",
                  color: "white",
                }}
              >
                <ArrowRightGlyph width={16} height={16} />
              </Button>
            </span>
          )}
        </>
      )}

      {/* Loading indicator for progressive loading */}
      {isLoadingProgressive && (
        <div
          style={{
            position: "absolute",
            bottom: "8px",
            left: "8px",
            background: "rgba(0,0,0,0.7)",
            color: "white",
            padding: "4px 8px",
            borderRadius: T.radiusMd,
            fontSize: "11px",
            display: "flex",
            alignItems: "center",
            gap: "4px",
          }}
        >
          <Spinner size="small" aria-label="Loading" />
          {progressiveCount > 0 ? `Loading… ${progressiveCount} found` : 'Loading…'}
        </div>
      )}

      {/* Error indicator for non-404 errors */}
      {hasLoadingError && (
        <div
          style={{
            position: "absolute",
            bottom: "8px",
            left: "8px",
            background: "rgba(139,0,0,0.7)",
            color: "white",
            padding: "4px 8px",
            borderRadius: T.radiusMd,
            fontSize: "11px",
          }}
        >
          Error loading images
        </div>
      )}
    </div>
  );
};

export default NavigableAssetImage;
