// If not set it uses the local 'api/' endpoint
export const apiUrl = process.env.REACT_APP_API_URL || "";

export const defaultEmbeddingFieldName = process.env.REACT_APP_DEFAULT_EMBEDDING_FIELD_NAME || "siglip2-embedding.embedding";
export const defaultEmbeddingDimension = process.env.REACT_APP_DEFAULT_EMBEDDING_DIMENSION || 1536;

// Default embedding configuration
export const defaultEmbeddingConfig = {
  field_name: defaultEmbeddingFieldName,
  dimension: 1536
};

// Server name to URL mapping configuration
// Expects a JSON string in format: {"server1": "http://url1", "server2": "http://url2"}
let serverMapping = {};
try {
  const mappingStr = process.env.REACT_APP_SERVER_MAPPING || "{}";
  serverMapping = JSON.parse(mappingStr);
} catch (error) {
  console.error("Failed to parse SERVER_MAPPING configuration:", error);
  serverMapping = {};
}
export const SERVER_MAPPING = serverMapping;

// Image processing configuration
export const IMAGE_SIZE = 224;

// Max dimension (longest side, in pixels) that uploaded query images are
// downscaled to — preserving aspect ratio — before being sent to the search
// service and the per-hit VLM validator. Large uploads put needless load on
// the backend; the embedding models / VLMs work at far smaller resolutions.
// Defaults to Full HD (1920). Set REACT_APP_IMAGE_MAX_DIMENSION to "0" (or any
// non-positive value) to disable resizing and send images at full resolution.
export const IMAGE_MAX_DIMENSION = (() => {
  const parsed = parseInt(process.env.REACT_APP_IMAGE_MAX_DIMENSION ?? "", 10);
  return Number.isNaN(parsed) ? 1920 : parsed;
})();

// Duplicate removal configuration
export const DUPLICATE_REMOVAL_THRESHOLD = process.env.REACT_APP_DUPLICATE_REMOVAL_THRESHOLD || 0.0001;

// Default search-form values (build-time overridable via REACT_APP_*).
// These pre-fill the search filters when the app loads and are restored when
// the matching "clear" button is used.
//
// DEFAULT_CUTOFF_THRESHOLD pre-fills the "Similarity Cutoff" field. An empty
// string means no cutoff is sent to the backend unless the user enters one.
export const DEFAULT_CUTOFF_THRESHOLD = process.env.REACT_APP_DEFAULT_CUTOFF_THRESHOLD || "";
// DEFAULT_FILE_EXTENSION_INCLUDE pre-fills the "Include Extensions" filter.
// Nullish (??) not "||" on purpose: an explicitly-set empty string means "no
// extension filter" (match every file type) and must be honored. The "usd*"
// fallback only applies when the var is genuinely unset (e.g. local dev).
export const DEFAULT_FILE_EXTENSION_INCLUDE = process.env.REACT_APP_DEFAULT_FILE_EXTENSION_INCLUDE ?? "usd*";

// Default hybrid-search text-leg settings, seeded into DEFAULT_HYBRID_CONFIG
// (see HybridSearchConfig.jsx). Both are build-time overridable via REACT_APP_*
// and default to the values the UI historically hardcoded, so an un-configured
// build behaves exactly as before.
//
// DEFAULT_TEXT_WEIGHT is the overall weight of the text leg in hybrid scoring
// (hybrid_text.weight). A non-numeric override falls back to 1.2.
export const DEFAULT_TEXT_WEIGHT = (() => {
  const parsed = parseFloat(process.env.REACT_APP_DEFAULT_TEXT_WEIGHT ?? "");
  return Number.isNaN(parsed) ? 1.2 : parsed;
})();
// DEFAULT_CROSS_FIELD_OPERATOR is hybrid_text.cross_field_operator: whether a
// query must match across text fields with "and" or "or". Coerced to a valid
// value ("or" unless the override is exactly "and", case-insensitive).
export const DEFAULT_CROSS_FIELD_OPERATOR =
  (process.env.REACT_APP_DEFAULT_CROSS_FIELD_OPERATOR || "").toLowerCase() === "and" ? "and" : "or";

// Check if running on HTTPS (required for clipboard API)
export const IS_HTTPS = typeof window !== 'undefined' && window.location.protocol === 'https:';

// Feature flags configuration
export const FEATURE_FLAGS = {
  // Enable/disable feedback modal - enabled by default, can be disabled via env var
  ENABLE_FEEDBACK_MODAL: process.env.REACT_APP_ENABLE_FEEDBACK_MODAL === "true",

  // LLM query parsing (natural-language search via /llm_parse/query) and VLM
  // per-hit validation are both ENABLED by default; each is disabled only when
  // its var is explicitly "false". Disabling LLM parsing routes every text
  // query through a plain search; disabling VLM validation hides the toggle and
  // never runs validation. (The /llm_parse/fields filter-picker catalog is a
  // separate concern and is unaffected by ENABLE_LLM_PARSING.)
  ENABLE_LLM_PARSING: process.env.REACT_APP_ENABLE_LLM_PARSING !== "false",
  ENABLE_VLM_VALIDATION: process.env.REACT_APP_ENABLE_VLM_VALIDATION !== "false",

  // Asset-detail dependency views (Dependencies + Inverse Dependencies sections
  // and the full-screen dependency-graph visualization), the Index Management
  // section, and the authentication icon + popover (landing AuthButton and the
  // results-view HeaderIcons account control). All ENABLED by default; each is
  // disabled only when its var is explicitly "false".
  ENABLE_DEPENDENCY_VIEWS: process.env.REACT_APP_ENABLE_DEPENDENCY_VIEWS !== "false",
  ENABLE_INDEX_MANAGEMENT: process.env.REACT_APP_ENABLE_INDEX_MANAGEMENT !== "false",
  ENABLE_AUTH_UI: process.env.REACT_APP_ENABLE_AUTH_UI !== "false",
};

// Validation configuration
export const VALIDATION_CONFIG = {
  MAX_CONCURRENT: parseInt(process.env.REACT_APP_VALIDATION_MAX_CONCURRENT || "8", 10),
  MAX_RETRIES: parseInt(process.env.REACT_APP_VALIDATION_MAX_RETRIES || "3", 10),
  RETRY_DELAY_MS: parseInt(process.env.REACT_APP_VALIDATION_RETRY_DELAY_MS || "5000", 10),
  TIMEOUT_MS: parseInt(process.env.REACT_APP_VALIDATION_TIMEOUT_MS || "30000", 10),
  // Per-result verdicts are coalesced and flushed to state at most once per this
  // window (ms), so the results grid re-partitions a handful of times instead of
  // once per validation — keeps live grouping smooth without per-hit reflow.
  FLUSH_INTERVAL_MS: parseInt(process.env.REACT_APP_VALIDATION_FLUSH_MS || "200", 10),
};

// Authentication configuration
export const AUTH_CONFIG = {
  // All three authentication methods are available by default; each can be
  // explicitly disabled with REACT_APP_ENABLE_*_AUTH="false".
  ENABLE_NUCLEUS_AUTH: process.env.REACT_APP_ENABLE_NUCLEUS_AUTH !== "false",
  ENABLE_API_KEY_AUTH: process.env.REACT_APP_ENABLE_API_KEY_AUTH !== "false",
  ENABLE_BASIC_AUTH: process.env.REACT_APP_ENABLE_BASIC_AUTH !== "false",

  // Default values if provided
  DEFAULT_NUCLEUS_TOKEN: process.env.REACT_APP_DEFAULT_NUCLEUS_TOKEN || "",
  DEFAULT_API_KEY: process.env.REACT_APP_DEFAULT_API_KEY || "",
  DEFAULT_USERNAME: process.env.REACT_APP_DEFAULT_USERNAME || "",
  DEFAULT_PASSWORD: process.env.REACT_APP_DEFAULT_PASSWORD || "",
};
