import { ELEMENT_ATTRIBUTE_SETS } from '../constants/attributes.js';

function extractProps(element, props) {
  const elementAttrs = ELEMENT_ATTRIBUTE_SETS[element];
  const extracted = {};
  const rest = {};
  for (const key in props) {
    if (elementAttrs.has(key)) {
      extracted[key] = props[key];
    } else {
      rest[key] = props[key];
    }
  }
  return [extracted, rest];
}

export { extractProps };
