import React from "react";
import { AppBar, Badge, Button, Divider, HorizontalLogo, Switch, Tooltip } from "@kui/foundations-react";
import { AiImageGlyph, DownloadGlyph, TargetGlyph } from "./icons";
import T from "../kui/tokens";

const VLM_TOOLTIP =
  "Re-checks each match with a vision-language model and filters out visually irrelevant hits.";

// A square icon button in the right cluster (Downloads, Advanced scoring).
// Reads green ("brand") while its surface is open, neutral otherwise.
const ChromeButton = ({ active, label, onClick, children }) => (
  <Tooltip slotContent={label} side="bottom">
    <Button
      kind="secondary"
      color={active ? "brand" : "neutral"}
      size="small"
      aria-label={label}
      onClick={onClick}
      style={{ position: "relative", borderRadius: T.radiusSm }}
    >
      {children}
    </Button>
  </Tooltip>
);

// Results/graph-view top app bar: NVIDIA logo (→ landing) · compact NL search
// pill · VLM-validation toggle (modifies the query) · spacer · Downloads ·
// Advanced scoring · divider · account (source + avatar).
const TopBar = ({
  onLogoClick,
  searchBarSlot,
  showVlm = true,
  vlmOn,
  onToggleVlm,
  downloadCount = 0,
  downloadsActive = false,
  onDownloadsClick,
  scoringActive = false,
  onScoringClick,
  accountSlot,
}) => {
  return (
    <AppBar
      // Taller bar so the (now larger) search pill has breathing room above the
      // bottom divider instead of crowding it.
      style={{ position: "sticky", top: 0, zIndex: 10, flex: "none", minHeight: 66 }}
      slotStart={
        <Tooltip slotContent="Back to home" side="bottom">
          <button
            type="button"
            onClick={onLogoClick}
            aria-label="Back to home"
            style={{
              display: "flex",
              alignItems: "center",
              cursor: "pointer",
              background: "none",
              border: "none",
              padding: 0,
            }}
          >
            <HorizontalLogo style={{ height: "24px", width: "auto" }} />
          </button>
        </Tooltip>
      }
      slotEnd={
        <>
          <ChromeButton active={downloadsActive} label="Downloads" onClick={onDownloadsClick}>
            <DownloadGlyph width={15} height={15} />
            {downloadCount > 0 && (
              <span
                style={{
                  position: "absolute",
                  top: -6,
                  right: -6,
                  pointerEvents: "none",
                }}
              >
                <Badge color="green" kind="solid">
                  {downloadCount}
                </Badge>
              </span>
            )}
          </ChromeButton>

          <ChromeButton active={scoringActive} label="Advanced scoring" onClick={onScoringClick}>
            <TargetGlyph width={15} height={15} />
          </ChromeButton>

          {accountSlot && (
            <>
              <Divider orientation="vertical" style={{ height: 22 }} />
              {accountSlot}
            </>
          )}
        </>
      }
    >
      {/* Center slot: compact search pill (flex-fills) + VLM validation toggle */}
      <div style={{ display: "flex", alignItems: "center", gap: 16, flex: 1, minWidth: 0 }}>
        <div style={{ flex: 1, maxWidth: 640, minWidth: 0 }}>{searchBarSlot}</div>

        {/* VLM validation toggle — icon + switch only, described on hover.
            Hidden entirely when the build disables VLM validation. */}
        {showVlm && (
          <Tooltip slotContent={VLM_TOOLTIP} side="bottom" className="max-w-[280px]">
            <div
              style={{
                display: "flex",
                alignItems: "center",
                gap: 9,
                flex: "none",
                height: 38,
                padding: "0 13px",
                borderRadius: 999,
                border: `1px solid ${vlmOn ? T.brandBorder : T.borderStrong}`,
                background: vlmOn ? `color-mix(in srgb, ${T.brandDim} 50%, transparent)` : T.surfaceRaised,
              }}
            >
              <AiImageGlyph width={22.5} height={22.5} color={vlmOn ? "var(--text-color-brand)" : "#7a7a7e"} />
              <Switch
                size="small"
                checked={vlmOn}
                onCheckedChange={() => onToggleVlm?.()}
                aria-label="Toggle VLM validation"
              />
            </div>
          </Tooltip>
        )}
      </div>
    </AppBar>
  );
};

export default TopBar;
