import './index.css';
import '@kui/foundations-react/base.css'; // Kaizen Foundations: reset + design tokens + fonts + dark theme
import React, {useState, useEffect} from 'react';
import * as ReactDOMClient from 'react-dom/client';
import { ThemeProvider } from '@kui/foundations-react';
import { Avatar, Button, Divider, Modal, ModalCloseButton, Popover, Select, TextInput } from '@kui/foundations-react';
import { AuthGlyph, LockGlyph, ExternalGlyph } from './components/icons';
import { useBrandedToast, BrandedToaster } from './utils/brandedToast';
import useDisclosure from './kui/useDisclosure';
import T from './kui/tokens';

import SearchApp from "./HybridDeepSearchUI";
import { apiUrl as defaultApiUrl, SERVER_MAPPING, defaultEmbeddingConfig } from "./config";
import GraphVisualization from "./Graph";
import persistentCache from "./utils/persistentImageCache";
import { useDeviceFlowAuth, getServerHttpsUrl, AuthStatus, createApiToken } from "./nucleus";
import {
    AUTH_METHODS,
    readAuth,
    writeAuthMethod,
    writeCredential,
    clearCredential,
    selectDefaultMethod,
    enabledMethods,
    buildAuthHeaders,
    hasStoredCredential,
} from "./utils/authStorage";
import { AUTH_STATUS, useAuthStatus } from "./utils/authStatus";


// Authentication Form Component
const AuthForm = ({ auth, setAuth, selectedServer }) => {
    // Device flow modal state
    const { isOpen: isDeviceFlowOpen, onOpen: onDeviceFlowOpen, onClose: onDeviceFlowClose } = useDisclosure();
    const deviceFlowAuth = useDeviceFlowAuth();
    const toast = useBrandedToast();

    // Helper function to check if backend is S3
    const isS3Backend = (backendString) => {
        return backendString && backendString.toLowerCase().includes('s3');
    };

    // Helper function to check if backend is Nucleus
    const isNucleusBackend = (backendString) => {
        return backendString && backendString.toLowerCase().includes('omniverse://');
    };

    // Resolved backend type ("omniverse://..." | "s3://..." | null) and
    // a flag that distinguishes "we haven't tried yet" from "we tried and got
    // nothing back". The form stays disabled until the probe settles so the
    // default selection is computed *after* the backend type is known.
    const [backend, setBackend] = useState(null);
    const [backendResolved, setBackendResolved] = useState(false);

    // Available auth methods. `nucleus_token` is filtered out only when the
    // backend is confirmed to be non-Nucleus; when detection failed (backend
    // still null after the probe settled) we keep all methods so the user can
    // still pick Nucleus manually.
    const availableMethods = enabledMethods().filter(
        (m) => m !== AUTH_METHODS.NUCLEUS_TOKEN || isNucleusBackend(backend) || !backend
    );

    // Auth method selection — lazily aligned with the resolved backend once
    // detection finishes. While `backendResolved` is false we render a loading
    // placeholder instead of the form, so the initial state value is a
    // placeholder; the reconciliation effect below installs the real default.
    const [authMethod, setAuthMethod] = useState(() => {
        const stored = auth.method;
        if (stored) return stored;
        return selectDefaultMethod(selectedServer, backend);
    });

    useEffect(() => {
        if (!backendResolved || !availableMethods.length) return;

        // Treat a stored `auth_method` whose matching credential is empty as
        // "no real pick" — that's the shape left behind by an earlier version
        // of this code that auto-persisted defaults, and it would otherwise
        // pin Nucleus users to basic auth forever.
        const stored = readAuth(selectedServer);
        const credPopulated = ({
            [AUTH_METHODS.API_KEY]: !!stored.api_key,
            [AUTH_METHODS.BASIC]: !!(stored.username || stored.password),
            [AUTH_METHODS.NUCLEUS_TOKEN]: !!stored.nucleus_api_token,
        })[stored.method];
        const hasExplicitPick = stored.method && credPopulated;

        if (!availableMethods.includes(authMethod) || !hasExplicitPick) {
            const next = selectDefaultMethod(selectedServer, backend);
            if (next !== authMethod) setAuthMethod(next);
            // Only persist when forced by an unavailable method. Defaults stay
            // implicit so a Nucleus backend always defaults to nucleus_token,
            // even if a previous load wrote `auth_method=basic` to storage.
            if (!availableMethods.includes(authMethod)) {
                writeAuthMethod(selectedServer, next);
            }
        }
    }, [backend, backendResolved, selectedServer]); // eslint-disable-line react-hooks/exhaustive-deps

    const persistMethod = (next) => {
        setAuthMethod(next);
        writeAuthMethod(selectedServer, next);
        setAuth((prev) => ({ ...prev, method: next }));
        window.dispatchEvent(new Event('auth-updated'));
    };

    const fetchBackendInfo = async () => {
        try {
            const headers = {
                "Content-Type": "application/json",
                ...(selectedServer ? { "x-usdsearch-storage-backend": selectedServer } : {}),
                ...buildAuthHeaders(selectedServer, null),
            };

            const fullUrl = defaultApiUrl ? `${defaultApiUrl}/info/backend/storage` : `/info/backend/storage`;
            const response = await fetch(fullUrl, { method: 'GET', headers: headers });

            if (response.ok) {
                const data = await response.json();
                if (data.backends && Object.keys(data.backends).length > 0) {
                    const backendInfo = Object.keys(data.backends).join(', ');
                    setBackend(backendInfo);
                }
            }
        } catch (error) {
            console.error("Error fetching backend info:", error);
        } finally {
            setBackendResolved(true);
        }
    };

    // Fetch backend info when component mounts or server / credentials change.
    React.useEffect(() => {
        fetchBackendInfo();
    }, [auth.api_key, auth.username, auth.password, auth.nucleus_api_token, selectedServer]);

    // Pre-fill a sane username default for S3 backends only. Nucleus no longer
    // hijacks the basic-auth slot — the dedicated `nucleus_token` method owns
    // that flow.
    React.useEffect(() => {
        if (!backend) return;
        const stored = readAuth(selectedServer);
        if (stored.username || stored.password) return;
        if (isS3Backend(backend)) {
            writeCredential(selectedServer, "username", "");
            writeCredential(selectedServer, "password", "dummy");
            setAuth((prev) => ({ ...prev, username: "", password: "dummy" }));
        }
    }, [backend]); // eslint-disable-line react-hooks/exhaustive-deps

    // Start Nucleus device flow authentication
    const handleStartDeviceFlow = async () => {
        // Prefer the auto-detected backend, but fall back to the server the
        // user explicitly picked (its SERVER_MAPPING name is the Nucleus URL)
        // so login isn't blocked when /info detection is unavailable.
        const effectiveBackend = backend || SERVER_MAPPING[selectedServer]?.name || selectedServer;
        if (!effectiveBackend) {
            toast({
                title: "No server selected",
                description: "Pick a server from the dropdown above, then sign in.",
                status: "error",
                duration: 4000,
            });
            return;
        }

        onDeviceFlowOpen();

        try {
            const result = await deviceFlowAuth.startAuth(effectiveBackend);
            // Start polling for token
            deviceFlowAuth.startPolling(effectiveBackend, result.device_code, result.interval);
        } catch (error) {
            toast({
                title: "Failed to start authentication",
                description: error.message,
                status: "error",
                duration: 5000,
            });
        }
    };

    // Handle successful device flow authentication - create API token
    useEffect(() => {
        const createAndSaveApiToken = async () => {
            if (deviceFlowAuth.authResult && deviceFlowAuth.authResult.status === AuthStatus.OK) {
                try {
                    // Create a long-lived API token using the access token
                    const now = new Date();
                    const timestamp = `${now.toISOString().split('T')[0]}_${now.getHours().toString().padStart(2, '0')}-${now.getMinutes().toString().padStart(2, '0')}-${now.getSeconds().toString().padStart(2, '0')}`;
                    const tokenName = `USD-Search-${timestamp}`;

                    toast({
                        title: "Creating API token...",
                        description: "Please wait while we create a permanent API token",
                        status: "info",
                        duration: 3000,
                    });

                    // Same effective-backend fallback as handleStartDeviceFlow:
                    // use the auto-detected backend, else the server the user
                    // picked (its SERVER_MAPPING name is the Nucleus URL).
                    // Without this, createApiToken receives null on backends
                    // where /info detection is unavailable → "Invalid URL".
                    const effectiveBackend = backend || SERVER_MAPPING[selectedServer]?.name || selectedServer;

                    // Pass null for expireAt to create a permanent token (no expiration)
                    const apiTokenResult = await createApiToken(
                        effectiveBackend,
                        deviceFlowAuth.authResult.access_token,
                        tokenName,
                        null
                    );

                    // Token lives in its own slot; auth_method pins the choice.
                    writeCredential(selectedServer, "nucleus_api_token", apiTokenResult.api_token);
                    writeAuthMethod(selectedServer, AUTH_METHODS.NUCLEUS_TOKEN);
                    setAuth({ ...readAuth(selectedServer) });
                    setAuthMethod(AUTH_METHODS.NUCLEUS_TOKEN);
                    window.dispatchEvent(new Event('storage'));
                    window.dispatchEvent(new Event('auth-updated'));

                    toast({
                        title: "Authentication successful!",
                        description: `Created permanent API token for ${deviceFlowAuth.authResult.username || 'user'}.`,
                        status: "success",
                        duration: 5000,
                    });

                    onDeviceFlowClose();
                    deviceFlowAuth.reset();
                } catch (error) {
                    console.error("Failed to create API token:", error);

                    toast({
                        title: "Failed to create API token",
                        description: error.message || "Unknown error occurred while creating API token",
                        status: "error",
                        duration: 8000,
                    });

                    // Reset the device flow but keep the modal open so user can retry
                    deviceFlowAuth.reset();
                }
            }
        };

        createAndSaveApiToken();
    }, [deviceFlowAuth.authResult]); // eslint-disable-line react-hooks/exhaustive-deps

    // Handle device flow errors
    useEffect(() => {
        if (deviceFlowAuth.error) {
            toast({
                title: "Authentication failed",
                description: deviceFlowAuth.error,
                status: "error",
                duration: 5000,
            });
        }
    }, [deviceFlowAuth.error]); // eslint-disable-line react-hooks/exhaustive-deps

    const METHOD_LABELS = {
        [AUTH_METHODS.NUCLEUS_TOKEN]: "Nucleus API Token",
        [AUTH_METHODS.BASIC]: "Basic Auth",
        [AUTH_METHODS.API_KEY]: "API Key",
    };

    if (!backendResolved) {
        return (
            <div style={{ display: "flex", flexDirection: "column", gap: 12, padding: "16px 0" }}>
                <span style={{ fontSize: 13, color: T.textMuted, textAlign: "center" }}>
                    Detecting backend type…
                </span>
                <div style={{ opacity: 0.5, pointerEvents: "none" }}>
                    <div style={{ fontSize: 13, color: T.textSecondary, marginBottom: 8 }}>Authentication Method</div>
                    <Select size="small" disabled placeholder="…" items={[]} />
                </div>
            </div>
        );
    }

    const credInput = (key, value, type, placeholder) => (
        <TextInput
            size="small"
            type={type}
            value={value || ""}
            onValueChange={(v) => {
                writeCredential(selectedServer, key, v);
                setAuth((prev) => ({ ...prev, [key]: v }));
                window.dispatchEvent(new Event('storage'));
                window.dispatchEvent(new Event('auth-updated'));
            }}
            placeholder={placeholder}
        />
    );

    return (
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
            {availableMethods.length > 1 && (
                <div>
                    <div style={{ fontSize: 13, color: T.textSecondary, marginBottom: 8 }}>Authentication Method</div>
                    <Select
                        size="small"
                        value={authMethod}
                        onValueChange={persistMethod}
                        items={availableMethods.map((m) => ({ value: m, children: METHOD_LABELS[m] }))}
                    />
                </div>
            )}

            {authMethod === AUTH_METHODS.API_KEY && (
                <div>
                    <div style={{ fontSize: 13, color: T.textSecondary, marginBottom: 6 }}>API Key</div>
                    {credInput("api_key", auth.api_key, "password", "Enter your API key")}
                </div>
            )}

            {authMethod === AUTH_METHODS.NUCLEUS_TOKEN && (
                <div>
                    {auth.nucleus_api_token ? (
                        <Button
                            size="small"
                            kind="secondary"
                            color="danger"
                            style={{ width: "100%" }}
                            onClick={() => {
                                clearCredential(selectedServer, "nucleus_api_token");
                                setAuth((prev) => ({ ...prev, nucleus_api_token: "" }));
                                window.dispatchEvent(new Event('storage'));
                                window.dispatchEvent(new Event('auth-updated'));
                            }}
                        >
                            Clear Token
                        </Button>
                    ) : (
                        <Button
                            size="small"
                            kind="primary"
                            color="brand"
                            style={{ width: "100%" }}
                            onClick={handleStartDeviceFlow}
                        >
                            🔑 Get token from Nucleus
                        </Button>
                    )}
                </div>
            )}

            {authMethod === AUTH_METHODS.BASIC && (
                <>
                    <div>
                        <div style={{ fontSize: 13, color: T.textSecondary, marginBottom: 6 }}>Username</div>
                        {credInput("username", auth.username, "text", "Enter username")}
                    </div>
                    {!isS3Backend(backend) && (
                        <div>
                            <div style={{ fontSize: 13, color: T.textSecondary, marginBottom: 6 }}>Password</div>
                            {credInput("password", auth.password, "password", "Enter password")}
                        </div>
                    )}
                </>
            )}

            {/* Device Flow Modal */}
            <Modal
                open={isDeviceFlowOpen}
                onOpenChange={(o) => { if (!o) { onDeviceFlowClose(); deviceFlowAuth.reset(); } }}
                slotHeading="Authenticate with Nucleus"
                slotFooter={
                    <ModalCloseButton kind="tertiary" onClick={() => { onDeviceFlowClose(); deviceFlowAuth.reset(); }}>
                        Cancel
                    </ModalCloseButton>
                }
            >
                {deviceFlowAuth.isLoading && (
                    <div style={{ padding: "16px 0" }}>
                        <span>Connecting to Nucleus server...</span>
                    </div>
                )}

                {deviceFlowAuth.deviceFlowData && !deviceFlowAuth.authResult && (
                    <div style={{ display: "flex", flexDirection: "column", gap: 16, padding: "16px 0" }}>
                        <span style={{ fontSize: 13, color: T.textSecondary }}>
                            To authenticate, visit the Nucleus server and enter the code below:
                        </span>

                        <div style={{ background: T.surfaceRaised, padding: 16, borderRadius: T.radiusMd, textAlign: "center" }}>
                            <span style={{ fontSize: 24, fontWeight: 700, letterSpacing: "0.2em", color: T.accentText }}>
                                {deviceFlowAuth.deviceFlowData.user_code}
                            </span>
                        </div>

                        <a
                            href={(() => {
                                const uri = deviceFlowAuth.deviceFlowData.verification_uri;
                                // If verification_uri has a port (e.g., https://server:3180/...), use standard login URL instead
                                if (uri && /:\d+/.test(uri)) {
                                    const serverHost = getServerHttpsUrl(backend).replace(/^https?:\/\//, '').split('/')[0];
                                    return `https://${serverHost}/omni/auth/login/device`;
                                }
                                return uri || getServerHttpsUrl(backend);
                            })()}
                            target="_blank"
                            rel="noreferrer"
                            style={{ display: "inline-flex", alignItems: "center", gap: 4, color: T.info, alignSelf: "center" }}
                        >
                            Open Nucleus Login Page <ExternalGlyph width={12} height={12} />
                        </a>

                        {deviceFlowAuth.isPolling && (
                            <div style={{ display: "flex", justifyContent: "center", alignItems: "center", gap: 8 }}>
                                <span style={{ width: 8, height: 8, background: T.success, borderRadius: 999 }} />
                                <span style={{ fontSize: 13, color: T.textMuted }}>
                                    Waiting for you to enter the code...
                                </span>
                            </div>
                        )}

                        <span style={{ fontSize: 11, color: T.textMuted, textAlign: "center" }}>
                            Code expires in {Math.floor((deviceFlowAuth.deviceFlowData.expires_in || 900) / 60)} minutes
                        </span>
                    </div>
                )}

                {deviceFlowAuth.error && (
                    <div style={{ display: "flex", flexDirection: "column", gap: 16, padding: "16px 0", alignItems: "center" }}>
                        <span style={{ color: T.danger }}>{deviceFlowAuth.error}</span>
                        <Button size="small" kind="secondary" onClick={handleStartDeviceFlow}>
                            Try Again
                        </Button>
                    </div>
                )}
            </Modal>
        </div>
    );
};

const MONO_FONT = "'JetBrains Mono', ui-monospace, monospace";

// Shared width for the account/server popover so the landing (AuthButton) and
// results (HeaderIcons) triggers render an identical panel.
const AUTH_POPOVER_WIDTH = 360;
const EYEBROW = {
    fontSize: 10,
    fontWeight: 700,
    letterSpacing: ".07em",
    textTransform: "uppercase",
    color: T.textMuted,
};

// Verified auth-status → dot color / tag copy / avatar-ring mapping (states
// come from ./utils/authStatus). We only surface the positive "Signed in"
// (green ring/label); the not-signed-in / unknown states render NO visible
// label — the absence of the green badge, alongside the visible sign-in form,
// is signal enough and reads far cleaner than repeating "Not signed in" on
// every source row. `aria` stays descriptive so screen readers still hear the
// state even when `label` is blank.
const STATUS_META = {
    [AUTH_STATUS.SIGNED_IN]:     { label: "Signed in", aria: "Signed in",     dot: T.brand,     fg: T.accentText, ring: true },
    [AUTH_STATUS.NOT_SIGNED_IN]: { label: "",          aria: "Not signed in", dot: "#5e5e62",   fg: T.textMuted,  ring: false },
    [AUTH_STATUS.CHECKING]:      { label: "Checking…", aria: "Checking…",     dot: T.textMuted, fg: T.textMuted,  ring: false },
    [AUTH_STATUS.UNKNOWN]:       { label: "",          aria: "Not signed in", dot: "#5e5e62",   fg: T.textMuted,  ring: false },
};
const statusMeta = (status) => STATUS_META[status] || STATUS_META[AUTH_STATUS.UNKNOWN];

const ELLIPSIS = { overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" };

const CaretGlyph = ({ width = 10, height = 10 }) => (
    <svg width={width} height={height} viewBox="0 0 10 6" fill="none" aria-hidden="true">
        <path d="M1 1l4 4 4-4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
);

// Glanceable short name for a source URL: first two host labels of a
// nucleus/http host (vdc.sample.omniverse.nvidia.com → "vdc.sample"), or the
// first two hyphen-segments of an S3 bucket
// (blossom-drivesim2-content-production → "blossom-drivesim2").
const shortSourceName = (fullUrl, fallback) => {
    if (!fullUrl) return fallback || "";
    const m = /^([a-z0-9]+):\/\/(.+)$/i.exec(fullUrl);
    const scheme = m ? m[1].toLowerCase() : "";
    const rest = (m ? m[2] : fullUrl).split(/[/?#]/)[0];
    if (scheme === "s3") {
        const parts = rest.split("-");
        return parts.slice(0, 2).join("-") || rest;
    }
    const labels = rest.split(".");
    return labels.slice(0, 2).join(".") || rest;
};

// Best-effort description of a configured asset source. SERVER_MAPPING is
// deployment-defined ({ name, apiUrl, embedding_config }); `name` typically
// carries the source URL (omniverse:// or s3://). We derive a protocol tag, a
// glanceable short name, a "kind", the full URL (tooltip + row), and the REST
// endpoint.
const describeSource = (key, config) => {
    const fullUrl = config?.name || config?.url || key;
    const endpoint = config?.apiUrl || "";
    const probe = `${key} ${fullUrl} ${endpoint}`.toLowerCase();
    let kind = "Asset source";
    let protocol = "SRC";
    if (probe.includes("omniverse://") || probe.includes("nucleus")) {
        kind = "Omniverse Nucleus";
        protocol = "OMNIVERSE";
    } else if (probe.includes("s3")) {
        kind = "S3 asset index";
        protocol = "S3";
    } else if (probe.includes("http")) {
        kind = "REST catalog";
        protocol = "HTTP";
    }
    return {
        name: config?.name || key,
        shortName: shortSourceName(fullUrl, config?.name || key),
        protocol,
        kind,
        fullUrl,
        endpoint,
    };
};

// One selectable row in the asset-source list: verified status dot, full source
// URL (mono, ellipsis), a "kind · endpoint" subline, and a right-aligned status
// tag. Selected row = green border + subtle green tint. Subscribes to its own
// source's verified status so every row tells the truth independently.
const SourceRow = ({ serverKey, fullUrl, kind, endpoint, selected, onSelect }) => {
    const meta = statusMeta(useAuthStatus(serverKey));
    return (
        <button
            type="button"
            onClick={onSelect}
            style={{
                display: "flex",
                alignItems: "center",
                gap: 11,
                padding: "9px 11px",
                textAlign: "left",
                width: "100%",
                borderRadius: 8,
                border: `1px solid ${selected ? T.brandBorder : T.border}`,
                background: selected ? `color-mix(in srgb, ${T.brandDim} 45%, transparent)` : "transparent",
                cursor: "pointer",
                transition: "background .12s, border-color .12s",
            }}
        >
            <span style={{ flex: "none", width: 8, height: 8, borderRadius: 999, background: meta.dot }} />
            <span style={{ flex: 1, minWidth: 0, display: "flex", flexDirection: "column", gap: 1 }}>
                <span style={{ fontSize: 12.5, fontWeight: 500, color: "#e8e8ea", fontFamily: MONO_FONT, ...ELLIPSIS }}>
                    {fullUrl}
                </span>
                <span style={{ fontSize: 10.5, color: "#7a7a7e", ...ELLIPSIS }}>
                    {endpoint ? `${kind} · ${endpoint}` : kind}
                </span>
            </span>
            <span style={{ flex: "none", fontSize: 10, fontWeight: 600, color: meta.fg, whiteSpace: "nowrap" }}>
                {meta.label}
            </span>
        </button>
    );
};

// Single source of truth for the sources + authentication panel body. Used by
// BOTH the landing and results account controls so the two can never drift.
// Fixed max-height with a PINNED header ("Search source" + N configured) and a
// PINNED auth footer; only the source list scrolls between them, so a long list
// never pushes the header or the sign-in form off-screen.
const ServerAuthPanel = ({ selectedServer, selectedStatus, onServerChange, auth, setAuth }) => {
    const sources = Object.entries(SERVER_MAPPING);
    const hasServers = sources.length > 0;
    const meta = statusMeta(selectedStatus);
    return (
        <div style={{ display: "flex", flexDirection: "column", maxHeight: 440, width: AUTH_POPOVER_WIDTH }}>
            {/* Pinned header */}
            <div
                style={{
                    flex: "none",
                    display: "flex",
                    alignItems: "baseline",
                    justifyContent: "space-between",
                    gap: 8,
                    paddingBottom: 10,
                    marginBottom: 12,
                    borderBottom: `1px solid ${T.border}`,
                }}
            >
                <span style={{ fontWeight: 600, fontSize: 13.5, color: T.textPrimary }}>
                    {hasServers ? "Search source" : "Authentication"}
                </span>
                {hasServers && (
                    <span style={{ fontSize: 11, color: T.textMuted }}>{sources.length} configured</span>
                )}
            </div>

            {/* Scrolling source list — the only region that scrolls */}
            {hasServers && (
                <div style={{ flex: 1, minHeight: 0, overflowY: "auto", display: "flex", flexDirection: "column", gap: 6, marginBottom: 14 }}>
                    {sources.map(([key, config]) => {
                        const info = describeSource(key, config);
                        return (
                            <SourceRow
                                key={key}
                                serverKey={key}
                                fullUrl={info.fullUrl}
                                kind={info.kind}
                                endpoint={info.endpoint}
                                selected={key === selectedServer}
                                onSelect={() => onServerChange(key)}
                            />
                        );
                    })}
                </div>
            )}

            {/* Pinned auth footer */}
            <div style={{ flex: "none", borderTop: hasServers ? `1px solid ${T.border}` : "none", paddingTop: hasServers ? 14 : 0 }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                    <div style={EYEBROW}>Authentication</div>
                    <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                        <span style={{ fontSize: 11, fontWeight: 600, color: meta.fg }}>{meta.label}</span>
                        <LockGlyph
                            width={12}
                            height={12}
                            color={selectedStatus === AUTH_STATUS.SIGNED_IN ? "var(--text-color-brand)" : "var(--text-color-subtle)"}
                        />
                    </div>
                </div>
                <AuthForm auth={auth} setAuth={setAuth} selectedServer={selectedServer} />
            </div>
        </div>
    );
};

// Source selector button — the popover trigger. Kept deliberately minimal (the
// glanceable short source name + a caret): still a SINGLE element so it never
// overlaps the avatar, but without the protocol tag / eyebrow that read as
// clutter. The full URL lives in the native tooltip (title) and in the panel.
// forwardRef so it can anchor the Popover.
