SourceSelectorButton.displayName = "SourceSelectorButton";

// The account avatar. Its ring turns green only when the active source is
// verified signed-in. forwardRef so it can double as the popover trigger for
// auth-only deployments (no sources configured).
const AccountAvatar = React.forwardRef(({ status, onClick, ...props }, ref) => {
    const signedIn = status === AUTH_STATUS.SIGNED_IN;
    return (
        <button
            ref={ref}
            type="button"
            onClick={onClick}
            style={{ display: "inline-flex", background: "none", border: "none", padding: 0, cursor: "pointer", borderRadius: 999 }}
            {...props}
        >
            <span style={signedIn ? { display: "inline-flex", borderRadius: 999, boxShadow: "0 0 0 2px var(--border-color-brand)" } : { display: "inline-flex" }}>
                <Avatar
                    size="medium"
                    kind="outline"
                    interactive
                    alt=""
                    fallback={<AuthGlyph width={16} height={16} color={signedIn ? "var(--text-color-brand)" : undefined} />}
                />
            </span>
        </button>
    );
});
AccountAvatar.displayName = "AccountAvatar";

// Composed account cluster: the source selector (popover trigger) + a vertical
// divider + the status avatar. Shared by the landing (AuthButton) and results
// (HeaderIcons) controls. With no sources configured, the avatar itself is the
// trigger (auth-only). The caller owns the disclosure + auth state.
const AccountControl = ({ selectedServer, activeStatus, auth, setAuth, onServerChange, isOpen, onOpenChange, onToggle }) => {
    const hasServers = Object.keys(SERVER_MAPPING).length > 0;
    const meta = statusMeta(activeStatus);
    const info = hasServers ? describeSource(selectedServer, SERVER_MAPPING[selectedServer]) : null;
    const panel = (
        <ServerAuthPanel
            selectedServer={selectedServer}
            selectedStatus={activeStatus}
            onServerChange={onServerChange}
            auth={auth}
            setAuth={setAuth}
        />
    );
    return (
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <Popover open={isOpen} onOpenChange={onOpenChange} side="bottom" align="end" slotContent={panel}>
                {hasServers ? (
                    <SourceSelectorButton
                        shortName={info.shortName || "Select source"}
                        fullUrl={info.fullUrl}
                        aria-label={`Search source: ${info.fullUrl} — ${meta.aria}`}
                    />
                ) : (
                    <AccountAvatar status={activeStatus} aria-label={`Account — ${meta.aria}`} />
                )}
            </Popover>
            {hasServers && (
                <>
                    <Divider orientation="vertical" style={{ height: 22 }} />
                    <AccountAvatar status={activeStatus} onClick={onToggle} aria-label={`Account — ${meta.aria}`} />
                </>
            )}
        </div>
    );
};

// Standalone authentication control: the AuthGlyph "user" icon plus a popover
// hosting the AuthForm (device flow / API key / basic). Self-contained — it
// derives `selectedServer` from the URL / SERVER_MAPPING and keeps its own auth
// state in sync via the same `server-changed` / `auth-updated` events the rest
// of the app dispatches — so it can be dropped onto the landing screen (which
// has no HeaderIcons bar) and let users authenticate (e.g. a Nucleus server
// that requires login) before their first search. Does not auto-open.
export const AuthButton = () => {
    const [selectedServer, setSelectedServer] = useState(() => {
        const serverParam = new URLSearchParams(window.location.search).get('server');
        if (serverParam && SERVER_MAPPING[serverParam]) return serverParam;
        const servers = Object.keys(SERVER_MAPPING);
        return servers.length > 0 ? servers[0] : "";
    });
    const [auth, setAuth] = useState(() => readAuth(selectedServer));
    const { isOpen, onOpen, onClose, onToggle } = useDisclosure();

    useEffect(() => {
        const onServerChanged = (e) => {
            if (e?.detail?.server !== undefined) setSelectedServer(e.detail.server);
        };
        const refresh = () => setAuth(readAuth(selectedServer));
        // A search that 401s dispatches 'open-auth' so the user can sign in
        // (e.g. a first search from the landing screen against a Nucleus server).
        const openAuth = () => onOpen();
        // A search dispatches 'close-auth' as it leaves the landing screen, so
        // this landing popover doesn't linger (and mis-position) into the
        // results view — where HeaderIcons owns the single account popover.
        const closeAuth = () => onClose();
        window.addEventListener('server-changed', onServerChanged);
        window.addEventListener('auth-updated', refresh);
        window.addEventListener('storage', refresh);
        window.addEventListener('open-auth', openAuth);
        window.addEventListener('close-auth', closeAuth);
        return () => {
            window.removeEventListener('server-changed', onServerChanged);
            window.removeEventListener('auth-updated', refresh);
            window.removeEventListener('storage', refresh);
            window.removeEventListener('open-auth', openAuth);
            window.removeEventListener('close-auth', closeAuth);
        };
    }, [selectedServer, onOpen, onClose]);

    // Switch the active backend from inside the popover (multi-backend support).
    // Updates the ?server= URL param and dispatches `server-changed` so the rest
    // of the app re-points; reloads this server's stored credentials so the form
    // and glyph reflect the new backend immediately.
    const handleServerChange = (serverName) => {
        setSelectedServer(serverName);
        setAuth(readAuth(serverName));
        const newEmbeddingConfig = SERVER_MAPPING[serverName]?.embedding_config || defaultEmbeddingConfig;
        const params = new URLSearchParams(window.location.search);
        params.set('server', serverName);
        const url = new URL(window.location);
        url.search = params.toString();
        window.history.replaceState({}, '', url);
        window.dispatchEvent(new CustomEvent('server-changed', {
            detail: { server: serverName, embeddingConfig: newEmbeddingConfig },
        }));
    };

    const activeStatus = useAuthStatus(selectedServer);
    return (
        <AccountControl
            selectedServer={selectedServer}
            activeStatus={activeStatus}
            auth={auth}
            setAuth={setAuth}
            onServerChange={handleServerChange}
            isOpen={isOpen}
            onOpenChange={(o) => (o ? onOpen() : onClose())}
            onToggle={onToggle}
        />
    );
};

// Header Icons Component
export const HeaderIcons = () => {
    // Server selection state
    const [selectedServer, setSelectedServer] = useState(() => {
        // Check URL for server parameter first
        const urlParams = new URLSearchParams(window.location.search);
        const serverParam = urlParams.get('server');

        // If server is in URL and exists in mapping, use it
        if (serverParam && SERVER_MAPPING[serverParam]) {
            return serverParam;
        }

        // Otherwise, if we have servers in the mapping, select the first one
        const servers = Object.keys(SERVER_MAPPING);
        return servers.length > 0 ? servers[0] : "";
    });

    const [auth, setAuth] = useState(() => readAuth(selectedServer));
    const [embeddingConfig, setEmbeddingConfig] = useState(() => {
        return selectedServer && SERVER_MAPPING[selectedServer]?.embedding_config || defaultEmbeddingConfig;
    });

    // Handle server change
    const handleServerChange = (serverName) => {
        setSelectedServer(serverName);

        // Get the new embedding config from the server configuration
        const newEmbeddingConfig = SERVER_MAPPING[serverName]?.embedding_config || defaultEmbeddingConfig;
        setEmbeddingConfig(newEmbeddingConfig);

        // // Update apiUrl for the new server
        // setApiUrl(SERVER_MAPPING[serverName]?.apiUrl || defaultApiUrl);

        // Load server-specific auth
        setAuth(readAuth(serverName));

        // Update URL while preserving existing parameters
        const params = new URLSearchParams(window.location.search);
        const existingParams = {};


        // Save all existing parameters
        params.forEach((value, key) => {
            existingParams[key] = value;
        });

        // Update server parameter
        existingParams.server = serverName;

        // Reconstruct URL with all parameters
        const newParams = new URLSearchParams(existingParams);
        const url = new URL(window.location);
        url.search = newParams.toString();
        window.history.replaceState({}, '', url);

        // Dispatch a custom event to notify other components about the server change
        window.dispatchEvent(new CustomEvent('server-changed', {
            detail: { server: serverName, embeddingConfig: newEmbeddingConfig }
        }));
    };

    // Auth popover disclosure. Seed "open" synchronously from whether a
    // credential is even stored; the verified-status effect below then corrects
    // it once the backend probe settles (auto-open only for "not signed in").
    const { isOpen: isAuthOpen, onOpen: onAuthOpen, onClose: onAuthClose, onToggle: onAuthToggle } = useDisclosure({
        defaultIsOpen: !hasStoredCredential(selectedServer, null)
    });

    // Verified status for the active source, kept live via authStatus. Drives
    // the avatar ring / source tag, and auto-open: a valid sign-in closes the
    // panel; a rejected/absent credential opens it.
    const activeStatus = useAuthStatus(selectedServer);
    useEffect(() => {
        if (activeStatus === AUTH_STATUS.SIGNED_IN) {
            onAuthClose();
        } else if (activeStatus === AUTH_STATUS.NOT_SIGNED_IN) {
            onAuthOpen();
        }
    }, [activeStatus]); // eslint-disable-line react-hooks/exhaustive-deps

    const [plugins, setPlugins] = useState({ active: [], inactive: [] });
    const [backend, setBackend] = useState(null);
    const [loading, setLoading] = useState(false);

    // Listen for storage changes to update auth state
    useEffect(() => {
        const refresh = () => setAuth(readAuth(selectedServer));
        // A search that 401s dispatches 'open-auth' so we surface the
        // server/auth popover for the user to sign in.
        const openAuth = () => onAuthOpen();

        window.addEventListener('storage', refresh);
        window.addEventListener('auth-updated', refresh);
        window.addEventListener('open-auth', openAuth);

        return () => {
            window.removeEventListener('storage', refresh);
            window.removeEventListener('auth-updated', refresh);
            window.removeEventListener('open-auth', openAuth);
        };
    }, [selectedServer, onAuthOpen]);


    const getHeaders = () => {
        const headers = { "Content-Type": "application/json" };
        if (selectedServer) {
            headers["x-usdsearch-storage-backend"] = selectedServer;
        }
        return { ...headers, ...buildAuthHeaders(selectedServer, null) };
    };

    const fetchPluginsInfo = async (selectedServerOverride = null) => {
        try {
            setLoading(true);
            const headers = getHeaders();
            const fullUrl = defaultApiUrl ? `${defaultApiUrl}/info/plugins` : `/info/plugins`;

            const response = await fetch(fullUrl, {
                method: 'GET',
                headers: headers
            });

            if (response.ok) {
                const data = await response.json();

                // Handle different response formats
                if (Array.isArray(data)) {
                    // If data is just an array of plugin names
                    setPlugins({ active: data, inactive: [] });
                } else if (data.active || data.inactive) {
                    // If data has active/inactive structure
                    setPlugins(data);
                } else {
                    // If data is an object with plugin info
                    setPlugins({ active: Object.keys(data), inactive: [] });
                }
            } else {
                const errorText = await response.text();
                console.error("Failed to fetch plugins:", response.status, response.statusText, errorText);

                // Try without auth headers if auth failed
                if (response.status === 401 || response.status === 403) {
                    // Keep the storage backend header but remove auth headers
                    const noAuthHeaders = {
                        "Content-Type": "application/json",
                        ...(selectedServer && { "x-usdsearch-storage-backend": selectedServerOverride ? selectedServerOverride:selectedServer })
                    };
                    const noAuthResponse = await fetch(fullUrl, {
                        method: 'GET',
                        headers: noAuthHeaders
                    });
                    if (noAuthResponse.ok) {
                        const data = await noAuthResponse.json();

                        // Handle different response formats
                        if (Array.isArray(data)) {
                            setPlugins({ active: data, inactive: [] });
                        } else if (data.active || data.inactive) {
                            setPlugins(data);
                        } else {
                            setPlugins({ active: Object.keys(data), inactive: [] });
                        }
                    }
                }
            }
        } catch (error) {
            console.error("Error fetching plugins info:", error);
        } finally {
            setLoading(false);
        }
    };

    const fetchBackendInfo = async (selectedServerOverride = null) => {
        try {
            const headers = getHeaders();
            const fullUrl = defaultApiUrl ? `${defaultApiUrl}/info/backend/storage` : `/info/backend/storage`;

            const response = await fetch(fullUrl, {
                method: 'GET',
                headers: headers
            });

            if (response.ok) {
                const data = await response.json();

                // Parse the backends structure
                if (data.backends && Object.keys(data.backends).length > 0) {
                    const backendInfo = Object.entries(data.backends).map(([url, info]) => ({
                        url,
                        type: info.storage_backend_type,
                        baseUrl: info.base_url
                    }));
                    setBackend(backendInfo);
                } else {
                    setBackend(null);
                }
            } else {
                const errorText = await response.text();
                console.error("Failed to fetch backend:", response.status, response.statusText, errorText);

                // Try without auth headers if auth failed
                if (response.status === 401 || response.status === 403) {
                    // Keep the storage backend header but remove auth headers
                    const noAuthHeaders = {
                        "Content-Type": "application/json",
                        ...(selectedServer && { "x-usdsearch-storage-backend": selectedServerOverride ? selectedServerOverride:selectedServer })
                    };
                    const noAuthResponse = await fetch(fullUrl, {
                        method: 'GET',
                        headers: noAuthHeaders
                    });
                    if (noAuthResponse.ok) {
                        const data = await noAuthResponse.json();

                        if (data.backends && Object.keys(data.backends).length > 0) {
                            const backendInfo = Object.entries(data.backends).map(([url, info]) => ({
                                url,
                                type: info.storage_backend_type,
                                baseUrl: info.base_url
                            }));
                            setBackend(backendInfo);
                        } else {
                            setBackend(null);
                        }
                    }
                }
            }
        } catch (error) {
            console.error("Error fetching backend info:", error);
        }
    };

    useEffect(() => {
        fetchPluginsInfo();
        fetchBackendInfo();

        // Dispatch initial server configuration so other components get the correct initial state
        if (selectedServer && SERVER_MAPPING[selectedServer]) {
            const initialEmbeddingConfig = SERVER_MAPPING[selectedServer]?.embedding_config || defaultEmbeddingConfig;
            window.dispatchEvent(new CustomEvent('server-changed', {
                detail: { server: selectedServer, embeddingConfig: initialEmbeddingConfig }
            }));
        }
    }, []);

    // Rightmost item: the source selector + status avatar. Controlled by the
    // auth disclosure — auto-opens only for "not signed in" (see the status
    // effect above); a 401 during search reopens it via the 'open-auth' event.
    return (
        <AccountControl
            selectedServer={selectedServer}
            activeStatus={activeStatus}
            auth={auth}
            setAuth={setAuth}
            onServerChange={handleServerChange}
            isOpen={isAuthOpen}
            onOpenChange={(o) => (o ? onAuthOpen() : onAuthClose())}
            onToggle={onAuthToggle}
        />
    );
};

// App wrapper to initialize persistent cache
const App = () => {
    useEffect(() => {
        // Initialize persistent image cache on app startup
        persistentCache.init().catch(err => {
            console.warn('Failed to initialize persistent image cache:', err);
        });
    }, []);

    return (
        <>
            <SearchApp/>
            {/* Toast outlet — Kaizen has no toast manager, so brandedToast ships
                its own store + this bottom-right outlet (see utils/brandedToast). */}
            <BrandedToaster/>
        </>
    );
};

