/**
 * Generic IndexedDB wrapper for the Explorer's persistent client-side caches.
 * Hand-rolled (no dep) — mirrors the shape of `persistentImageCache.js`.
 *
 * Single DB `DeepSearchClientCache` (v1) with named object stores:
 *   - `searches`     — search-result hits keyed by request-body hash
 *   - `validations`  — VLM verdicts keyed by `${queryHash}:${hitId}`
 *   - `hits`         — per-hit metadata keyed by hit ID
 *
 * Envelope on every entry:
 *     { data, ts, version, accessed_ts }
 *
 *   - `ts`          : write timestamp (used for TTL on read)
 *   - `version`     : `CACHE_VERSION` snapshot; mismatched → treated as miss
 *                     and deleted. Bump the constant to invalidate everything.
 *   - `accessed_ts` : refreshed on read; used by LRU eviction.
 *
 * Every store enforces a `maxEntries` cap on write (oldest by accessed_ts
 * evicted) and a TTL on read.
 */

const DB_NAME = "DeepSearchClientCache";
const DB_VERSION = 1;

// Bump this when the cache envelope or downstream consumer contracts
// change in a way that makes old entries unsafe. Reading any entry whose
// `version` does not match this constant treats it as a miss + deletes it.
export const CACHE_VERSION = 1;

// Default per-store configs. Callers can override on openStore().
const DEFAULTS = {
  searches:    { maxEntries: 200,  ttlMs: 5 * 60 * 1000 },
  validations: { maxEntries: 5000, ttlMs: 24 * 60 * 60 * 1000 },
  hits:        { maxEntries: 5000, ttlMs: 7 * 24 * 60 * 60 * 1000 },
};

const STORE_NAMES = Object.keys(DEFAULTS);

let _dbPromise = null;

function openDb() {
  if (_dbPromise) return _dbPromise;
  _dbPromise = new Promise((resolve, reject) => {
    if (typeof window === "undefined" || !window.indexedDB) {
      // No IDB available — every store falls back to no-op behavior.
      resolve(null);
      return;
    }
    const req = indexedDB.open(DB_NAME, DB_VERSION);
    req.onupgradeneeded = () => {
      const db = req.result;
      for (const name of STORE_NAMES) {
        if (!db.objectStoreNames.contains(name)) {
          db.createObjectStore(name);
        }
      }
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => {
      console.warn("[persistentStore] IDB open failed:", req.error);
      resolve(null);
    };
  });
  return _dbPromise;
}

function tx(db, storeName, mode) {
  return db.transaction(storeName, mode).objectStore(storeName);
}

function pReq(req) {
  return new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
}

/**
 * Open a named store with TTL + cap policies. Returns an object with
 * async methods that no-op gracefully if IDB is unavailable.
 *
 * @param {string} name  one of STORE_NAMES
 * @param {{maxEntries?: number, ttlMs?: number}} [overrides]
 */
export function openStore(name, overrides = {}) {
  if (!STORE_NAMES.includes(name)) {
    throw new Error(`[persistentStore] unknown store '${name}'`);
  }
  const config = { ...DEFAULTS[name], ...overrides };

  return {
    /** Read an entry. Returns the unwrapped `data` or `undefined`. */
    async get(key) {
      const db = await openDb();
      if (!db) return undefined;
      try {
        const entry = await pReq(tx(db, name, "readonly").get(key));
        if (!entry) return undefined;
        if (entry.version !== CACHE_VERSION) {
          this.delete(key).catch(() => {});
          return undefined;
        }
        if (Date.now() - entry.ts > config.ttlMs) {
          this.delete(key).catch(() => {});
          return undefined;
        }
        // Refresh LRU stamp (fire-and-forget — don't block the read).
        try {
          tx(db, name, "readwrite").put(
            { ...entry, accessed_ts: Date.now() },
            key,
          );
        } catch {}
        return entry.data;
      } catch (e) {
        return undefined;
      }
    },

    /** Write an entry. Enforces the cap on overflow (oldest evicted). */
    async set(key, data) {
      const db = await openDb();
      if (!db) return;
      const now = Date.now();
      const entry = { data, ts: now, version: CACHE_VERSION, accessed_ts: now };
      try {
        await pReq(tx(db, name, "readwrite").put(entry, key));
      } catch (e) {
        return;
      }
      // Cheap async cap enforcement. Skip if we just wrote; do a count
      // check + evict-oldest if over the limit.
      try {
        const count = await pReq(tx(db, name, "readonly").count());
        if (count > config.maxEntries) {
          await this.evictOldest(count - config.maxEntries);
        }
      } catch {}
    },

    async delete(key) {
      const db = await openDb();
      if (!db) return;
      try {
        await pReq(tx(db, name, "readwrite").delete(key));
      } catch {}
    },

    /** Return an array of all keys (used by hydrate). */
    async keys() {
      const db = await openDb();
      if (!db) return [];
      try {
        return await pReq(tx(db, name, "readonly").getAllKeys());
      } catch {
        return [];
      }
    },

    /**
     * Returns up to `limit` entries (key + value) sorted by
     * `accessed_ts` descending — used to pre-warm the in-memory cache
     * on app mount with the hottest items first.
     */
    async mostRecent(limit) {
      const db = await openDb();
      if (!db) return [];
      try {
        const store = tx(db, name, "readonly");
        const keys = await pReq(store.getAllKeys());
        const vals = await pReq(store.getAll());
        const pairs = keys.map((k, i) => [k, vals[i]]).filter(([, v]) => !!v);
        pairs.sort((a, b) => (b[1].accessed_ts || 0) - (a[1].accessed_ts || 0));
        // Filter stale + wrong-version on the way out.
        const now = Date.now();
        return pairs
          .filter(([, v]) => v.version === CACHE_VERSION && now - v.ts <= config.ttlMs)
          .slice(0, limit)
          .map(([k, v]) => ({ key: k, data: v.data, ts: v.ts }));
      } catch {
        return [];
      }
    },

    /** Drop entries whose TTL has expired. Cheap to run on idle. */
    async evictStale() {
      const db = await openDb();
      if (!db) return;
      try {
        const store = tx(db, name, "readwrite");
        const keys = await pReq(store.getAllKeys());
        const vals = await pReq(store.getAll());
        const now = Date.now();
        for (let i = 0; i < keys.length; i++) {
          const v = vals[i];
          if (!v || v.version !== CACHE_VERSION || now - v.ts > config.ttlMs) {
            store.delete(keys[i]);
          }
        }
      } catch {}
    },

    /** Drop the N oldest entries by `accessed_ts`. */
    async evictOldest(n) {
      if (!n || n <= 0) return;
      const db = await openDb();
      if (!db) return;
      try {
        const store = tx(db, name, "readwrite");
        const keys = await pReq(store.getAllKeys());
        const vals = await pReq(store.getAll());
        const pairs = keys.map((k, i) => [k, vals[i]]).filter(([, v]) => !!v);
        pairs.sort((a, b) => (a[1].accessed_ts || 0) - (b[1].accessed_ts || 0));
        for (let i = 0; i < Math.min(n, pairs.length); i++) {
          store.delete(pairs[i][0]);
        }
      } catch {}
    },

    async clear() {
      const db = await openDb();
      if (!db) return;
      try {
        await pReq(tx(db, name, "readwrite").clear());
      } catch {}
    },
  };
}

/** Wipe every named store. Useful for the `__usdsearch.cache.clear()` hook. */
export async function clearAllStores() {
  for (const name of STORE_NAMES) {
    await openStore(name).clear();
  }
}

// Dev-only debug hook on the window so we can inspect / clear from
// DevTools. Skipped in production by CRA's NODE_ENV gate.
if (typeof window !== "undefined" && process.env.NODE_ENV !== "production") {
  window.__usdsearch = window.__usdsearch || {};
  window.__usdsearch.cache = {
    clear: clearAllStores,
    openStore,
    CACHE_VERSION,
  };
}
