// Bridge between the left filter rail and the structured server-side search
// params. A rail click is NOT client-side faceting — it writes a real
// /search_hybrid filter token into searchParams (the same params the Advanced
// drawer edits and the chips display), so the search re-runs server-side, just
// like an LLM-parsed filter.
//
// The exact USD property key is deployment-configurable (env overrides like
// USDSEARCH_SEARCH_LLM_RIGID_BODY_PROPERTY), so the rail learns the *resolved*
// key from the catalog (GET /llm_parse/fields, which now advertises each
// field's `kind` + resolved `property`) instead of hardcoding it.
//
// Token formats mirror the backend builders in nl_parse/fields.py exactly, so
// rail-set tokens are indistinguishable from LLM-parsed ones:
//   property_exists  -> filter_by_properties           "<prop>="
//   property_numeric -> filter_by_properties_numeric   "<prop>>=N" / "<prop><=N"
//   property_match   -> filter_by_properties_include_any "<prop>=~*Class*" (OR)
//   bbox             -> max_bbox_x/y/z = N

import { mergeCsv } from "./llmParse";

const splitCsv = (s) =>
  String(s || "")
    .split(",")
    .map((t) => t.trim())
    .filter(Boolean);

const escapeRegExp = (s) => String(s).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");

// Serialize a rail value the way the backend's _numeric_fragment does: a whole
// number has no decimal point (">=10", not ">=10.0"). Rail controls are
// integer-stepped, so this round-trips losslessly.
const numStr = (value) => {
  const n = Number(value);
  if (!Number.isFinite(n)) return null;
  return Number.isInteger(n) ? String(n) : String(n);
};

// The property key portion of a numeric token ("physics:mass>=10" -> "physics:mass").
const numericTokenKey = (token) => {
  const m = String(token).match(/^(.*?)(<=|>=|<|>|=)/);
  return m ? m[1] : String(token);
};

// --- catalog lookup --------------------------------------------------------

/** The catalog entry for `name`, or null. */
export function getCatalogField(availableFilters, name) {
  if (!Array.isArray(availableFilters)) return null;
  return availableFilters.find((f) => f && f.name === name) || null;
}

/** Resolved USD property key for a property-backed rail field, or null. */
export function railFieldProperty(availableFilters, name) {
  const f = getCatalogField(availableFilters, name);
  return f && f.property ? f.property : null;
}

/** True when the deployment catalog advertises `name`. */
export function catalogHasField(availableFilters, name) {
  return getCatalogField(availableFilters, name) != null;
}

// --- boolean (property_exists) --------------------------------------------

/** Add/remove the existence token `prop=` in filter_by_properties. */
export function buildBoolPatch(prop, checked, params = {}) {
  const token = `${prop}=`;
  const current = params.filter_by_properties;
  const value = checked
    ? mergeCsv(current, token)
    : splitCsv(current)
        .filter((t) => t !== token)
        .join(",");
  return { filter_by_properties: value };
}

/** Whether `prop=` is present in filter_by_properties. */
export function readBool(params = {}, prop) {
  if (!prop) return false;
  return splitCsv(params.filter_by_properties).includes(`${prop}=`);
}

// --- numeric (property_numeric) -------------------------------------------

/**
 * Set a single numeric bound for `prop` in filter_by_properties_numeric.
 * `op` is ">=" (min) or "<=" (max). Removes any prior token for the same
 * property (latest-wins, so dragging the slider overwrites rather than stacks);
 * value <= 0 clears it.
 */
export function buildNumericPatch(prop, op, value, params = {}) {
  const kept = splitCsv(params.filter_by_properties_numeric).filter(
    (t) => numericTokenKey(t) !== prop
  );
  const n = numStr(value);
  if (n != null && Number(value) > 0) kept.push(`${prop}${op}${n}`);
  return { filter_by_properties_numeric: kept.join(",") };
}

/** The numeric value set for `prop` (any operator), or 0 when unset. */
export function readNumeric(params = {}, prop) {
  if (!prop) return 0;
  const re = new RegExp(`^${escapeRegExp(prop)}(?:<=|>=|<|>|=)(.+)$`);
  for (const t of splitCsv(params.filter_by_properties_numeric)) {
    const m = t.match(re);
    if (m) {
      const n = Number(m[1]);
      return Number.isFinite(n) ? n : 0;
    }
  }
  return 0;
}

// --- bbox (dimension) ------------------------------------------------------

/** Set/clear the equal-on-all-axes max bbox bound (dimension <= N meters). */
export function buildBboxMaxPatch(value) {
  const n = Number(value);
  if (Number.isFinite(n) && n > 0) {
    return { max_bbox_x: n, max_bbox_y: n, max_bbox_z: n };
  }
  return { max_bbox_x: "", max_bbox_y: "", max_bbox_z: "" };
}

/** The dimension bound when all three max axes are equal + set, else 0. */
export function readBboxMax(params = {}) {
  const x = params.max_bbox_x;
  const y = params.max_bbox_y;
  const z = params.max_bbox_z;
  if (x === "" || x == null) return 0;
  if (String(x) === String(y) && String(y) === String(z)) {
    const n = Number(x);
    return Number.isFinite(n) ? n : 0;
  }
  return 0;
}

// --- enumerated multi-select (object_class, property_match, OR) ------------

/**
 * Add/remove a contains-match for one class value in
 * filter_by_properties_include_any (OR across the selected classes).
 */
export function buildClassPatch(prop, className, on, params = {}) {
  const token = `${prop}=~*${className}*`;
  const current = params.filter_by_properties_include_any;
  const value = on
    ? mergeCsv(current, token)
    : splitCsv(current)
        .filter((t) => t !== token)
        .join(",");
  return { filter_by_properties_include_any: value };
}

/** The set of class values currently selected for `prop`. */
export function readClasses(params = {}, prop) {
  const out = new Set();
  if (!prop) return out;
  const re = new RegExp(`^${escapeRegExp(prop)}=~\\*(.*)\\*$`);
  for (const t of splitCsv(params.filter_by_properties_include_any)) {
    const m = t.match(re);
    if (m) out.add(m[1]);
  }
  return out;
}
